function BurdJournals.Server.cleanupRateLimitCache()
    local now = getTimestampMs and getTimestampMs() or 0
    local staleThreshold = 60000
    for playerId, timestamp in pairs(BurdJournals.Server._rateLimitCache) do
        if now - timestamp > staleThreshold then
            BurdJournals.Server._rateLimitCache[playerId] = nil
        end
    end
end

function BurdJournals.Server.cleanupTransientCommandCaches(nowMs)
    nowMs = tonumber(nowMs) or ((getTimestampMs and getTimestampMs()) or ((os.time() or 0) * 1000))
    for key, pending in pairs(BurdJournals.Server._recordAllExportBaselineQueue) do
        local updatedAt = type(pending) == "table" and tonumber(pending._updatedAt) or 0
        if updatedAt <= 0 or (nowMs - updatedAt) >= 600000 then
            BurdJournals.Server._recordAllExportBaselineQueue[key] = nil
        end
    end
    local preambleCache = BurdJournals.Server._lastPreambleCompactAt
    if type(preambleCache) == "table" then
        for key, lastAt in pairs(preambleCache) do
            if (nowMs - (tonumber(lastAt) or 0)) >= 600000 then preambleCache[key] = nil end
        end
    end
end

function BurdJournals.Server.deepCopy(orig, copies)
    copies = copies or {}
    local origType = type(orig)
    local copy

    if origType == 'table' then

        if copies[orig] then
            copy = copies[orig]
        else
            copy = {}
            copies[orig] = copy
            for origKey, origValue in pairs(orig) do

                local keyCopy = BurdJournals.Server.deepCopy(origKey, copies)
                local valueCopy = BurdJournals.Server.deepCopy(origValue, copies)
                copy[keyCopy] = valueCopy
            end

        end
    else

        copy = orig
    end
    return copy
end

-- Safe wrapper for shouldDissolve that re-fetches the journal by ID to avoid zombie object errors
-- This prevents "Object tried to call nil" crashes when the journal becomes invalid during processing
function BurdJournals.Server.safeShouldDissolve(player, journalId)
    if not player or not journalId then return false end

    -- Re-fetch the journal by ID to get a fresh reference
    local freshJournal = BurdJournals.Server.resolvePostActionJournal(player, journalId, nil)
    if not freshJournal then
        -- Journal no longer exists - treat as dissolved
        return false
    end

    -- Validate the item is still valid (not a zombie object) before calling shouldDissolve
    -- isValidItem uses instanceof which doesn't trigger error logging
    if not BurdJournals.isValidItem(freshJournal) then
        BurdJournals.debugPrint("[BurdJournals] safeShouldDissolve: Item is invalid/zombie, skipping dissolution check")
        return false
    end

    -- Call shouldDissolve with the validated reference
    if BurdJournals.shouldDissolve then
        return BurdJournals.shouldDissolve(freshJournal, player)
    end
    return false
end

-- Post-action claim checks are possession-only. Re-resolve from the requester's
-- inventory so a stale cached reference or nearby world item can never be mutated.
function BurdJournals.Server.resolvePostActionJournal(player, journalId, cachedJournal)
    if not player or journalId == nil then return nil end
    if BurdJournals.Server.findJournalInRequestersInventory then
        local journal, inventorySearched = BurdJournals.Server.findJournalInRequestersInventory(player, journalId, nil, nil)
        if inventorySearched then return journal end
    end
    local inventory = player.getInventory and player:getInventory() or nil
    if inventory and BurdJournals.findItemByIdInContainer then
        return BurdJournals.findItemByIdInContainer(inventory, journalId)
    end
    return nil
end

function BurdJournals.Server.copyJournalData(journal)
    if not journal then return nil end
    local modData = journal:getModData()
    if not modData or not modData.BurdJournals then return nil end

    return BurdJournals.Server.deepCopy(modData.BurdJournals)
end

local function isStrictMPServer()
    return BurdJournals.isStrictMPServerContext and BurdJournals.isStrictMPServerContext()
end

local function estimatePayloadBytes(value, seen, depth)
    local valueType = type(value)
    if valueType == "nil" then
        return 4
    elseif valueType == "boolean" then
        return value and 4 or 5
    elseif valueType == "number" then
        return string.len(tostring(value))
    elseif valueType == "string" then
        return string.len(value)
    elseif valueType == "table" then
        seen = seen or {}
        if seen[value] then
            return 0
        end
        seen[value] = true
        depth = (depth or 0) + 1
        if depth > 32 then
            return 0
        end
        local bytes = 2
        for key, entryValue in pairs(value) do
            bytes = bytes + estimatePayloadBytes(key, seen, depth)
            bytes = bytes + estimatePayloadBytes(entryValue, seen, depth)
            bytes = bytes + 2
        end
        return bytes
    end
    return string.len(tostring(value))
end

function BurdJournals.Server.countJournalPayloadEntries(journalData)
    if type(journalData) ~= "table" then
        return 0
    end
    local count = 0
    local buckets = {"skills", "traits", "stats", "recipes"}
    for _, bucketName in ipairs(buckets) do
        local bucket = journalData[bucketName]
        if type(bucket) == "table" then
            for _ in pairs(bucket) do
                count = count + 1
            end
        end
    end
    local storedCount = 0
    if type(journalData.entryStoreEntryCounts) == "table" then
        for _, bucketName in ipairs(buckets) do
            storedCount = storedCount + math.max(0, tonumber(journalData.entryStoreEntryCounts[bucketName]) or 0)
        end
    end
    if storedCount > 0 then
        if count <= 0 then
            return storedCount
        end
        if journalData.entryStoreEnabled == true and count < storedCount then
            return storedCount + count
        end
    end
    return count
end

function BurdJournals.Server.countResidentJournalPayloadEntries(journalData)
    if type(journalData) ~= "table" then return 0 end
    local count = 0
    for _, bucketName in ipairs(BurdJournals.ENTRY_STORE_BUCKETS or {"skills", "traits", "stats", "recipes"}) do
        local bucket = journalData[bucketName]
        if type(bucket) == "table" then for _ in pairs(bucket) do count = count + 1 end end
    end
    return count
end

function BurdJournals.Server.getJournalEntryFileBackupName(uuid)
    local s = tostring(uuid or "")
    if s == "" then
        return nil
    end
    local cleaned = string.gsub(s, "[^%w_%-]", "_")
    if string.len(cleaned) > 64 then
        cleaned = string.sub(cleaned, 1, 64)
    end
    return "BurdJournals_JournalEntryBackup_" .. cleaned .. ".json"
end

function BurdJournals.Server.buildJournalDataFromEntryStoreEntry(uuid, entry)
    if type(entry) ~= "table" then
        return nil
    end
    local journalData = {
        uuid = uuid,
        entryStoreEnabled = true,
        entryStoreUUID = uuid,
        entryStoreEntryCounts = {},
    }
    for _, bucketName in ipairs(BurdJournals.ENTRY_STORE_BUCKETS or {"skills", "traits", "stats", "recipes"}) do
        local bucket = type(entry[bucketName]) == "table" and entry[bucketName] or {}
        journalData[bucketName] = BurdJournals.Server.deepCopy and BurdJournals.Server.deepCopy(bucket) or bucket
        journalData.entryStoreEntryCounts[bucketName] = BurdJournals.Server.countJournalPayloadEntries({[bucketName] = bucket})
    end
    journalData.entryStoreUpdatedAt = entry.updatedAt
    return journalData
end

function BurdJournals.Server.restoreJournalEntryStoreFromPayload(uuid, journalData, sourceTag)
    if type(uuid) ~= "string" or uuid == "" or type(journalData) ~= "table"
        or BurdJournals.Server.countResidentJournalPayloadEntries(journalData) <= 0
        or not BurdJournals.getOrCreateJournalEntryStoreEntryForData then return false end
    local identity = {uuid = uuid, entryStoreUUID = uuid, entryStoreEnabled = true}
    local entry, shardKey = BurdJournals.getOrCreateJournalEntryStoreEntryForData(identity, true, nil,
        sourceTag or "entryStoreRecovery")
    if type(entry) ~= "table" or type(shardKey) ~= "string" or shardKey == "" then return false end
    for _, bucketName in ipairs(BurdJournals.ENTRY_STORE_BUCKETS or {"skills", "traits", "stats", "recipes"}) do
        local sourceBucket = journalData[bucketName]
        local targetBucket = type(entry[bucketName]) == "table" and entry[bucketName] or {}
        if type(sourceBucket) == "table" then
            for key, value in pairs(sourceBucket) do
                targetBucket[key] = BurdJournals.normalizeEntryBucketValue
                    and BurdJournals.normalizeEntryBucketValue(bucketName, value)
                    or BurdJournals.Server.deepCopy(value)
            end
        end
        entry[bucketName] = targetBucket
    end
    entry.updatedAt = math.max(tonumber(entry.updatedAt) or 0, tonumber(journalData.entryStoreUpdatedAt) or 0,
        getTimestampMs and getTimestampMs() or 0)
    local shard = BurdJournals._getJournalEntryStoreShard and BurdJournals._getJournalEntryStoreShard(shardKey, false) or nil
    if type(shard) ~= "table" or not BurdJournals.persistJournalEntryStoreShard
        or BurdJournals.persistJournalEntryStoreShard(shardKey, shard) ~= true then return false end
    bsjWriteLogLine("[BurdJournals][EntryStoreFileBackup] restored authoritative entry store"
        .. " uuid=" .. tostring(uuid) .. " source=" .. tostring(sourceTag or "entryStoreRecovery")
        .. " entries=" .. tostring(BurdJournals.Server.countResidentJournalPayloadEntries(journalData)))
    return true
end

function BurdJournals.Server.writeJournalEntryFileBackup(uuid, entry, sourceTag)
    if not (getFileWriter and BurdJournals.encodeJournalExportJSON) then
        return false
    end
    local filename = BurdJournals.Server.getJournalEntryFileBackupName(uuid)
    if not filename then
        return false
    end
    local journalData = BurdJournals.Server.buildJournalDataFromEntryStoreEntry(uuid, entry)
    if type(journalData) ~= "table" or BurdJournals.Server.countJournalPayloadEntries(journalData) <= 0 then
        return false
    end
    local payload = {
        schema = "BurdJournals.EntryStoreFileBackup",
        version = 1,
        uuid = uuid,
        source = tostring(sourceTag or "entryStore"),
        updatedAt = getTimestampMs and getTimestampMs() or os.time(),
        journalData = journalData,
    }
    local jsonText = BurdJournals.encodeJournalExportJSON(payload)
    if type(jsonText) ~= "string" or jsonText == "" then
        return false
    end
    -- File IO can legitimately fail independently of journal state. Keep each
    -- protected operation narrow so a failed write cannot masquerade as a
    -- successful backup and always attempt to release an opened writer.
    local opened, writer = pcall(getFileWriter, filename, true, false)
    if not opened or not writer then
        return false
    end
    local wrotePayload = pcall(writer.write, writer, jsonText)
    local wroteNewline = wrotePayload and pcall(writer.write, writer, "\r\n") or false
    local closed = pcall(writer.close, writer)
    local ok = wrotePayload and wroteNewline and closed
    if ok then
        bsjWriteLogLine("[BurdJournals][EntryStoreFileBackup] wrote uuid="
            .. tostring(uuid)
            .. " source=" .. tostring(sourceTag or "entryStore")
            .. " entries=" .. tostring(BurdJournals.Server.countJournalPayloadEntries(journalData)))
    end
    return ok == true
end

function BurdJournals.Server.invalidateJournalEntryFileBackup(uuid, sourceTag)
    if not (getFileReader and getFileWriter and BurdJournals.encodeJournalExportJSON) then
        return false
    end
    local filename = BurdJournals.Server.getJournalEntryFileBackupName(uuid)
    if not filename then
        return false
    end

    -- PZ exposes overwrite-capable readers/writers here but no stable cross-build
    -- delete API. Only create a tombstone when a backup actually exists.
    local openedReader, reader = pcall(getFileReader, filename, true)
    if not openedReader or not reader then
        return false
    end
    pcall(reader.close, reader)

    local payload = {
        schema = "BurdJournals.EntryStoreFileBackupTombstone",
        version = 1,
        uuid = uuid,
        source = tostring(sourceTag or "purged"),
        deleted = true,
        updatedAt = getTimestampMs and getTimestampMs() or os.time(),
    }
    local jsonText = BurdJournals.encodeJournalExportJSON(payload)
    if type(jsonText) ~= "string" or jsonText == "" then
        return false
    end
    local openedWriter, writer = pcall(getFileWriter, filename, true, false)
    if not openedWriter or not writer then
        return false
    end
    local wrotePayload = pcall(writer.write, writer, jsonText)
    local wroteNewline = wrotePayload and pcall(writer.write, writer, "\r\n") or false
    local closed = pcall(writer.close, writer)
    return wrotePayload and wroteNewline and closed
end

-- File backups are belt-and-suspenders recovery data (the authoritative entries
-- live in global ModData), so they never need to happen on the hot path. Writers
-- enqueue here and the server tick drains one JSON write per tick; the entry is
-- re-resolved at write time so coalesced queue hits always capture fresh data.
BurdJournals.Server._pendingEntryFileBackups = BurdJournals.Server._pendingEntryFileBackups or {}

function BurdJournals.Server.queueJournalEntryFileBackup(uuid, shardKey, sourceTag)
    if type(uuid) ~= "string" or uuid == "" then
        return false
    end
    BurdJournals.Server._pendingEntryFileBackups[uuid] = {
        shardKey = shardKey,
        sourceTag = tostring(sourceTag or "queued"),
    }
    return true
end

function BurdJournals.Server.drainPendingEntryFileBackups(maxWrites)
    local pending = BurdJournals.Server._pendingEntryFileBackups
    if type(pending) ~= "table" then
        return 0
    end
    local budget = math.max(1, tonumber(maxWrites) or 1)
    local written = 0
    local nowMs = (getTimestampMs and getTimestampMs()) or ((os.time() or 0) * 1000)
    for uuid, info in pairs(pending) do
        if budget <= 0 then
            break
        end
        local retryAfterMs = type(info) == "table" and tonumber(info.retryAfterMs) or 0
        if retryAfterMs <= nowMs then
            local entry = nil
            if BurdJournals._getLegacyJournalEntryStoreEntry then
                entry = BurdJournals._getLegacyJournalEntryStoreEntry(uuid, info and info.shardKey)
            end
            if type(entry) ~= "table" then
                pending[uuid] = nil
            elseif BurdJournals.Server.writeJournalEntryFileBackup(uuid, entry, info and info.sourceTag) then
                pending[uuid] = nil
                written = written + 1
            else
                info = type(info) == "table" and info or {}
                info.attempts = (tonumber(info.attempts) or 0) + 1
                info.retryAfterMs = nowMs + math.min(60000, info.attempts * 5000)
                pending[uuid] = info
            end
            budget = budget - 1
        end
    end
    return written
end

function BurdJournals.Server.readJournalEntryFileBackup(uuid, sourceTag)
    if not (getFileReader and BurdJournals.decodeJournalExportJSON) then
        return nil
    end
    local filename = BurdJournals.Server.getJournalEntryFileBackupName(uuid)
    if not filename then
        return nil
    end
    -- File handles are an optional persistence boundary and may legitimately
    -- be stale. Protect only the individual I/O calls; never hide decode or
    -- journal-state defects behind one broad catch.
    local opened, reader = pcall(getFileReader, filename, true)
    if not opened or not reader then return nil end
    local text, byteCount, readFailed = {}, 0, false
    while #text < 8000 and byteCount <= 1048576 do
        local readOk, line = pcall(reader.readLine, reader)
        if not readOk then readFailed = true break end
        if line == nil then break end
        byteCount = byteCount + #tostring(line)
        text[#text + 1] = line
    end
    local closeOk = pcall(reader.close, reader)
    if readFailed or not closeOk or byteCount > 1048576 or #text >= 8000 or #text <= 0 then
        return nil
    end
    local decoded = BurdJournals.decodeJournalExportJSON(table.concat(text, "\n"))
    local journalData = type(decoded) == "table" and decoded.journalData or nil
    if type(journalData) ~= "table" or BurdJournals.Server.countJournalPayloadEntries(journalData) <= 0 then
        return nil
    end
    journalData.uuid = journalData.uuid or uuid
    journalData.entryStoreUUID = journalData.entryStoreUUID or uuid
    journalData.entryStoreEnabled = true
    bsjWriteLogLine("[BurdJournals][EntryStoreFileBackup] read uuid="
        .. tostring(uuid)
        .. " source=" .. tostring(sourceTag or "nil")
        .. " entries=" .. tostring(BurdJournals.Server.countJournalPayloadEntries(journalData)))
    return journalData
end

function BurdJournals.Server.hasAnyDeltaEntries(delta)
    if type(delta) ~= "table" then
        return false
    end
    return (BurdJournals.hasAnyEntries and (
            BurdJournals.hasAnyEntries(delta.skills)
            or BurdJournals.hasAnyEntries(delta.traits)
            or BurdJournals.hasAnyEntries(delta.stats)
            or BurdJournals.hasAnyEntries(delta.recipes)
        ))
        or false
end

function BurdJournals.Server.normalizeEntrySyncBucket(bucketName)
    local wanted = tostring(bucketName or "")
    for _, candidate in ipairs(BurdJournals.ENTRY_STORE_BUCKETS or {"skills", "traits", "stats", "recipes"}) do
        if wanted == candidate then
            return candidate
        end
    end
    return "skills"
end

function BurdJournals.Server.collectSortedEntryKeys(bucket)
    local keys = {}
    if type(bucket) ~= "table" then
        return keys
    end
    for key, value in pairs(bucket) do
        if key ~= nil and value ~= nil then
            keys[#keys + 1] = tostring(key)
        end
    end
    table.sort(keys)
    return keys
end

BurdJournals.Server.ENTRY_CHUNK_KEY_CACHE_TTL_MS = 30000
BurdJournals.Server.ENTRY_CHUNK_KEY_CACHE_MAX = 64

function BurdJournals.Server.pruneEntryChunkKeyCache(now)
    now = tonumber(now) or 0
    local cache = BurdJournals.Server._entryChunkKeyCache
    local retained = {}
    for key, cached in pairs(cache) do
        local timestamp = tonumber(type(cached) == "table" and cached.timestamp or 0) or 0
        if type(cached) ~= "table" or (now > 0 and timestamp > 0 and (now - timestamp) > BurdJournals.Server.ENTRY_CHUNK_KEY_CACHE_TTL_MS) then
            cache[key] = nil
        else
            retained[#retained + 1] = { key = key, timestamp = timestamp }
        end
    end
    table.sort(retained, function(a, b) return a.timestamp < b.timestamp end)
    for index = 1, math.max(0, #retained - BurdJournals.Server.ENTRY_CHUNK_KEY_CACHE_MAX) do
        cache[retained[index].key] = nil
    end
end

function BurdJournals.Server.collectCachedEntryKeys(journalData, bucketName, bucket)
    local now = getTimestampMs and getTimestampMs() or 0
    BurdJournals.Server.pruneEntryChunkKeyCache(now)
    local journalUUID = BurdJournals.getJournalIdentityUUID and BurdJournals.getJournalIdentityUUID(journalData) or nil
    local cacheKey = tostring(journalUUID or "unknown") .. ":" .. tostring(bucketName or "skills")
    local bucketToken = tostring(bucket)
    local count = 0
    if type(bucket) == "table" then
        for key, value in pairs(bucket) do
            if key ~= nil and value ~= nil then
                count = count + 1
            end
        end
    end
    local cached = BurdJournals.Server._entryChunkKeyCache[cacheKey]
    if cached
        and cached.bucketToken == bucketToken
        and cached.count == count
        and now - (cached.timestamp or 0) <= 10000
        and type(cached.keys) == "table"
    then
        cached.timestamp = now
        return cached.keys
    end
    local keys = BurdJournals.Server.collectSortedEntryKeys(bucket)
    BurdJournals.Server._entryChunkKeyCache[cacheKey] = {
        bucketToken = bucketToken,
        count = count,
        timestamp = now,
        keys = keys,
    }
    BurdJournals.Server.pruneEntryChunkKeyCache(now)
    return keys
end

function BurdJournals.Server.getJournalEntrySyncBucket(journalData, bucketName)
    if type(journalData) ~= "table" then
        return nil
    end
    local entry = BurdJournals.getOrCreateJournalEntryStoreEntryForData
        and BurdJournals.getOrCreateJournalEntryStoreEntryForData(journalData, false)
        or nil
    if type(entry) == "table" and type(entry[bucketName]) == "table" then
        return entry[bucketName]
    end
    return journalData[bucketName]
end

function BurdJournals.Server.getJournalEntrySyncBucketFromRegistry(journalData, bucketName, sourceTag)
    if type(journalData) ~= "table" or type(bucketName) ~= "string" then
        return nil
    end
    local journalUUID = BurdJournals.getJournalIdentityUUID and BurdJournals.getJournalIdentityUUID(journalData) or nil
    if not journalUUID then
        return nil
    end
    local registryEntry = BurdJournals.Server.getPlayerJournalRegistryEntryByUUID
        and BurdJournals.Server.getPlayerJournalRegistryEntryByUUID(journalUUID)
        or nil
    local registryData = type(registryEntry) == "table" and registryEntry.journalData or nil
    -- The registry deliberately stores an entry-store manifest in strict MP.
    -- Materialize it only for this actual server recovery/chunk request.
    if type(registryData) == "table" and registryData.entryStoreEnabled == true
        and BurdJournals.hydrateJournalDataFromEntryStore then
        registryData = BurdJournals.Server.deepCopy(registryData)
        BurdJournals.hydrateJournalDataFromEntryStore(registryData, "playerRegistryEntryRecovery")
    end
    local registryBucket = type(registryData) == "table" and registryData[bucketName] or nil
    if type(registryBucket) ~= "table" or not (BurdJournals.hasAnyEntries and BurdJournals.hasAnyEntries(registryBucket)) then
        return nil
    end
    bsjWriteLogLine("[BurdJournals][EntryStoreFallback] serving chunk bucket from player journal registry"
        .. " uuid=" .. tostring(journalUUID)
        .. " bucket=" .. tostring(bucketName)
        .. " source=" .. tostring(sourceTag or "nil")
        .. " entries=" .. tostring(BurdJournals.Server.countJournalPayloadEntries(registryData)))
    return registryBucket, registryData
end

function BurdJournals.Server.getJournalEntrySyncBucketFromFileBackup(journalData, bucketName, sourceTag)
    if type(journalData) ~= "table" or type(bucketName) ~= "string" then
        return nil
    end
    local journalUUID = BurdJournals.getJournalIdentityUUID and BurdJournals.getJournalIdentityUUID(journalData) or nil
    if not journalUUID then
        return nil
    end
    local backupData = BurdJournals.Server.readJournalEntryFileBackup
        and BurdJournals.Server.readJournalEntryFileBackup(journalUUID, sourceTag or "entryChunk")
        or nil
    local backupBucket = type(backupData) == "table" and backupData[bucketName] or nil
    if type(backupBucket) ~= "table" or not (BurdJournals.hasAnyEntries and BurdJournals.hasAnyEntries(backupBucket)) then
        return nil
    end
    bsjWriteLogLine("[BurdJournals][EntryStoreFileBackup] serving chunk bucket"
        .. " uuid=" .. tostring(journalUUID)
        .. " bucket=" .. tostring(bucketName)
        .. " source=" .. tostring(sourceTag or "nil")
        .. " entries=" .. tostring(BurdJournals.Server.countJournalPayloadEntries(backupData)))
    return backupBucket, backupData
end

function BurdJournals.Server.repairMissingEntryStoreFromInlineData(journalData, sourceTag)
    if type(journalData) ~= "table" or journalData.entryStoreEnabled ~= true then
        return false
    end
    local hasInlineEntries = false
    for _, bucketName in ipairs(BurdJournals.ENTRY_STORE_BUCKETS or {"skills", "traits", "stats", "recipes"}) do
        if BurdJournals.hasAnyEntries and BurdJournals.hasAnyEntries(journalData[bucketName]) then
            hasInlineEntries = true
            break
        end
    end
    if not hasInlineEntries then
        return false
    end

    local entry, shardKey = BurdJournals.getOrCreateJournalEntryStoreEntryForData
        and BurdJournals.getOrCreateJournalEntryStoreEntryForData(journalData, true, nil, sourceTag or "repairMissingEntryStore")
        or nil
    if type(entry) ~= "table" then
        return false
    end

    journalData.entryStoreEntryCounts = type(journalData.entryStoreEntryCounts) == "table" and journalData.entryStoreEntryCounts or {}
    for _, bucketName in ipairs(BurdJournals.ENTRY_STORE_BUCKETS or {"skills", "traits", "stats", "recipes"}) do
        local bucket = journalData[bucketName]
        if type(bucket) == "table" then
            entry[bucketName] = entry[bucketName] or {}
            local count = 0
            for key, value in pairs(bucket) do
                entry[bucketName][key] = BurdJournals.Server.deepCopy and BurdJournals.Server.deepCopy(value) or value
                count = count + 1
            end
            if count > 0 then
                journalData.entryStoreEntryCounts[bucketName] = math.max(count, tonumber(journalData.entryStoreEntryCounts[bucketName]) or 0)
            end
        end
    end
    if shardKey and BurdJournals.markEntryStoreShardDirty then
        BurdJournals.markEntryStoreShardDirty(shardKey, true)
    end
    bsjWriteLogLine("[BurdJournals][EntryStoreRepair] repaired missing shard from inline data uuid="
        .. tostring(journalData.uuid or journalData.entryStoreUUID)
        .. " source=" .. tostring(sourceTag or "nil")
        .. " counts=" .. bsjFormatEntryStoreCounts(journalData.entryStoreEntryCounts))
    return true
end

function BurdJournals.Server.buildJournalEntryChunkPayload(journalId, journalData, args)
    local canonicalUUID = BurdJournals.getJournalIdentityUUID and BurdJournals.getJournalIdentityUUID(journalData) or nil
    local bucketName = BurdJournals.Server.normalizeEntrySyncBucket(args and args.bucket)
    local offset = math.max(0, tonumber(args and args.offset) or 0)
    local chunkSize = math.max(1, math.min(128, tonumber(args and args.chunkSize) or tonumber(BurdJournals.ENTRY_SYNC_CHUNK_SIZE) or 64))
    local sourceBucket = BurdJournals.Server.getJournalEntrySyncBucket(journalData, bucketName)
    local expectedCount = type(journalData.entryStoreEntryCounts) == "table"
        and math.max(0, tonumber(journalData.entryStoreEntryCounts[bucketName]) or 0)
        or 0
    if journalData.entryStoreEnabled == true and expectedCount > 0 and type(sourceBucket) ~= "table" then
        if BurdJournals.Server.repairMissingEntryStoreFromInlineData(journalData, "buildJournalEntryChunkPayload") then
            sourceBucket = BurdJournals.Server.getJournalEntrySyncBucket(journalData, bucketName)
        end
    end
    if journalData.entryStoreEnabled == true and expectedCount > 0 and type(sourceBucket) ~= "table" then
        local registryBucket, registryData = BurdJournals.Server.getJournalEntrySyncBucketFromRegistry(journalData, bucketName, "missingSourceBucket")
        if type(registryBucket) == "table" then
            sourceBucket = registryBucket
            if type(registryData) == "table" and type(registryData.entryStoreEntryCounts) == "table" then
                journalData.entryStoreEntryCounts = registryData.entryStoreEntryCounts
                expectedCount = math.max(0, tonumber(journalData.entryStoreEntryCounts[bucketName]) or 0)
            end
        end
    end
    if journalData.entryStoreEnabled == true and expectedCount > 0 and type(sourceBucket) ~= "table" then
        local fileBucket, fileData = BurdJournals.Server.getJournalEntrySyncBucketFromFileBackup(journalData, bucketName, "missingSourceBucket")
        if type(fileBucket) == "table" then
            sourceBucket = fileBucket
            if type(fileData) == "table" and type(fileData.entryStoreEntryCounts) == "table" then
                journalData.entryStoreEntryCounts = fileData.entryStoreEntryCounts
                expectedCount = math.max(0, tonumber(journalData.entryStoreEntryCounts[bucketName]) or 0)
            end
        end
    end
    if journalData.entryStoreEnabled == true and expectedCount > 0 and type(sourceBucket) ~= "table" then
        local journalUUID = canonicalUUID
        local derivedShardKey = BurdJournals.getJournalEntryStoreShardKeyForUUID and BurdJournals.getJournalEntryStoreShardKeyForUUID(journalUUID) or nil
        local legacyShardKey = BurdJournals._getJournalEntryStoreLegacyShardKeyForUUID and BurdJournals._getJournalEntryStoreLegacyShardKeyForUUID(journalUUID) or nil
        bsjWriteLogLine("[BurdJournals][EntryStoreUnavailable] missing source bucket"
            .. " journalId=" .. tostring(journalId)
            .. " uuid=" .. tostring(journalUUID)
            .. " bucket=" .. tostring(bucketName)
            .. " expected=" .. tostring(expectedCount)
            .. " stampedShard=" .. tostring(journalData.entryStoreShardKey)
            .. " derivedShard=" .. tostring(derivedShardKey)
            .. " legacyShard=" .. tostring(legacyShardKey)
            .. " counts=" .. bsjFormatEntryStoreCounts(journalData.entryStoreEntryCounts))
        return {
            requestId = args and args.requestId or nil,
            serverRuntimeMarker = BurdJournals.RUNTIME_LOAD_MARKER,
            journalId = journalId,
            journalUUID = journalUUID,
            bucket = bucketName,
            offset = offset,
            nextOffset = offset,
            total = expectedCount,
            done = false,
            chunkSize = chunkSize,
            entryStoreEnabled = true,
            entryStoreEntryCounts = journalData.entryStoreEntryCounts,
            error = "Journal entry store unavailable.",
            terminal = true,
            entryStoreUnavailable = true,
        }
    end
    local keys = BurdJournals.Server.collectCachedEntryKeys(journalData, bucketName, sourceBucket)
    local total = #keys
    if journalData.entryStoreEnabled == true and expectedCount > 0 and total <= 0 then
        local registryBucket, registryData = BurdJournals.Server.getJournalEntrySyncBucketFromRegistry(journalData, bucketName, "emptySourceBucket")
        if type(registryBucket) == "table" then
            sourceBucket = registryBucket
            if type(registryData) == "table" and type(registryData.entryStoreEntryCounts) == "table" then
                journalData.entryStoreEntryCounts = registryData.entryStoreEntryCounts
                expectedCount = math.max(0, tonumber(journalData.entryStoreEntryCounts[bucketName]) or 0)
            end
            keys = BurdJournals.Server.collectCachedEntryKeys(journalData, bucketName, sourceBucket)
            total = #keys
        end
    end
    if journalData.entryStoreEnabled == true and expectedCount > 0 and total <= 0 then
        local fileBucket, fileData = BurdJournals.Server.getJournalEntrySyncBucketFromFileBackup(journalData, bucketName, "emptySourceBucket")
        if type(fileBucket) == "table" then
            sourceBucket = fileBucket
            if type(fileData) == "table" and type(fileData.entryStoreEntryCounts) == "table" then
                journalData.entryStoreEntryCounts = fileData.entryStoreEntryCounts
                expectedCount = math.max(0, tonumber(journalData.entryStoreEntryCounts[bucketName]) or 0)
            end
            keys = BurdJournals.Server.collectCachedEntryKeys(journalData, bucketName, sourceBucket)
            total = #keys
        end
    end
    if journalData.entryStoreEnabled == true and expectedCount > 0 and total <= 0 then
        local journalUUID = canonicalUUID
        local derivedShardKey = BurdJournals.getJournalEntryStoreShardKeyForUUID and BurdJournals.getJournalEntryStoreShardKeyForUUID(journalUUID) or nil
        local legacyShardKey = BurdJournals._getJournalEntryStoreLegacyShardKeyForUUID and BurdJournals._getJournalEntryStoreLegacyShardKeyForUUID(journalUUID) or nil
        bsjWriteLogLine("[BurdJournals][EntryStoreUnavailable] empty source bucket"
            .. " journalId=" .. tostring(journalId)
            .. " uuid=" .. tostring(journalUUID)
            .. " bucket=" .. tostring(bucketName)
            .. " expected=" .. tostring(expectedCount)
            .. " stampedShard=" .. tostring(journalData.entryStoreShardKey)
            .. " derivedShard=" .. tostring(derivedShardKey)
            .. " legacyShard=" .. tostring(legacyShardKey)
            .. " counts=" .. bsjFormatEntryStoreCounts(journalData.entryStoreEntryCounts))
        return {
            requestId = args and args.requestId or nil,
            serverRuntimeMarker = BurdJournals.RUNTIME_LOAD_MARKER,
            journalId = journalId,
            journalUUID = journalUUID,
            bucket = bucketName,
            offset = offset,
            nextOffset = offset,
            total = expectedCount,
            done = false,
            chunkSize = chunkSize,
            entryStoreEnabled = true,
            entryStoreEntryCounts = journalData.entryStoreEntryCounts,
            error = "Journal entry store unavailable.",
            terminal = true,
            entryStoreUnavailable = true,
        }
    end
    if offset > total then
        offset = total
    end

    local entries = {}
    local lastIndex = math.min(total, offset + chunkSize)
    for i = offset + 1, lastIndex do
        local key = keys[i]
        entries[key] = BurdJournals.Server.deepCopy and BurdJournals.Server.deepCopy(sourceBucket[key]) or sourceBucket[key]
    end

    return {
        requestId = args and args.requestId or nil,
        serverRuntimeMarker = BurdJournals.RUNTIME_LOAD_MARKER,
        journalId = journalId,
        journalUUID = canonicalUUID,
        bucket = bucketName,
        entries = entries,
        offset = offset,
        nextOffset = lastIndex,
        total = total,
        done = lastIndex >= total,
        chunkSize = chunkSize,
        buckets = BurdJournals.ENTRY_STORE_BUCKETS or {"skills", "traits", "stats", "recipes"},
        entryStoreEnabled = journalData.entryStoreEnabled == true,
        entryStoreEntryCounts = type(journalData.entryStoreEntryCounts) == "table" and journalData.entryStoreEntryCounts or nil,
        entryStoreUpdatedAt = journalData.entryStoreUpdatedAt,
    }
end

local function isEntryStoreFallbackPlayerJournalIdentitySource(source)
    if type(source) ~= "table" then
        return false
    end
    if source.isYuletideJournal == true
        and source.yuletideState == BurdJournals.YULETIDE_STATE_UNWRAPPED
    then
        return false
    end
    if source.isPlayerCreated == true then
        return true
    end
    if source.isPlayerCreated == nil
        and (source.ownerUsername or source.ownerSteamId or source.ownerCharacterName)
        and source.isWorn ~= true
        and source.isBloody ~= true
    then
        return true
    end
    local sourceType = string.lower(tostring(source.sourceType or ""))
    local originMode = string.lower(tostring(source.originMode or ""))
    return sourceType == "personal" or sourceType == "player" or originMode == "personal" or originMode == "player"
end

local function copyEntryStoreFallbackIdentityFields(target, source)
    if type(target) ~= "table" or type(source) ~= "table" then
        return
    end
    local keys = {
        "ownerUsername",
        "ownerSteamId",
        "ownerCharacterName",
        "author",
        "profession",
        "professionName",
        "recordedWithBaseline",
        "baselineId",
        "baselineCharacterId",
        "sourceType",
        "originMode",
        "respawnGeneration",
        "lastPlayerJournalUseTs",
    }
    for _, key in ipairs(keys) do
        if target[key] == nil and source[key] ~= nil then
            target[key] = source[key]
        end
    end
    if target.skillBaseline == nil and type(source.skillBaseline) == "table" then
        target.skillBaseline = BurdJournals.Server.deepCopy and BurdJournals.Server.deepCopy(source.skillBaseline) or source.skillBaseline
    end
end

local function preserveEntryStoreFallbackPlayerJournalIdentity(fallbackData, sourceData, journalUUID, sourceTag)
    if type(fallbackData) ~= "table" then
        return fallbackData
    end

    local registryEntry = nil
    if type(journalUUID) == "string" and journalUUID ~= "" and BurdJournals.Server.getPlayerJournalRegistryEntryByUUID then
        registryEntry = BurdJournals.Server.getPlayerJournalRegistryEntryByUUID(journalUUID)
    end
    local registryData = type(registryEntry) == "table" and registryEntry.journalData or nil

    local hasPlayerJournalProof = isEntryStoreFallbackPlayerJournalIdentitySource(sourceData)
        or isEntryStoreFallbackPlayerJournalIdentitySource(registryData)
        or isEntryStoreFallbackPlayerJournalIdentitySource(registryEntry)
    if not hasPlayerJournalProof then
        return fallbackData
    end

    copyEntryStoreFallbackIdentityFields(fallbackData, registryData)
    copyEntryStoreFallbackIdentityFields(fallbackData, registryEntry)
    copyEntryStoreFallbackIdentityFields(fallbackData, sourceData)
    fallbackData.isPlayerCreated = true
    if fallbackData.sourceType == nil or tostring(fallbackData.sourceType) == "" then
        fallbackData.sourceType = "personal"
    end
    if fallbackData.originMode == nil or tostring(fallbackData.originMode) == "" then
        fallbackData.originMode = "personal"
    end
    fallbackData.isWorn = false
    fallbackData.isBloody = false

    bsjWriteLogLine("[BurdJournals][EntryStoreFallback] preserved player journal identity"
        .. " uuid=" .. tostring(journalUUID or fallbackData.uuid or fallbackData.entryStoreUUID)
        .. " source=" .. tostring(sourceTag or "nil")
        .. " owner=" .. tostring(fallbackData.ownerUsername or fallbackData.ownerSteamId or fallbackData.ownerCharacterName or "nil"))

    return fallbackData
end

function BurdJournals.Server.buildEntryStoreOnlyJournalData(journalUUID, sourceTag)
    if type(journalUUID) ~= "string" or journalUUID == "" then
        return nil
    end
    local journalData = {
        uuid = journalUUID,
        entryStoreEnabled = true,
        entryStoreUUID = journalUUID,
        entryStoreEntryCounts = {},
    }
    local entry = BurdJournals.getOrCreateJournalEntryStoreEntryForData
        and BurdJournals.getOrCreateJournalEntryStoreEntryForData(journalData, false, nil, sourceTag or "entryStoreOnly")
        or nil
    local liveEntryCount = type(entry) == "table"
        and BurdJournals.Server.countResidentJournalPayloadEntries(entry) or 0
    if liveEntryCount > 0 and BurdJournals.Server.readJournalEntryFileBackup
        and BurdJournals.Server.restoreJournalEntryStoreFromPayload
    then
        local fileData = BurdJournals.Server.readJournalEntryFileBackup(
            journalUUID, (sourceTag or "entryStoreOnly") .. "CompareLive")
        local fileEntryCount = type(fileData) == "table"
            and BurdJournals.Server.countResidentJournalPayloadEntries(fileData) or 0
        if fileEntryCount > liveEntryCount
            and BurdJournals.Server.restoreJournalEntryStoreFromPayload(
                journalUUID, fileData, (sourceTag or "entryStoreOnly") .. "RepairLive")
        then
            entry = BurdJournals.getOrCreateJournalEntryStoreEntryForData(
                journalData, false, nil, (sourceTag or "entryStoreOnly") .. "RepairLiveVerify")
        end
    end
    if type(entry) ~= "table"
        or BurdJournals.Server.countResidentJournalPayloadEntries(entry) <= 0
    then
        local registryEntry = BurdJournals.Server.getPlayerJournalRegistryEntryByUUID
            and BurdJournals.Server.getPlayerJournalRegistryEntryByUUID(journalUUID)
            or nil
        local registryData = type(registryEntry) == "table" and registryEntry.journalData or nil
        if type(registryData) == "table" and BurdJournals.Server.countResidentJournalPayloadEntries(registryData) > 0 then
            local fallback = BurdJournals.Server.deepCopy(registryData)
            fallback.uuid = fallback.uuid or journalUUID
            fallback.entryStoreUUID = fallback.entryStoreUUID or journalUUID
            local registryStoreRestored = fallback.entryStoreEnabled ~= true
                or BurdJournals.Server.restoreJournalEntryStoreFromPayload(
                    journalUUID, fallback, sourceTag or "entryStoreOnlyRegistry")
            if registryStoreRestored then
                fallback._entryStoreFallbackSource = tostring(sourceTag or "entryStoreOnly")
                preserveEntryStoreFallbackPlayerJournalIdentity(fallback, registryEntry, journalUUID, sourceTag or "entryStoreOnly")
                bsjWriteLogLine("[BurdJournals][EntryStoreFallback] restored journalData from registry backup"
                    .. " uuid=" .. tostring(journalUUID) .. " source=" .. tostring(sourceTag or "entryStoreOnly")
                    .. " entries=" .. tostring(BurdJournals.Server.countJournalPayloadEntries(fallback)))
                return fallback
            end
        end
        local fileData = BurdJournals.Server.readJournalEntryFileBackup
            and BurdJournals.Server.readJournalEntryFileBackup(journalUUID, sourceTag or "entryStoreOnly")
            or nil
        if type(fileData) == "table" and BurdJournals.Server.countResidentJournalPayloadEntries(fileData) > 0 then
            fileData.uuid = fileData.uuid or journalUUID
            fileData.entryStoreUUID = fileData.entryStoreUUID or journalUUID
            if not BurdJournals.Server.restoreJournalEntryStoreFromPayload(
                journalUUID, fileData, sourceTag or "entryStoreOnlyFile") then
                bsjWriteLogLine("[BurdJournals][EntryStoreFileBackup] restore failed uuid=" .. tostring(journalUUID)
                    .. " source=" .. tostring(sourceTag or "entryStoreOnlyFile"))
                return nil
            end
            fileData._entryStoreFallbackSource = tostring(sourceTag or "entryStoreOnlyFile")
            preserveEntryStoreFallbackPlayerJournalIdentity(fileData, registryEntry, journalUUID, sourceTag or "entryStoreOnlyFile")
            return fileData
        end
        return nil
    end
    journalData.entryStoreUpdatedAt = tonumber(entry.updatedAt) or journalData.entryStoreUpdatedAt
    for _, bucketName in ipairs(BurdJournals.ENTRY_STORE_BUCKETS or {"skills", "traits", "stats", "recipes"}) do
        local bucket = entry[bucketName]
        local count = 0
        if type(bucket) == "table" then
            for key, value in pairs(bucket) do
                if key ~= nil and value ~= nil then
                    count = count + 1
                end
            end
        end
        journalData.entryStoreEntryCounts[bucketName] = count
    end
    return journalData
end

function BurdJournals.Server.preferEntryStoreDataForEmptyShell(journalData, args, sourceTag)
    if type(journalData) ~= "table" then
        return journalData
    end
    if BurdJournals.Server.countJournalPayloadEntries(journalData) > 0 then
        return journalData
    end
    local fallbackUUID = type(journalData.entryStoreUUID) == "string" and journalData.entryStoreUUID ~= "" and journalData.entryStoreUUID
        or (type(journalData.uuid) == "string" and journalData.uuid ~= "" and journalData.uuid)
        or (type(journalData.replacedByJournalUUID) == "string" and journalData.replacedByJournalUUID ~= "" and journalData.replacedByJournalUUID)
        or (type(args) == "table" and type(args.journalUUID) == "string" and args.journalUUID ~= "" and args.journalUUID)
        or (type(args) == "table" and type(args.entryStoreUUID) == "string" and args.entryStoreUUID ~= "" and args.entryStoreUUID)
    local fallbackJournalData = fallbackUUID
        and BurdJournals.Server.buildEntryStoreOnlyJournalData
        and BurdJournals.Server.buildEntryStoreOnlyJournalData(fallbackUUID, sourceTag or "emptyShellEntryStoreFallback")
        or nil
    local fallbackStoreCount = 0
    if type(fallbackJournalData) == "table" and type(fallbackJournalData.entryStoreEntryCounts) == "table" then
        for _, bucketName in ipairs(BurdJournals.ENTRY_STORE_BUCKETS or {"skills", "traits", "stats", "recipes"}) do
            fallbackStoreCount = fallbackStoreCount + math.max(0, tonumber(fallbackJournalData.entryStoreEntryCounts[bucketName]) or 0)
        end
    end
    if fallbackStoreCount > 0 then
        preserveEntryStoreFallbackPlayerJournalIdentity(fallbackJournalData, journalData, fallbackUUID, sourceTag or "emptyShellEntryStoreFallback")
        return fallbackJournalData
    end
    return journalData
end

function BurdJournals.Server.countEntryStoreManifestEntries(journalData)
    local counts = type(journalData) == "table" and journalData.entryStoreEntryCounts or nil
    if type(counts) ~= "table" then return 0 end
    local total = 0
    for _, bucketName in ipairs(BurdJournals.ENTRY_STORE_BUCKETS or {"skills", "traits", "stats", "recipes"}) do
        total = total + math.max(0, tonumber(counts[bucketName]) or 0)
    end
    return total
end

-- A replicated non-empty partial item can still be older than its same-UUID
-- server entry store. Preserve metadata, but make the richer store authoritative.
function BurdJournals.Server.preferRicherEntryStoreData(journalData, args, sourceTag)
    if type(journalData) ~= "table" then return journalData, false end
    local journalUUID = type(journalData.entryStoreUUID) == "string" and journalData.entryStoreUUID ~= "" and journalData.entryStoreUUID
        or (type(journalData.uuid) == "string" and journalData.uuid ~= "" and journalData.uuid)
        or (type(journalData.replacedByJournalUUID) == "string" and journalData.replacedByJournalUUID ~= "" and journalData.replacedByJournalUUID)
        or (type(args) == "table" and type(args.journalUUID) == "string" and args.journalUUID ~= "" and args.journalUUID) or nil
    if not journalUUID then return journalData, false end
    if journalData.entryStoreEnabled == true and BurdJournals.Server.countEntryStoreManifestEntries(journalData) > 0 then
        local expectedStoreCount = BurdJournals.Server.countEntryStoreManifestEntries(journalData)
        local liveEntry = BurdJournals.getOrCreateJournalEntryStoreEntryForData
            and BurdJournals.getOrCreateJournalEntryStoreEntryForData(journalData, false, nil,
                sourceTag or "preferRicherEntryStoreData") or nil
        local liveStoreCount = type(liveEntry) == "table"
            and BurdJournals.Server.countResidentJournalPayloadEntries(liveEntry) or 0
        if liveStoreCount >= expectedStoreCount then
            return journalData, false
        end
        if liveStoreCount > 0 and BurdJournals.Server.readJournalEntryFileBackup
            and BurdJournals.Server.restoreJournalEntryStoreFromPayload
        then
            local recoveryTag = (sourceTag or "preferRicherEntryStoreData") .. "PartialStore"
            local fileData = BurdJournals.Server.readJournalEntryFileBackup(journalUUID, recoveryTag)
            local fileStoreCount = type(fileData) == "table"
                and BurdJournals.Server.countResidentJournalPayloadEntries(fileData) or 0
            if fileStoreCount > liveStoreCount
                and BurdJournals.Server.restoreJournalEntryStoreFromPayload(journalUUID, fileData, recoveryTag)
            then
                local restoredEntry = BurdJournals.getOrCreateJournalEntryStoreEntryForData(
                    journalData, false, nil, recoveryTag .. "Verify")
                local restoredCount = type(restoredEntry) == "table"
                    and BurdJournals.Server.countResidentJournalPayloadEntries(restoredEntry) or 0
                if restoredCount >= expectedStoreCount then
                    bsjWriteLogLine("[BurdJournals][EntryStoreFallback] repaired partial live entry store"
                        .. " uuid=" .. tostring(journalUUID)
                        .. " liveEntries=" .. tostring(liveStoreCount)
                        .. " restoredEntries=" .. tostring(restoredCount)
                        .. " expectedEntries=" .. tostring(expectedStoreCount))
                    return journalData, false
                end
            end
        end
    end
    local storeData = BurdJournals.Server.buildEntryStoreOnlyJournalData
        and BurdJournals.Server.buildEntryStoreOnlyJournalData(journalUUID, sourceTag or "preferRicherEntryStoreData") or nil
    if type(storeData) ~= "table" then return journalData, false end
    local residentCount = BurdJournals.Server.countJournalPayloadEntries(journalData)
    local residentAuthoritativeCount = residentCount
    if journalData.entryStoreEnabled == true then
        residentAuthoritativeCount = math.max(residentAuthoritativeCount, BurdJournals.Server.countEntryStoreManifestEntries(journalData))
    end
    local storeCount = BurdJournals.Server.countEntryStoreManifestEntries(storeData)
    if storeCount <= 0 then storeCount = BurdJournals.Server.countJournalPayloadEntries(storeData) end
    local residentRevision = tonumber(journalData.entryStoreUpdatedAt) or 0
    local storeRevision = tonumber(storeData.entryStoreUpdatedAt) or 0
    if residentRevision > 0 and storeRevision > 0 and storeRevision < residentRevision then
        return journalData, false
    end
    if storeCount <= residentAuthoritativeCount then return journalData, false end
    local preferred = BurdJournals.Server.deepCopy(journalData)
    preferred.uuid, preferred.entryStoreEnabled, preferred.entryStoreUUID = journalUUID, true, journalUUID
    preferred.entryStoreEntryCounts = BurdJournals.Server.deepCopy(storeData.entryStoreEntryCounts or {})
    preferred.entryStoreUpdatedAt = math.max(residentRevision, storeRevision)
    for _, bucketName in ipairs(BurdJournals.ENTRY_STORE_BUCKETS or {"skills", "traits", "stats", "recipes"}) do preferred[bucketName] = {} end
    preserveEntryStoreFallbackPlayerJournalIdentity(preferred, journalData, journalUUID, sourceTag or "preferRicherEntryStoreData")
    bsjWriteLogLine("[BurdJournals][EntryStoreFallback] preferred richer server entry store"
        .. " uuid=" .. tostring(journalUUID) .. " source=" .. tostring(sourceTag or "preferRicherEntryStoreData")
        .. " residentEntries=" .. tostring(residentCount) .. " storeEntries=" .. tostring(storeCount))
    return preferred, true
end

function BurdJournals.Server.preferEntryStoreDataForMissingEntry(journalData, args, bucketName, entryKey, sourceTag)
    if type(journalData) ~= "table" or type(bucketName) ~= "string" or type(entryKey) ~= "string" or entryKey == "" then
        return journalData
    end
    local bucket = journalData[bucketName]
    local resolvedKey = entryKey
    if bucketName == "skills" and type(bucket) == "table" and BurdJournals.resolveSkillKey then
        resolvedKey = BurdJournals.resolveSkillKey(bucket, entryKey) or entryKey
    end
    if type(bucket) == "table" and bucket[resolvedKey] ~= nil then
        return journalData
    end

    local fallbackUUID = type(journalData.entryStoreUUID) == "string" and journalData.entryStoreUUID ~= "" and journalData.entryStoreUUID
        or (type(journalData.uuid) == "string" and journalData.uuid ~= "" and journalData.uuid)
        or (type(journalData.replacedByJournalUUID) == "string" and journalData.replacedByJournalUUID ~= "" and journalData.replacedByJournalUUID)
        or (type(args) == "table" and type(args.journalUUID) == "string" and args.journalUUID ~= "" and args.journalUUID)
        or (type(args) == "table" and type(args.entryStoreUUID) == "string" and args.entryStoreUUID ~= "" and args.entryStoreUUID)
    local function fallbackHasEntry(candidateData)
        local candidateBucket = type(candidateData) == "table" and candidateData[bucketName] or nil
        local candidateKey = entryKey
        if bucketName == "skills" and type(candidateBucket) == "table" and BurdJournals.resolveSkillKey then
            candidateKey = BurdJournals.resolveSkillKey(candidateBucket, entryKey) or entryKey
        end
        return type(candidateBucket) == "table" and candidateBucket[candidateKey] ~= nil
    end

    local fallbackJournalData = fallbackUUID
        and BurdJournals.Server.buildEntryStoreOnlyJournalData
        and BurdJournals.Server.buildEntryStoreOnlyJournalData(fallbackUUID, sourceTag or "missingEntryStoreFallback")
        or nil
    if not fallbackHasEntry(fallbackJournalData)
        and fallbackUUID
        and BurdJournals.Server.readJournalEntryFileBackup
    then
        local fileData = BurdJournals.Server.readJournalEntryFileBackup(fallbackUUID, sourceTag or "missingEntryStoreFallbackFile")
        if fallbackHasEntry(fileData) then
            fallbackJournalData = fileData
        end
    end
    if fallbackHasEntry(fallbackJournalData) then
        fallbackJournalData._entryStoreFallbackSource = tostring(sourceTag or "missingEntryStoreFallback")
        preserveEntryStoreFallbackPlayerJournalIdentity(fallbackJournalData, journalData, fallbackUUID, sourceTag or "missingEntryStoreFallback")
        bsjWriteLogLine("[BurdJournals][EntryStoreFallback] restored missing claim entry"
            .. " uuid=" .. tostring(fallbackUUID)
            .. " bucket=" .. tostring(bucketName)
            .. " key=" .. tostring(entryKey)
            .. " source=" .. tostring(sourceTag or "missingEntryStoreFallback")
            .. " counts=" .. tostring(BurdJournals.Server.countJournalPayloadEntries(fallbackJournalData)))
        return fallbackJournalData
    end
    return journalData
end

local function shouldSkipPlayerJournalRegistryTouchOnInitialServerTouch(sourceTag)
    local tag = tostring(sourceTag or "")
    return tag == "recordProgress"
        or tag == "requestJournalEntryChunk"
        or tag == "sanitizeJournal"
        or tag == "syncJournalData"
        or tag == "eraseEntry"
end

local function shouldSkipEntryStoreHydrationOnServerTouch(sourceTag)
    local tag = tostring(sourceTag or "")
    return tag == "recordProgress"
        or tag == "requestJournalEntryChunk"
        or tag == "sanitizeJournal"
        or tag == "syncJournalData"
end

local function isStrictMPEmptyJournalShellData(journalData)
    return isStrictMPServer()
        and type(journalData) == "table"
        and journalData.entryStoreEnabled ~= true
        and not (journalData.isPlayerCreated == true and journalData.isWritten == false)
        and BurdJournals.Server.countJournalPayloadEntries(journalData) <= 0
end

local function bsjHasAnyTableEntry(tbl)
    if type(tbl) ~= "table" then
        return false
    end
    for _ in pairs(tbl) do
        return true
    end
    return false
end

function BurdJournals.Server.narrowRuntimeDeltaForClaimPayload(runtimeDelta, payload, sourceTag)
    if type(runtimeDelta) ~= "table" or type(payload) ~= "table" then
        return runtimeDelta
    end
    local tag = tostring(sourceTag or "")
    local isClaimResponse = string.find(tag, "claim", 1, true) ~= nil
        or string.find(tag, "Claim", 1, true) ~= nil
        or string.find(tag, "absorb", 1, true) ~= nil
        or string.find(tag, "Absorb", 1, true) ~= nil
        or string.find(tag, "AlreadyKnown", 1, true) ~= nil
        or string.find(tag, "Maxed", 1, true) ~= nil
    if not isClaimResponse then
        return runtimeDelta
    end

    local characterId = runtimeDelta.characterId
    local sourceClaims = nil
    if type(runtimeDelta.claims) == "table" then
        if characterId and type(runtimeDelta.claims[characterId]) == "table" then
            sourceClaims = runtimeDelta.claims[characterId]
        else
            for claimCharacterId, claimData in pairs(runtimeDelta.claims) do
                if type(claimData) == "table" then
                    characterId = claimCharacterId
                    sourceClaims = claimData
                    break
                end
            end
        end
    end

    local narrowedClaim = {}
    local skillName = type(payload.skillName) == "string" and payload.skillName or nil
    local traitId = type(payload.traitId) == "string" and payload.traitId or nil
    local recipeName = type(payload.recipeName) == "string" and payload.recipeName or nil
    local statId = type(payload.statId) == "string" and payload.statId or nil

    if type(sourceClaims) == "table" then
        if skillName and type(sourceClaims.skills) == "table" and sourceClaims.skills[skillName] ~= nil then
            narrowedClaim.skills = {[skillName] = sourceClaims.skills[skillName]}
        end
        if traitId and type(sourceClaims.traits) == "table" and sourceClaims.traits[traitId] ~= nil then
            narrowedClaim.traits = {[traitId] = sourceClaims.traits[traitId]}
        end
        if recipeName and type(sourceClaims.recipes) == "table" and sourceClaims.recipes[recipeName] ~= nil then
            narrowedClaim.recipes = {[recipeName] = sourceClaims.recipes[recipeName]}
        end
        if statId and type(sourceClaims.stats) == "table" and sourceClaims.stats[statId] ~= nil then
            narrowedClaim.stats = {[statId] = sourceClaims.stats[statId]}
        end
        if traitId and type(sourceClaims.forgetSlots) == "table" and sourceClaims.forgetSlots[traitId] ~= nil then
            narrowedClaim.forgetSlots = {[traitId] = sourceClaims.forgetSlots[traitId]}
        end
        if skillName and type(sourceClaims.drSkillReadCounts) == "table" and sourceClaims.drSkillReadCounts[skillName] ~= nil then
            narrowedClaim.drSkillReadCounts = {[skillName] = sourceClaims.drSkillReadCounts[skillName]}
        end
    end

    local narrowedSkillReads = nil
    if skillName and type(runtimeDelta.skillReadCounts) == "table" and runtimeDelta.skillReadCounts[skillName] ~= nil then
        narrowedSkillReads = {[skillName] = runtimeDelta.skillReadCounts[skillName]}
    end

    if not bsjHasAnyTableEntry(narrowedClaim) and not narrowedSkillReads then
        return runtimeDelta
    end

    local narrowed = {
        version = runtimeDelta.version,
        characterId = characterId or runtimeDelta.characterId,
        readCount = runtimeDelta.readCount,
        readSessionCount = runtimeDelta.readSessionCount,
        currentSessionId = runtimeDelta.currentSessionId,
        currentSessionReadCount = runtimeDelta.currentSessionReadCount,
        skillReadCounts = narrowedSkillReads or {},
        drLegacyMode3Migrated = runtimeDelta.drLegacyMode3Migrated == true,
    }
    if characterId and bsjHasAnyTableEntry(narrowedClaim) then
        narrowed.claims = {
            [characterId] = narrowedClaim
        }
    else
        narrowed.claims = {}
    end
    return narrowed
end

local function safeTransmitServerJournalModData(journal, sourceTag)
    if not (journal and journal.transmitModData) then
        return false
    end
    if isStrictMPServer()
        and journal.getModData
        and BurdJournals.offloadJournalEntriesToStoreIfNeeded
    then
        local modData = journal:getModData()
        local journalData = modData and modData.BurdJournals or nil
        local residentEntries = type(journalData) == "table"
            and BurdJournals.countJournalEntryStoreEntries
            and BurdJournals.countJournalEntryStoreEntries(journalData) or 0
        if type(journalData) == "table" and journalData.entryStoreEnabled == true and residentEntries > 0 then
            BurdJournals.offloadJournalEntriesToStoreIfNeeded(
                journal,
                "preTransmit:" .. tostring(sourceTag or "server"),
                true,
                true
            )
        end
    end
    if BurdJournals.shouldTransmitJournalItemModData
        and not BurdJournals.shouldTransmitJournalItemModData(journal, sourceTag or "server")
    then
        return false
    end
    journal:transmitModData()
    return true
end

local function maybeMigrateRuntimeOnTouch(journal, player, sourceTag)
    -- Hover/preview/open requests must observe the identity chosen at spawn;
    -- they must never turn an explicitly sealed journal into a hidden one.
    local presentationOnlyCursedTouch = sourceTag == "requestCursedInsightPreview"
        or sourceTag == "openCursedJournal"
        or sourceTag == "openCursedJournalConfirm"
    if not presentationOnlyCursedTouch
        and BurdJournals.Server
        and BurdJournals.Server.ensureSandboxHiddenCursedBootstrap
    then
        BurdJournals.Server.ensureSandboxHiddenCursedBootstrap(journal, sourceTag)
    end
    if journal and journal.getModData
        and BurdJournals.hydrateJournalDataFromEntryStore
        and not shouldSkipEntryStoreHydrationOnServerTouch(sourceTag)
    then
        local modData = journal:getModData()
        if modData and type(modData.BurdJournals) == "table" then
            BurdJournals.hydrateJournalDataFromEntryStore(modData.BurdJournals, sourceTag or "serverTouch")
        end
    end
    if BurdJournals.migrateJournalRuntimeToGlobalIfNeeded then
        BurdJournals.migrateJournalRuntimeToGlobalIfNeeded(journal, player, sourceTag)
    end
    if BurdJournals.Server
        and BurdJournals.Server.rejectStaleRespawnJournalInstance
        and BurdJournals.Server.rejectStaleRespawnJournalInstance(player, journal, sourceTag)
    then
        return false
    end
    if BurdJournals.Server
        and BurdJournals.Server.touchPlayerJournalRegistry
        and not shouldSkipPlayerJournalRegistryTouchOnInitialServerTouch(sourceTag)
    then
        BurdJournals.Server.touchPlayerJournalRegistry(journal, player, sourceTag)
    end
    return true
end

local function getJournalLightRequirementMessage()
    local tooDarkText = (getText and getText("ContextMenu_TooDark")) or "Too dark to read."
    if tooDarkText == "ContextMenu_TooDark" then
        tooDarkText = "Too dark to read."
    end
    return tooDarkText
end

local function enforceJournalLightRequirement(player, sourceTag)
    if not (BurdJournals.requiresLightForJournalUse and BurdJournals.requiresLightForJournalUse()) then
        return true
    end

    local canUse = true
    local reason = nil
    if BurdJournals.canUseJournalInCurrentLight then
        canUse, reason = BurdJournals.canUseJournalInCurrentLight(player)
    elseif not player or (player.tooDarkToRead and player:tooDarkToRead()) then
        canUse = false
        reason = getJournalLightRequirementMessage()
    end

    if canUse ~= false then
        return true
    end

    BurdJournals.debugPrint("[BurdJournals] " .. tostring(sourceTag or "journalLightRequirement")
        .. ": blocked by RequireLightForJournalUse")
    BurdJournals.Server.sendToClient(player, "error", {
        message = reason or getJournalLightRequirementMessage()
    })
    return false
end

function BurdJournals.Server.validatePlayerJournalMutation(player, journal, options)
    options = type(options) == "table" and options or {}
    if not player or not journal or not journal.getModData then
        return false, "invalidJournal", "Invalid journal."
    end

    local modData = journal:getModData()
    local journalData = modData and modData.BurdJournals or nil
    local isBlank = BurdJournals.isBlankJournal and BurdJournals.isBlankJournal(journal) == true
    local isPlayerJournal = type(journalData) == "table"
        and ((BurdJournals.isEffectivelyPlayerJournal and BurdJournals.isEffectivelyPlayerJournal(journalData) == true)
            or journalData.isPlayerCreated == true)
    local invalidState = (BurdJournals.isClean and BurdJournals.isClean(journal) ~= true)
        or (BurdJournals.isCursedJournalItem and BurdJournals.isCursedJournalItem(journal) == true)
        or (BurdJournals.isHiddenCursedJournal and BurdJournals.isHiddenCursedJournal(journal) == true)
        or (type(journalData) == "table" and (journalData.isCursedJournal == true or journalData.isCursedReward == true))
        or (BurdJournals.isYuletideJournalItem and BurdJournals.isYuletideJournalItem(journal) == true)
    if invalidState then
        return false, "journalNotWritable", "Only clean personal journals can be modified."
    end
    if isBlank then
        if options.allowBlank ~= true then
            return false, "journalNotWritable", "This operation requires a written personal journal."
        end
    elseif not isPlayerJournal then
        return false, "journalNotWritable", "Only personal journals can be modified."
    end

    local hasOwnership = type(journalData) == "table"
        and (journalData.ownerSteamId or journalData.ownerUsername or journalData.ownerCharacterName or journalData.author)
    if (isPlayerJournal or hasOwnership)
        and BurdJournals.isJournalOwner
        and BurdJournals.isJournalOwner(player, journal) ~= true
    then
        return false, "notJournalOwner", "Only the journal owner can modify it."
    end
    return true, nil, nil
end

local function addJournalItemToContainerCompat(container, itemType)
    if not container or type(itemType) ~= "string" or itemType == "" then
        return nil
    end

    local before = {}
    local function getContainerItems()
        return container.getItems and container:getItems() or nil
    end
    local function getItemAt(items, index)
        return items.get and items:get(index) or items[index + 1]
    end
    local function getItemCount(items)
        return items and ((items.size and items:size()) or #items) or 0
    end
    local function itemMatchesType(item)
        if not item then return false end
        local fullType = item.getFullType and item:getFullType() or nil
        if fullType == itemType then return true end
        local bareType = item.getType and item:getType() or nil
        local wantedBare = itemType:match("^[^%.]+%.(.+)$") or itemType
        return bareType == itemType or bareType == wantedBare
    end
    local function rememberCurrentItems()
        local items = getContainerItems()
        for i = 0, getItemCount(items) - 1 do
            local item = getItemAt(items, i)
            if item then before[item] = true end
        end
    end
    local function findVerifiedInsertion(candidate)
        local items = getContainerItems()
        for i = 0, getItemCount(items) - 1 do
            local item = getItemAt(items, i)
            if item and itemMatchesType(item) and (item == candidate or not before[item]) then
                return item
            end
        end
        return nil
    end

    rememberCurrentItems()

    -- B41 can return a detached InventoryItem from an AddItem overload. Every
    -- compatibility attempt is therefore verified against the container before
    -- its result is trusted. If a hook throws after inserting, the same scan
    -- recovers that inserted item and prevents a duplicate retry.
    if container.AddItem then
        local _, candidate = pcall(container.AddItem, container, itemType)
        local inserted = findVerifiedInsertion(candidate)
        if inserted then return inserted end
    end

    local createdItem = nil
    if InventoryItemFactory and InventoryItemFactory.CreateItem then
        local createdOk
        createdOk, createdItem = pcall(InventoryItemFactory.CreateItem, itemType)
        if not createdOk then createdItem = nil end
    end
    if createdItem and container.AddItem then
        local _, candidate = pcall(container.AddItem, container, createdItem)
        local inserted = findVerifiedInsertion(candidate or createdItem)
        if inserted then return inserted end
    end

    if createdItem and container.AddItemBlind then
        local _, candidate = pcall(container.AddItemBlind, container, createdItem)
        local inserted = findVerifiedInsertion(candidate or createdItem)
        if inserted then return inserted end
    end

    if container.AddItems then
        pcall(container.AddItems, container, itemType, 1)
        local inserted = findVerifiedInsertion(nil)
        if inserted then return inserted end
    end

    return nil
end

local function hiddenCursedBootstrapHasMeaningfulData(journalData)
    if type(journalData) ~= "table" then
        return false
    end

    local meaningfulKeys = {
        "uuid",
        "author",
        "profession",
        "professionName",
        "flavorKey",
        "flavorText",
        "loreNoteText",
        "timestamp",
        "cursedEffectType",
    }
    for _, key in ipairs(meaningfulKeys) do
        local value = journalData[key]
        if value ~= nil and value ~= false and tostring(value) ~= "" then
            return true
        end
    end

    if BurdJournals.hasAnyEntries then
        if BurdJournals.hasAnyEntries(journalData.skills)
            or BurdJournals.hasAnyEntries(journalData.traits)
            or BurdJournals.hasAnyEntries(journalData.recipes)
            or BurdJournals.hasAnyEntries(journalData.stats)
            or BurdJournals.hasAnyEntries(journalData.cursedPendingRewards)
        then
            return true
        end
    end

    return journalData.forgetSlot == true
end

local function isRawCursedShellDataForHiddenBootstrap(journalData)
    if type(journalData) ~= "table" then
        return true
    end
    if journalData.isCursedReward == true or journalData.isHiddenCursedJournal == true then
        return false
    end
    if (journalData.isDebugSpawned == true or journalData.debugBackupEnabled == true)
        and (journalData.isCursedJournal == true or journalData.cursedState == "dormant")
    then
        return false
    end
    if journalData.cursedEffectType ~= nil or journalData.cursedForcedEffectType ~= nil then
        return false
    end
    if journalData.author ~= nil
        or journalData.profession ~= nil
        or journalData.professionName ~= nil
        or journalData.flavorKey ~= nil
        or journalData.flavorText ~= nil
        or journalData.loreNoteText ~= nil
    then
        return false
    end
    if BurdJournals.hasAnyEntries then
        if BurdJournals.hasAnyEntries(journalData.skills)
            or BurdJournals.hasAnyEntries(journalData.traits)
            or BurdJournals.hasAnyEntries(journalData.recipes)
            or BurdJournals.hasAnyEntries(journalData.stats)
            or BurdJournals.hasAnyEntries(journalData.cursedPendingRewards)
        then
            return false
        end
    end

    return journalData.forgetSlot ~= true
end

function BurdJournals.Server.isPlaceholderHiddenCursedAuthor(author)
    local normalizedAuthor = tostring(author or "")
    local unknownAuthorText = getText and getText("UI_BurdJournals_UnknownSurvivor") or "UI_BurdJournals_UnknownSurvivor"
    return normalizedAuthor == ""
        or normalizedAuthor == unknownAuthorText
        or normalizedAuthor == "Unknown Survivor"
end

function BurdJournals.Server.isPlaceholderHiddenCursedProfession(professionId, professionName)
    local normalizedProfession = tostring(professionId or "")
    local normalizedProfessionName = tostring(professionName or "")
    local unknownProfessionText = getText and getText("UI_BurdJournals_UnknownProfession") or "UI_BurdJournals_UnknownProfession"
    return normalizedProfessionName == ""
        or normalizedProfessionName == unknownProfessionText
        or normalizedProfessionName == "Unknown Profession"
        or (string.lower(normalizedProfession) == "survivor" and normalizedProfessionName == "Survivor")
end

function BurdJournals.Server.syncHiddenCursedPendingLoreIdentity(data)
    if type(data) ~= "table" or type(data.cursedPendingRewards) ~= "table" then
        return false
    end

    local pending = data.cursedPendingRewards
    local changed = false
    local rootAuthor = tostring(data.author or "")
    local rootProfession = tostring(data.profession or "")
    local rootProfessionName = tostring(data.professionName or "")

    if rootAuthor ~= ""
        and not BurdJournals.Server.isPlaceholderHiddenCursedAuthor(rootAuthor)
        and pending.author ~= rootAuthor
    then
        pending.author = rootAuthor
        changed = true
    end

    if not BurdJournals.Server.isPlaceholderHiddenCursedProfession(rootProfession, rootProfessionName) then
        if rootProfession ~= "" and pending.profession ~= rootProfession then
            pending.profession = rootProfession
            changed = true
        end
        if rootProfessionName ~= "" and pending.professionName ~= rootProfessionName then
            pending.professionName = rootProfessionName
            changed = true
        end
    end

    for _, key in ipairs({
        "flavorKey",
        "loreNoteText",
        "loreNoteTemplateVersion",
        "loreNoteTemplateFamily",
    }) do
        if data[key] ~= nil and pending[key] ~= data[key] then
            pending[key] = data[key]
            changed = true
        end
    end

    return changed
end

function BurdJournals.Server.ensureSandboxHiddenCursedBootstrap(journal, sourceTag, forceRawDisguise)
    if not (journal and journal.getModData and journal.getFullType) then
        return false
    end
    if not (BurdJournals.isDisguiseCursedJournalsAsBloodyEnabled and BurdJournals.isDisguiseCursedJournalsAsBloodyEnabled()) then
        return false
    end

    local cursedType = BurdJournals.CURSED_ITEM_TYPE or "BurdJournals.CursedJournal"
    local fullType = tostring(journal:getFullType() or "")
    if fullType ~= cursedType then
        return false
    end

    local modData = journal:getModData()
    modData.BurdJournals = modData.BurdJournals or {}
    local data = modData.BurdJournals

    local forceShellDisguise = forceRawDisguise == true and isRawCursedShellDataForHiddenBootstrap(data)

    if data.isCursedReward == true then
        return false
    end
    if (data.isCursedJournal == true or data.isHiddenCursedJournal == true) and not forceShellDisguise then
        return false
    end
    if hiddenCursedBootstrapHasMeaningfulData(data) and not forceShellDisguise then
        return false
    end

    local professionId, professionName, flavorKey
    if BurdJournals.getRandomProfession then
        professionId, professionName, flavorKey = BurdJournals.getRandomProfession()
    else
        professionId, professionName, flavorKey = "survivor", "Survivor", "UI_BurdJournals_BloodyFlavor"
    end
    local disguisedSeed = {
        uuid = data.uuid
            or ((BurdJournals.resolveJournalUUIDForRuntime and BurdJournals.resolveJournalUUIDForRuntime(data, journal, true))
                or (BurdJournals.generateUUID and BurdJournals.generateUUID())
                or ("cursed-" .. tostring(ZombRand(999999999)))),
        timestamp = tonumber(data.timestamp)
            or (getGameTime and getGameTime() and getGameTime():getWorldAgeHours())
            or 0,
        author = data.author
            or ((BurdJournals.generateRandomSurvivorName and BurdJournals.generateRandomSurvivorName()) or "Unknown Survivor"),
        profession = data.profession or professionId,
        professionName = data.professionName or professionName,
        flavorKey = data.flavorKey or flavorKey or "UI_BurdJournals_BloodyFlavor",
        lootNotesEligible = data.lootNotesEligible == true,
    }
    data.cursedPendingRewards = data.cursedPendingRewards or {
        uuid = disguisedSeed.uuid,
        timestamp = disguisedSeed.timestamp,
        author = disguisedSeed.author,
        profession = disguisedSeed.profession,
        professionName = disguisedSeed.professionName,
        flavorKey = disguisedSeed.flavorKey,
        lootNotesEligible = data.lootNotesEligible == true,
        cursedDeferredRewards = true,
    }

    data.uuid = data.uuid or disguisedSeed.uuid
    data.timestamp = tonumber(data.timestamp) or disguisedSeed.timestamp
    data.author = data.author or disguisedSeed.author
    data.profession = data.profession or disguisedSeed.profession
    data.professionName = data.professionName or disguisedSeed.professionName
    data.flavorKey = data.flavorKey or disguisedSeed.flavorKey
    local insightEffectType = type(data.cursedInsightEffectType) == "string" and data.cursedInsightEffectType ~= "" and data.cursedInsightEffectType
        or (BurdJournals.Server.rollCursedInsightEffectType and BurdJournals.Server.rollCursedInsightEffectType(nil, nil))
        or nil
    if insightEffectType then
        data.cursedInsightEffectType = insightEffectType
        if BurdJournals.Server.getCurseEffectOmenCategory then
            data.cursedOmenCategory = BurdJournals.Server.getCurseEffectOmenCategory(insightEffectType)
        end
    end
    data.isHiddenCursedJournal = true
    data.isCursedJournal = false
    data.cursedState = "hidden"
    -- Expired curses: record spawn time so old curses can go dormant.
    data.cursedSpawnedAtHours = data.cursedSpawnedAtHours
        or (BurdJournals.Server.getWorldAgeHoursSafe and BurdJournals.Server.getWorldAgeHoursSafe())
        or nil
    data.isCursedReward = false
    data.cursedEffectType = nil
    data.cursedUnleashedByCharacterId = nil
    data.cursedUnleashedByUsername = nil
    data.cursedUnleashedAtHours = nil
    data.cursedSealSoundEvent = nil
    data.cursedForcedEffectType = nil
    data.cursedForcedTraitId = nil
    data.cursedForcedSkillName = nil
    data.isBloody = true
    data.isWorn = false
    data.wasFromBloody = true
    data.hasBloodyOrigin = true
    data.isPlayerCreated = false
    data.isZombieJournal = true
    data.loreNoteTemplateVersion = tonumber(BurdJournals.Server and BurdJournals.Server.LORE_NOTE_TEMPLATE_VERSION) or 1
    data.loreNoteTemplateFamily = "bloody"
    data.loreNoteText = nil
    data.claims = data.claims or {}
    data.claimedSkills = data.claimedSkills or {}
    data.claimedTraits = data.claimedTraits or {}
    data.claimedRecipes = data.claimedRecipes or {}
    data.claimedForgetSlot = data.claimedForgetSlot or {}

    if BurdJournals.updateJournalName then
        BurdJournals.updateJournalName(journal, true)
    end
    if BurdJournals.updateJournalIcon then
        BurdJournals.updateJournalIcon(journal)
    end
    if journal.transmitModData and not BurdJournals.Server.shouldDeferBatchTransmit() then
        safeTransmitServerJournalModData(journal, "hiddenCursedBootstrap")
    end
    BurdJournals.debugPrint("[BurdJournals] " .. tostring(sourceTag or "hiddenCursedBootstrap")
        .. ": bootstrapped raw cursed item into hidden bloody disguise")
    return true
end

function BurdJournals.Server.materializeSandboxHiddenCursedBloodyItemIfNeeded(player, journal, sourceTag)
    if not (journal and journal.getFullType and journal.getModData) then
        return journal, false
    end
    if not (BurdJournals.isDisguiseCursedJournalsAsBloodyEnabled and BurdJournals.isDisguiseCursedJournalsAsBloodyEnabled()) then
        return journal, false
    end

    local cursedType = BurdJournals.CURSED_ITEM_TYPE or "BurdJournals.CursedJournal"
    local fullType = tostring(journal:getFullType() or "")
    if fullType ~= cursedType then
        return journal, false
    end

    if BurdJournals.Server.ensureSandboxHiddenCursedBootstrap then
        BurdJournals.Server.ensureSandboxHiddenCursedBootstrap(journal, sourceTag or "hiddenCursedMaterialize", true)
    end

    local sourceModData = journal:getModData()
    local sourceData = sourceModData and sourceModData.BurdJournals or nil
    if type(sourceData) ~= "table"
        or sourceData.isHiddenCursedJournal ~= true
        or sourceData.isCursedReward == true
    then
        return journal, false
    end

    local sourceContainer = journal.getContainer and journal:getContainer() or nil
    local inventory = player and player.getInventory and player:getInventory() or nil
    -- Defer materialization while the journal sits inside a bag / nested container.
    -- The remove+add item swap below, run against a nested ItemContainer, corrupts
    -- the client container UI (the inventory renders as an empty black box and the
    -- bag desyncs). The hidden state stays valid and claims remain blocked, so this
    -- simply retries on the next server touch once the item is moved or opened.
    if sourceContainer and sourceContainer ~= inventory and sourceContainer.getContainingItem then
        if sourceContainer:getContainingItem() ~= nil then
            BurdJournals.debugPrint("[BurdJournals] Deferring hidden cursed materialization: journal is in a nested container ("
                .. tostring(sourceTag) .. ")")
            return journal, false
        end
    end
    local targetContainer = sourceContainer or inventory
    if not (targetContainer and targetContainer.AddItem) then
        return journal, false
    end

    local oldJournalId = journal.getID and journal:getID() or nil
    local oldJournalUUID = sourceData.uuid
    local replacement = addJournalItemToContainerCompat(targetContainer, "BurdJournals.FilledSurvivalJournal_Bloody")
    if not replacement and inventory and inventory ~= targetContainer then
        replacement = addJournalItemToContainerCompat(inventory, "BurdJournals.FilledSurvivalJournal_Bloody")
        if replacement then
            targetContainer = inventory
        end
    end
    if not replacement then
        return journal, false
    end

    local copiedData = BurdJournals.Server.deepCopy and BurdJournals.Server.deepCopy(sourceData) or sourceData
    if BurdJournals.normalizeJournalData then
        copiedData = BurdJournals.normalizeJournalData(copiedData)
    end
    copiedData.isHiddenCursedJournal = true
    copiedData.isCursedJournal = false
    copiedData.isCursedReward = false
    copiedData.cursedState = "hidden"
    -- Expired curses: record spawn time so old curses can go dormant.
    copiedData.cursedSpawnedAtHours = copiedData.cursedSpawnedAtHours
        or (BurdJournals.Server.getWorldAgeHoursSafe and BurdJournals.Server.getWorldAgeHoursSafe())
        or nil
    copiedData.isBloody = true
    copiedData.wasFromBloody = true
    copiedData.hasBloodyOrigin = true
    copiedData.isPlayerCreated = false
    copiedData.isZombieJournal = true

    local replacementModData = replacement:getModData()
    replacementModData.BurdJournals = copiedData

    if player then
        BurdJournals.safePcall(function()
            if player.getPrimaryHandItem and player:getPrimaryHandItem() == journal then
                player:setPrimaryHandItem(nil)
            end
            if player.getSecondaryHandItem and player:getSecondaryHandItem() == journal then
                player:setSecondaryHandItem(nil)
            end
        end)
    end

    if sourceContainer and sourceContainer.Remove then
        sourceContainer:Remove(journal)
        if sourceContainer.setDrawDirty then
            sourceContainer:setDrawDirty(true)
        end
        if sendRemoveItemFromContainer then
            sendRemoveItemFromContainer(sourceContainer, journal)
        end
    elseif inventory and inventory.Remove and inventory.contains and inventory:contains(journal) then
        inventory:Remove(journal)
        if inventory.setDrawDirty then
            inventory:setDrawDirty(true)
        end
        if sendRemoveItemFromContainer then
            sendRemoveItemFromContainer(inventory, journal)
        end
    end

    if BurdJournals.updateJournalName then
        BurdJournals.updateJournalName(replacement, true)
    end
    if BurdJournals.updateJournalIcon then
        BurdJournals.updateJournalIcon(replacement)
    end
    if replacement.transmitModData then
        safeTransmitServerJournalModData(replacement, "hiddenCursedMaterialize")
    end
    if targetContainer and targetContainer.setDrawDirty then
        targetContainer:setDrawDirty(true)
    end
    if sendAddItemToContainer and targetContainer then
        sendAddItemToContainer(targetContainer, replacement)
    end
    if player and player.syncInventory then
        BurdJournals.safePcall(function()
            player:syncInventory()
        end)
    end
    if BurdJournals.Server.updateJournalUUIDIndex then
        BurdJournals.Server.updateJournalUUIDIndex(replacement, player, "hiddenCursedMaterialize")
    end

    BurdJournals.debugPrint("[BurdJournals] " .. tostring(sourceTag or "hiddenCursedMaterialize")
        .. ": materialized raw cursed item " .. tostring(oldJournalId)
        .. " as disguised bloody journal " .. tostring(replacement.getID and replacement:getID() or nil))

    return replacement, true, oldJournalId, oldJournalUUID, copiedData
end

local function normalizeCursedJournalStateForType(journal, sourceTag)
    if not (journal and journal.getModData and journal.getFullType) then
        return false
    end

    local fullType = tostring(journal:getFullType() or "")
    local cursedType = BurdJournals.CURSED_ITEM_TYPE or "BurdJournals.CursedJournal"
    if fullType ~= cursedType then
        return false
    end

    local modData = journal:getModData()
    modData.BurdJournals = modData.BurdJournals or {}
    local journalData = modData.BurdJournals
    local repaired = false

    if BurdJournals.isDisguiseCursedJournalsAsBloodyEnabled
        and BurdJournals.isDisguiseCursedJournalsAsBloodyEnabled()
        and journalData.isHiddenCursedJournal == true
        and journalData.isCursedReward ~= true
    then
        if journalData.isCursedJournal == true then
            journalData.isCursedJournal = false
            repaired = true
        end
        if journalData.cursedState ~= "hidden" then
            journalData.cursedState = "hidden"
            repaired = true
        end
        if journalData.isBloody ~= true then
            journalData.isBloody = true
            repaired = true
        end
        if journalData.wasFromBloody ~= true then
            journalData.wasFromBloody = true
            repaired = true
        end
        if journalData.hasBloodyOrigin ~= true then
            journalData.hasBloodyOrigin = true
            repaired = true
        end

        if repaired then
            if BurdJournals.updateJournalName then
                BurdJournals.updateJournalName(journal, true)
            end
            if BurdJournals.updateJournalIcon then
                BurdJournals.updateJournalIcon(journal)
            end
            if journal.transmitModData and not BurdJournals.Server.shouldDeferBatchTransmit() then
                safeTransmitServerJournalModData(journal, "normalizeCursedJournalStateForType")
            end
        end
        return repaired
    end

    if journalData.isHiddenCursedJournal == true then
        journalData.isHiddenCursedJournal = false
        repaired = true
    end

    if journalData.isCursedReward == true then
        if journalData.isCursedJournal == true then
            journalData.isCursedJournal = false
            repaired = true
        end
        if journalData.cursedState ~= "unleashed" then
            journalData.cursedState = "unleashed"
            repaired = true
        end
    else
        if journalData.isCursedJournal ~= true then
            journalData.isCursedJournal = true
            repaired = true
        end
        if journalData.cursedState ~= "dormant" then
            journalData.cursedState = "dormant"
            repaired = true
        end
        if journalData.isBloody == true then
            journalData.isBloody = false
            repaired = true
        end
        if journalData.wasFromBloody == true then
            journalData.wasFromBloody = false
            repaired = true
        end
        if journalData.hasBloodyOrigin == true then
            journalData.hasBloodyOrigin = false
            repaired = true
        end
    end

    if not repaired then
        return false
    end

    if BurdJournals.updateJournalName then
        BurdJournals.updateJournalName(journal, true)
    end
    if BurdJournals.updateJournalIcon then
        BurdJournals.updateJournalIcon(journal)
    end
    if journal.transmitModData and not BurdJournals.Server.shouldDeferBatchTransmit() then
        safeTransmitServerJournalModData(journal, "normalizeCursedJournalStateForType")
    end
    BurdJournals.debugPrint("[BurdJournals] " .. tostring(sourceTag or "cursedNormalize")
        .. ": normalized cursed journal state for item type")
    return true
end

local function isHiddenCursedJournalState(journal, journalData)
    if not journal or type(journalData) ~= "table" then
        return false
    end
    if journalData.isHiddenCursedJournal ~= true or journalData.isCursedReward == true then
        return false
    end

    local fullType = journal.getFullType and journal:getFullType() or ""
    return fullType == "BurdJournals.FilledSurvivalJournal_Bloody"
        or journalData.isBloody == true
        or journalData.wasFromBloody == true
        or journalData.hasBloodyOrigin == true
end

local function fullTypeHasToken(fullType, token)
    return type(fullType) == "string"
        and type(token) == "string"
        and token ~= ""
        and string.find(fullType, token, 1, true) ~= nil
end

local function isLikelyWornType(fullType)
    return fullTypeHasToken(fullType, "_Worn")
        or fullTypeHasToken(fullType, ".Worn")
        or fullTypeHasToken(fullType, "WornSurvivalJournal")
end

local function isLikelyBloodyType(fullType)
    return fullTypeHasToken(fullType, "_Bloody")
        or fullTypeHasToken(fullType, ".Bloody")
        or fullTypeHasToken(fullType, "BloodySurvivalJournal")
end

local function normalizeFoundJournalClaimFlags(journal, journalData, sourceTag)
    if not journal or type(journalData) ~= "table" then
        return false
    end

    normalizeCursedJournalStateForType(journal, sourceTag)

    local fullType = journal.getFullType and tostring(journal:getFullType() or "") or ""
    local isWornType = (BurdJournals.isWorn and BurdJournals.isWorn(journal)) or isLikelyWornType(fullType)
    local isBloodyType = (BurdJournals.isBloody and BurdJournals.isBloody(journal)) or isLikelyBloodyType(fullType)
    local isYuletideType = fullType == (BurdJournals.YULETIDE_ITEM_TYPE or "BurdJournals.YuletideJournal")
    local repaired = false

    if isWornType and journalData.isWorn ~= true then
        journalData.isWorn = true
        journalData.wasFromWorn = true
        repaired = true
    end
    if isBloodyType and journalData.isBloody ~= true then
        journalData.isBloody = true
        journalData.wasFromBloody = true
        repaired = true
    end
    local explicitPersonalOrigin = tostring(journalData.originMode or journalData.sourceType or "") == "personal"
    if (isWornType or isBloodyType or isYuletideType or journalData.isYuletideJournal == true)
        and ((BurdJournals.isEffectivelyPlayerJournal and BurdJournals.isEffectivelyPlayerJournal(journalData))
            or journalData.isPlayerCreated == true)
        and not explicitPersonalOrigin
    then
        journalData.isPlayerCreated = false
        repaired = true
        BurdJournals.debugPrint("[BurdJournals] " .. tostring(sourceTag or "claimNormalize")
            .. ": repaired misclassified found journal (forced isPlayerCreated=false)")
    end

    if repaired and journal.transmitModData then
        safeTransmitServerJournalModData(journal, "normalizeFoundJournalClaimFlags")
    end
    return repaired
end

local function attachRuntimeDeltaOrLegacyJournalData(payload, journalData, player, sourceTag)
    payload = payload or {}
    payload.serverRuntimeMarker = payload.serverRuntimeMarker or BurdJournals.RUNTIME_LOAD_MARKER
    if type(journalData) ~= "table" then
        payload.needsSync = true
        return payload
    end

    local canonicalUUID = BurdJournals.getJournalIdentityUUID(journalData)
    if canonicalUUID then
        payload.journalUUID = canonicalUUID
    end

    if isStrictMPEmptyJournalShellData(journalData) then
        payload.needsSync = true
        payload.fullJournalDataOmitted = true
        payload.fullJournalDataOmittedReason = "emptyShell"
        payload.entryStoreUnavailable = true
        BurdJournals.debugPrint("[BurdJournals] " .. tostring(sourceTag or "runtimeResponse")
            .. ": refused empty strict-MP journal shell in response payload")
        return payload
    end

    if not isStrictMPServer() then
        payload.journalData = journalData
        return payload
    end

    -- Strict-MP entry-store journals only keep a compact shell on the item.
    -- Every response path using this helper (notably sanitizeJournal and batch
    -- claim/absorb) must advertise that omission so the client hydrates the
    -- authoritative entry store instead of refreshing the UI from that shell.
    if journalData.entryStoreEnabled == true then
        local expectedEntryStoreCount = BurdJournals.Server.countEntryStoreManifestEntries(journalData)
        local actualEntryStoreCount = nil
        if BurdJournals.refreshJournalEntryStoreCounts then
        -- Capture only the first return value. Calling tonumber() with this
        -- multi-return function directly also passes the counts table as the
        -- radix argument under Kahlua, crashing the success-response path.
        local refreshedEntryStoreCount = BurdJournals.refreshJournalEntryStoreCounts(
            journalData, tostring(sourceTag or "runtimeResponse") .. "Counts")
        actualEntryStoreCount = tonumber(refreshedEntryStoreCount) or 0
        end
        payload.entryStoreEnabled = true
        payload.entryStoreEntryCounts = type(journalData.entryStoreEntryCounts) == "table"
            and BurdJournals.Server.deepCopy(journalData.entryStoreEntryCounts) or nil
        payload.entryStoreUpdatedAt = tonumber(journalData.entryStoreUpdatedAt)
        payload.entryStoreActualCount = actualEntryStoreCount
        payload.fullJournalDataOmitted = true
        payload.fullJournalDataOmittedReason = "entryStore"
        payload.entryStoreUnavailable = expectedEntryStoreCount > 0
            and actualEntryStoreCount ~= nil and actualEntryStoreCount <= 0 or false
    end

    local runtimeDelta = BurdJournals.buildRuntimeDeltaForPlayer and BurdJournals.buildRuntimeDeltaForPlayer(journalData, player) or nil
    if type(runtimeDelta) == "table" then
        runtimeDelta = BurdJournals.Server.narrowRuntimeDeltaForClaimPayload
            and BurdJournals.Server.narrowRuntimeDeltaForClaimPayload(runtimeDelta, payload, sourceTag)
            or runtimeDelta
        payload.runtimeDelta = runtimeDelta
    end

    local softLimit = math.max(1024, tonumber(BurdJournals.FULL_SYNC_SOFT_LIMIT_BYTES) or 48000)
    local estimate = estimatePayloadBytes(payload)
    if estimate > softLimit then
        payload.runtimeDelta = nil
        payload.needsSync = true
        BurdJournals.debugPrint("[BurdJournals] " .. tostring(sourceTag or "runtimeResponse")
            .. ": payload soft-limit exceeded (" .. tostring(estimate) .. " > " .. tostring(softLimit) .. "), forcing needsSync")
    end
    return payload
end

local function buildBatchJournalResponse(payload, player, journalId, journalUUID, journalData, sourceTag)
    local response = attachRuntimeDeltaOrLegacyJournalData(payload or {}, journalData, player, sourceTag)
    if journalId ~= nil then
        response.journalId = journalId
    end
    if journalUUID and response.journalUUID == nil then
        response.journalUUID = journalUUID
    end
    return response
end

local function normalizeCommandJournalUUID(args)
    if type(args) ~= "table" then
        return nil
    end

    local uuid = args.journalUUID or args.entryStoreUUID
    if (uuid == nil or uuid == "") and type(args.journalData) == "table" then
        uuid = args.journalData.uuid or args.journalData.entryStoreUUID
    end
    if uuid == nil or uuid == "" then
        uuid = args.journalKey
    end
    if uuid == nil then
        return nil
    end

    uuid = tostring(uuid)
    if string.len(uuid) > 128 or string.find(uuid, "[%z\1-\31\127]") then return nil end
    uuid = uuid:gsub("^%s+", ""):gsub("%s+$", "")
    if uuid == "" or uuid == "nil" or string.len(uuid) > 128 then return nil end
    return uuid
end

local function normalizeCommandJournalFingerprint(args)
    if type(args) ~= "table" then
        return nil
    end

    local fingerprint = args.journalFingerprint
    if fingerprint == nil or fingerprint == "" then
        fingerprint = args.journalLookupFingerprint
    end
    if fingerprint == nil then
        return nil
    end

    fingerprint = tostring(fingerprint)
    if string.len(fingerprint) > 4096 or string.find(fingerprint, "[%z\1-\31\127]") then return nil end
    fingerprint = fingerprint:gsub("^%s+", ""):gsub("%s+$", "")
    if fingerprint == "" or fingerprint == "nil" or string.len(fingerprint) > 4096 then return nil end
    return fingerprint
end

local function hasAnyJournalLookupArgs(args)
    if type(args) ~= "table" then
        return false
    end
    return args.journalId ~= nil
        or normalizeCommandJournalUUID(args) ~= nil
        or normalizeCommandJournalFingerprint(args) ~= nil
end

local function resolveCommandJournalUUIDFromIndex(player, args)
    if type(args) ~= "table" or args.journalId == nil then
        return nil
    end
    if type(ModData) ~= "table" then
        return nil
    end
    if not (BurdJournals.Server and BurdJournals.Server.getJournalUUIDIndex) then
        return nil
    end
    local wantedId = tostring(args.journalId)
    local indexCache = BurdJournals.Server.getJournalUUIDIndex()
    local journals = indexCache and indexCache.journals or nil
    if type(journals) ~= "table" then
        return nil
    end
    local requestedType = type(args.itemFullType) == "string" and args.itemFullType ~= "" and args.itemFullType or nil
    local playerSteamId = player and BurdJournals.getPlayerSteamId
        and BurdJournals.Server.normalizeRespawnIdentityValue(BurdJournals.getPlayerSteamId(player)) or nil
    local ownedMatches, fallbackMatches = {}, {}
    for uuid, entry in pairs(journals) do
        if type(entry) == "table" and entry.itemId ~= nil and tostring(entry.itemId) == wantedId
            and (not requestedType or tostring(entry.itemType or "") == requestedType) then
            local entryOwner = BurdJournals.Server.normalizeRespawnIdentityValue(entry.ownerSteamId)
            local normalizedUUID = trimUUID(uuid)
            if normalizedUUID then
                if playerSteamId and entryOwner == playerSteamId then
                    ownedMatches[#ownedMatches + 1] = normalizedUUID
                elseif not playerSteamId or not entryOwner then
                    fallbackMatches[#fallbackMatches + 1] = normalizedUUID
                end
            end
        end
    end
    local matches = #ownedMatches > 0 and ownedMatches or fallbackMatches
    if #matches == 1 then return matches[1] end
    if #matches > 1 then
        BurdJournals.debugPrint("[BurdJournals] UUID index lookup rejected ambiguous itemId="
            .. tostring(wantedId) .. " matches=" .. tostring(#matches))
    end
    return nil
end

local function getJournalFingerprintToken(fingerprint, token)
    if type(fingerprint) ~= "string" or fingerprint == "" or type(token) ~= "string" or token == "" then
        return nil
    end
    local value = fingerprint:match(token .. "=([^|]+)")
    if value == nil or value == "" then
        return nil
    end
    return value
end

local function getItemFullTypeEarly(item)
    if not (item and item.getFullType) then return nil end
    local fullType = item:getFullType()
    if fullType == nil then return nil end
    return tostring(fullType)
end

local function journalDataNeedsServerBootstrap(journalData)
    if type(journalData) ~= "table" then
        return true
    end
    if not (BurdJournals.getJournalIdentityUUID and BurdJournals.getJournalIdentityUUID(journalData)) then
        return true
    end
    return false
end

local function collectBootstrapJournalCandidatesFromContainer(container, fullType, conditionValue, outCandidates)
    if not container or not container.getItems or type(fullType) ~= "string" or fullType == "" then
        return
    end

    local items = container:getItems()
    if not items then
        return
    end

    for i = 0, items:size() - 1 do
        local item = items:get(i)
        if item then
            if getItemFullTypeEarly(item) == fullType then
                if conditionValue == nil or tonumber(item.getCondition and item:getCondition() or nil) == conditionValue then
                    table.insert(outCandidates, item)
                end
            end
            local subInventory = item.getInventory and item:getInventory() or nil
            if not subInventory and item.getItemContainer then
                subInventory = item:getItemContainer()
            end
            if subInventory and subInventory ~= container then
                collectBootstrapJournalCandidatesFromContainer(subInventory, fullType, conditionValue, outCandidates)
            end
        end
    end
end

local function collectBootstrapJournalCandidatesNearPlayer(player, fullType, conditionValue, outCandidates)
    if not player or type(fullType) ~= "string" or fullType == "" then
        return
    end

    local inventory = player.getInventory and player:getInventory() or nil
    if inventory then
        collectBootstrapJournalCandidatesFromContainer(inventory, fullType, conditionValue, outCandidates)
    end

    local square = player.getCurrentSquare and player:getCurrentSquare() or nil
    if not square then
        return
    end

    for dx = -1, 1 do
        for dy = -1, 1 do
            local nearSquare = getCell():getGridSquare(square:getX() + dx, square:getY() + dy, square:getZ())
            if nearSquare then
                local objects = nearSquare:getObjects()
                if objects then
                    for i = 0, objects:size() - 1 do
                        local obj = objects:get(i)
                        if obj and obj.getItem then
                            local worldItem = obj:getItem()
                            if worldItem and getItemFullTypeEarly(worldItem) == fullType then
                                if conditionValue == nil or tonumber(worldItem.getCondition and worldItem:getCondition() or nil) == conditionValue then
                                    table.insert(outCandidates, worldItem)
                                end
                            end
                        end
                        if obj and obj.getContainer then
                            local container = obj:getContainer()
                            if container then
                                collectBootstrapJournalCandidatesFromContainer(container, fullType, conditionValue, outCandidates)
                            end
                        end
                        if obj and obj.getInventory then
                            local objectInventory = obj:getInventory()
                            if objectInventory then
                                collectBootstrapJournalCandidatesFromContainer(objectInventory, fullType, conditionValue, outCandidates)
                            end
                        end
                    end
                end
            end
        end
    end
end

function BurdJournals.Server.collectBootstrapJournalCandidatesForResolution(player, fullType, conditionValue, outCandidates, includeNearby)
    if includeNearby then
        collectBootstrapJournalCandidatesNearPlayer(player, fullType, conditionValue, outCandidates)
        return
    end
    local inventory = player and player.getInventory and player:getInventory() or nil
    if inventory then
        collectBootstrapJournalCandidatesFromContainer(inventory, fullType, conditionValue, outCandidates)
    end
end

local function findBootstrapJournalCandidate(player, journalFingerprint, includeNearby)
    local fullType = getJournalFingerprintToken(journalFingerprint, "ft")
    if not player or not fullType then
        return nil
    end

    local conditionValue = tonumber(getJournalFingerprintToken(journalFingerprint, "condition"))
    local candidates = {}
    BurdJournals.Server.collectBootstrapJournalCandidatesForResolution(player, fullType, conditionValue, candidates, includeNearby)
    if #candidates == 0 and conditionValue ~= nil then
        BurdJournals.Server.collectBootstrapJournalCandidatesForResolution(player, fullType, nil, candidates, includeNearby)
    end
    if #candidates == 0 then
        return nil
    end

    local bootstrapCandidates = {}
    for _, candidate in ipairs(candidates) do
        local modData = candidate and candidate.getModData and candidate:getModData() or nil
        local journalData = modData and modData.BurdJournals or nil
        if journalDataNeedsServerBootstrap(journalData) then
            table.insert(bootstrapCandidates, candidate)
        end
    end

    if #bootstrapCandidates == 1 then
        return bootstrapCandidates[1]
    end
    if #candidates == 1 then
        return candidates[1]
    end
    return nil
end

local function findBootstrapJournalCandidateFromArgs(player, args, includeNearby)
    local journalFingerprint = normalizeCommandJournalFingerprint(args)
    local candidate = journalFingerprint and findBootstrapJournalCandidate(player, journalFingerprint, includeNearby) or nil
    if candidate then
        return candidate, "bootstrapByFingerprintType"
    end

    local fullType = type(args) == "table" and args.itemFullType or nil
    fullType = type(fullType) == "string" and fullType:gsub("^%s+", ""):gsub("%s+$", "") or nil
    if not fullType or fullType == "" or not string.find(fullType, "^BurdJournals%.") then
        return nil, nil
    end

    local conditionValue = tonumber(journalFingerprint and getJournalFingerprintToken(journalFingerprint, "condition") or nil)
    local candidates = {}
    BurdJournals.Server.collectBootstrapJournalCandidatesForResolution(player, fullType, conditionValue, candidates, includeNearby)
    if #candidates == 0 and conditionValue ~= nil then
        BurdJournals.Server.collectBootstrapJournalCandidatesForResolution(player, fullType, nil, candidates, includeNearby)
    end

    if #candidates == 1 then
        return candidates[1], "bootstrapByItemType"
    end
    return nil, nil
end

-- Recovery data must be derived from a server-owned registry/entry-store record.
-- Command journalData is presentation data from an untrusted client and must never
-- be allowed to create or overwrite reward-bearing state.
function BurdJournals.Server.getServerOwnedJournalRecoveryData(player, journalUUID, sourceTag)
    if not (player and type(journalUUID) == "string" and journalUUID ~= "") then return nil end
    local registryEntry = BurdJournals.Server.getPlayerJournalRegistryEntryByUUID
        and BurdJournals.Server.getPlayerJournalRegistryEntryByUUID(journalUUID) or nil
    if type(registryEntry) ~= "table" then return nil end
    local registryData = type(registryEntry.journalData) == "table" and registryEntry.journalData or registryEntry
    local ownerSteamId = tostring(registryEntry.ownerSteamId or registryData.ownerSteamId or "")
    local ownerUsername = tostring(registryEntry.ownerUsername or registryData.ownerUsername or "")
    local playerSteamId = BurdJournals.getPlayerSteamId and tostring(BurdJournals.getPlayerSteamId(player) or "") or ""
    local playerUsername = player.getUsername and tostring(player:getUsername() or "") or ""
    if (ownerSteamId ~= "" and ownerSteamId ~= playerSteamId)
        or (ownerSteamId == "" and ownerUsername ~= "" and string.lower(ownerUsername) ~= string.lower(playerUsername)) then return nil end
    local recovered = BurdJournals.Server.buildEntryStoreOnlyJournalData
        and BurdJournals.Server.buildEntryStoreOnlyJournalData(journalUUID, sourceTag or "serverOwnedRecovery") or nil
    if type(recovered) ~= "table" then return nil end
    recovered.uuid, recovered.entryStoreUUID, recovered.isPlayerCreated = journalUUID, journalUUID, true
    recovered.sourceType = recovered.sourceType or registryData.sourceType or "personal"
    recovered.originMode = recovered.originMode or registryData.originMode or "personal"
    recovered.ownerSteamId = recovered.ownerSteamId or registryEntry.ownerSteamId or registryData.ownerSteamId
    recovered.ownerUsername = recovered.ownerUsername or registryEntry.ownerUsername or registryData.ownerUsername
    recovered.ownerCharacterName = recovered.ownerCharacterName or registryEntry.ownerCharacterName or registryData.ownerCharacterName
    recovered.author = recovered.author or registryData.author or recovered.ownerCharacterName
    recovered.isWritten = true
    return recovered
end

local function bootstrapResolvedJournalFromCommandData(journal, player, args, sourceTag)
    if not journal or type(args) ~= "table" then
        return journal
    end
    if not BurdJournals.Server.applyNormalizedDebugJournalDataToItem then
        return journal
    end

    local modData = journal.getModData and journal:getModData() or nil
    local existingData = modData and modData.BurdJournals or nil
    local requestedUUID = normalizeCommandJournalUUID(args)
    local needsBootstrap = journalDataNeedsServerBootstrap(existingData)

    if (not needsBootstrap)
        and (not requestedUUID or (type(existingData) == "table"
            and tostring(BurdJournals.getJournalIdentityUUID(existingData) or "") == tostring(requestedUUID))) then
        return journal
    end

    local normalized = BurdJournals.Server.getServerOwnedJournalRecoveryData(player, requestedUUID, "bootstrapResolvedJournal:" .. tostring(sourceTag or "unknown"))
    if type(normalized) ~= "table" then return journal end
    local applied = BurdJournals.Server.applyNormalizedDebugJournalDataToItem(journal, normalized, requestedUUID)
    if type(applied) ~= "table" then
        return journal
    end

    if journal.transmitModData and not BurdJournals.Server.shouldDeferBatchTransmit() then
        safeTransmitServerJournalModData(journal, "bootstrapResolvedJournalFromCommandData")
    end
    if BurdJournals.Server.updateJournalUUIDIndex then
        BurdJournals.Server.updateJournalUUIDIndex(journal, player, tostring(sourceTag or "commandBootstrap"))
    end

    BurdJournals.debugPrint("[BurdJournals] Server: Restored server-owned journal data using client identity hints for source="
        .. tostring(sourceTag or "unknown")
        .. ", journalId=" .. tostring(journal.getID and journal:getID() or args.journalId)
        .. ", journalUUID=" .. tostring(applied.uuid))

    return journal
end

local function materializeServerJournalFromCommandData(player, args, sourceTag)
    if not player or type(args) ~= "table" then
        return nil, nil
    end

    -- Non-player journals spawned client-side (for example via admin item viewers on B41)
    -- may not exist in authoritative inventory state yet. Materializing them into a real
    -- server item should not depend on the debug gate; the payload/fullType checks below
    -- are the actual validation boundary for this bootstrap path.

    local requestedUUID = normalizeCommandJournalUUID(args)
    if not requestedUUID or requestedUUID == "" then
        if requestedUUID and requestedUUID ~= "" then
            bsjWriteLogLine("[BurdJournals] Server: Cannot materialize missing journal; no usable itemFullType"
                .. " source=" .. tostring(sourceTag or "unknown")
                .. " journalUUID=" .. tostring(requestedUUID)
                .. " itemFullType=" .. tostring(args.itemFullType)
                .. " fingerprint=" .. tostring(normalizeCommandJournalFingerprint(args)))
        end
        return nil, nil
    end

    local fullType = "BurdJournals.FilledSurvivalJournal"
    local normalized = BurdJournals.Server.getServerOwnedJournalRecoveryData(player, requestedUUID,
        "materializeServerJournalFromEntryStore:" .. tostring(sourceTag or "unknown"))
    if type(normalized) ~= "table" then
        if requestedUUID and requestedUUID ~= "" then
            bsjWriteLogLine("[BurdJournals] Server: Cannot materialize missing journal; no payload or entry-store backup"
                .. " source=" .. tostring(sourceTag or "unknown")
                .. " journalUUID=" .. tostring(requestedUUID)
                .. " fullType=" .. tostring(fullType))
        end
        return nil, nil
    end

    if args.createIfMissing == false then
        return nil, nil
    end

    local inventory = player.getInventory and player:getInventory() or nil
    if not inventory or not inventory.AddItem then
        return nil, nil
    end

    local journal = inventory:AddItem(fullType)
    if not journal then
        return nil, nil
    end

    local targetCondition = tonumber(normalized.condition)
        or tonumber(getJournalFingerprintToken(normalizeCommandJournalFingerprint(args), "condition"))
    if targetCondition and journal.setCondition then
        BurdJournals.safePcall(function()
            journal:setCondition(math.max(0, math.floor(targetCondition + 0.5)))
        end)
    end

    normalized.fullType = fullType
    if BurdJournals.clearPlayerJournalDebugProvenance then
        BurdJournals.clearPlayerJournalDebugProvenance(normalized, "materializeServerJournalFromCommandData")
    end

    local bj = BurdJournals.Server.applyNormalizedDebugJournalDataToItem
        and BurdJournals.Server.applyNormalizedDebugJournalDataToItem(journal, normalized, requestedUUID)
        or nil
    if type(bj) ~= "table" then
        inventory:Remove(journal)
        return nil, nil
    end

    normalizeFoundJournalClaimFlags(journal, bj, "materializeServerJournalFromCommandData")
    if BurdJournals.updateJournalName then
        BurdJournals.updateJournalName(journal, true)
    end
    if BurdJournals.updateJournalIcon then
        BurdJournals.updateJournalIcon(journal)
    end
    if journal.transmitModData and not BurdJournals.Server.shouldDeferBatchTransmit() then
        safeTransmitServerJournalModData(journal, "materializeServerJournalFromCommandData")
    end
    if inventory.setDrawDirty then
        inventory:setDrawDirty(true)
    end
    if player.syncInventory then
        BurdJournals.safePcall(function()
            player:syncInventory()
        end)
    end
    if sendAddItemToContainer then
        BurdJournals.safePcall(function()
            sendAddItemToContainer(inventory, journal)
        end)
    end
    if BurdJournals.Server.updateJournalUUIDIndex then
        BurdJournals.Server.updateJournalUUIDIndex(journal, player, "materialize:" .. tostring(sourceTag or "unknown"))
    end

    BurdJournals.Server.sendToClient(player, "journalMaterialized", {
        oldJournalId = args.journalId,
        oldJournalUUID = requestedUUID,
        newJournalId = journal.getID and journal:getID() or nil,
        journalUUID = bj.uuid,
        journalData = bj,
        source = sourceTag or "unknown",
    })

    BurdJournals.debugPrint("[BurdJournals] Server: Materialized client journal payload into live item for source="
        .. tostring(sourceTag or "unknown")
        .. ", requestedId=" .. tostring(args.journalId)
        .. ", requestedUUID=" .. tostring(requestedUUID)
        .. ", newJournalId=" .. tostring(journal.getID and journal:getID() or "nil")
        .. ", fullType=" .. tostring(fullType))

    return journal, "materializedFromPayload"
end

-- Repeated timed-action and entry-sync commands normally operate on a journal
-- already carried by the player.  Keep their stale/malformed lookup path out of
-- the recursive 3x3 world/container search used for explicit world interaction.
-- Opening/sealing actions pick the journal up before sending their command, so
-- ordinary command resolution never needs a nearby-world fallback.
BurdJournals.Server.INVENTORY_ONLY_JOURNAL_RESOLUTION_COMMANDS = {
    openCursedJournal = true,
    openCursedJournalConfirm = true,
    openYuletideJournal = true,
    openYuletideJournalConfirm = true,
    breakJournalSeal = true,
    yuletideGiftMaterialized = true,
    initializeJournal = true,
    logSkills = true,
    learnSkills = true,
    recordProgress = true,
    syncJournalData = true,
    requestJournalEntryChunk = true,
    claimSkill = true,
    claimTrait = true,
    claimForgetSlot = true,
    claimRecipe = true,
    claimStat = true,
    absorbSkill = true,
    absorbTrait = true,
    absorbRecipe = true,
    batchClaimRewards = true,
    batchAbsorbRewards = true,
    sanitizeJournal = true,
    saveJournalNotes = true,
    dissolveJournal = true,
    eraseJournal = true,
    convertToClean = true,
    eraseEntry = true,
    renameJournal = true,
    removeCraftDuplicates = true,
}

-- Missing-item recovery is deliberately narrower than ordinary command
-- resolution. These commands may recreate a server-owned registry journal,
-- but they still must not select an unrelated nearby world/container item.
BurdJournals.Server.MISSING_JOURNAL_RECOVERY_COMMANDS = {
    initializeJournal = true,
    syncJournalData = true,
}

-- B41 permits journal actions directly from an adjacent loot/world container.
-- Ordinary possession lookup remains inventory-only; this explicit interaction
-- path accepts only UUID/fingerprint matches and verifies the resolved item's
-- actual square is adjacent before any handler may mutate it.
BurdJournals.Server.DIRECT_WORLD_JOURNAL_COMMANDS = {
    absorbRecipe = true,
    absorbSkill = true,
    absorbTrait = true,
    batchAbsorbRewards = true,
    batchClaimRewards = true,
    breakJournalSeal = true,
    claimForgetSlot = true,
    claimRecipe = true,
    claimSkill = true,
    claimStat = true,
    claimTrait = true,
    convertToClean = true,
    dissolveJournal = true,
    eraseEntry = true,
    eraseJournal = true,
    initializeJournal = true,
    learnSkills = true,
    logSkills = true,
    openCursedJournal = true,
    openYuletideJournal = true,
    recordProgress = true,
    renameJournal = true,
    requestJournalEntryChunk = true,
    sanitizeJournal = true,
    saveJournalNotes = true,
    syncJournalData = true,
}

function BurdJournals.Server.getDirectWorldJournalSquare(journal, player)
    if not journal then return nil end

    local worldItem = journal.getWorldItem and journal:getWorldItem() or nil
    local worldSquare = worldItem and worldItem.getSquare and worldItem:getSquare() or nil
    if worldSquare then return worldSquare end

    local container = journal.getContainer and journal:getContainer() or nil
    local seen = {}
    for _ = 1, 8 do
        if not container or seen[container] then break end
        seen[container] = true
        local parent = container.getParent and container:getParent() or nil
        if parent == player then return nil end
        local square = parent and parent.getSquare and parent:getSquare() or nil
        if not square and container.getSourceGrid then
            square = container:getSourceGrid()
        end
        if square then return square end
        container = parent and parent.getContainer and parent:getContainer() or nil
    end
    return nil
end

function BurdJournals.Server.isDirectWorldJournalReachable(player, journal)
    if not (player and journal) then return false end
    local square = BurdJournals.Server.getDirectWorldJournalSquare(journal, player)
    local playerSquare = player.getCurrentSquare and player:getCurrentSquare() or nil
    if not (square and playerSquare) then return false end
    local sx = tonumber(square.getX and square:getX() or nil)
    local sy = tonumber(square.getY and square:getY() or nil)
    local sz = tonumber(square.getZ and square:getZ() or nil)
    local px = tonumber(playerSquare.getX and playerSquare:getX() or nil)
    local py = tonumber(playerSquare.getY and playerSquare:getY() or nil)
    local pz = tonumber(playerSquare.getZ and playerSquare:getZ() or nil)
    if not (sx and sy and sz and px and py and pz) or sz ~= pz then return false end
    return math.abs(sx - px) <= 1 and math.abs(sy - py) <= 1
end

function BurdJournals.Server.resolveDirectWorldJournalForCommand(player, args, sourceTag)
    if not (player and type(args) == "table" and BurdJournals.Server.DIRECT_WORLD_JOURNAL_COMMANDS[sourceTag]) then
        return nil, nil
    end
    local journalUUID = normalizeCommandJournalUUID(args)
    local journalFingerprint = normalizeCommandJournalFingerprint(args)
    if not journalUUID and not journalFingerprint then return nil, nil end
    local playerSquare = player.getCurrentSquare and player:getCurrentSquare() or nil
    if not playerSquare or not getCell then return nil, nil end
    local matches, seen = {}, {}
    local function addCandidate(candidate, path)
        if candidate and not seen[candidate]
            and BurdJournals.Server.isDirectWorldJournalReachable(player, candidate)
        then
            seen[candidate] = true
            matches[#matches + 1] = {item = candidate, path = path}
        end
    end
    local function inspectItem(candidate)
        if not candidate then return end
        local fullType = candidate.getFullType and tostring(candidate:getFullType()) or nil
        if not (fullType and fullType:find("^BurdJournals%.")) then return end
        local data = BurdJournals.getJournalData and BurdJournals.getJournalData(candidate) or nil
        local candidateUUID = type(data) == "table" and BurdJournals.getJournalIdentityUUID
            and BurdJournals.getJournalIdentityUUID(data) or nil
        if journalUUID and tostring(candidateUUID or "") == tostring(journalUUID) then
            addCandidate(candidate, "reachableWorldByUUID")
        elseif journalFingerprint and BurdJournals.buildJournalLookupFingerprint
            and BurdJournals.buildJournalLookupFingerprint(candidate, data) == journalFingerprint
        then
            addCandidate(candidate, "reachableWorldByFingerprint")
        end
    end
    local function inspectContainer(container)
        if not container then return end
        local candidate = journalUUID and BurdJournals.findJournalByUUIDInContainer
            and BurdJournals.findJournalByUUIDInContainer(container, journalUUID) or nil
        if candidate then
            addCandidate(candidate, "reachableWorldByUUID")
            return
        end
        candidate = journalFingerprint and BurdJournals.findJournalByLookupFingerprintInContainer
            and BurdJournals.findJournalByLookupFingerprintInContainer(container, journalFingerprint) or nil
        if candidate then addCandidate(candidate, "reachableWorldByFingerprint") end
    end
    local px, py, pz = playerSquare:getX(), playerSquare:getY(), playerSquare:getZ()
    for dx = -1, 1 do
        for dy = -1, 1 do
            local square = getCell():getGridSquare(px + dx, py + dy, pz)
            local objects = square and square.getObjects and square:getObjects() or nil
            if objects then
                for i = 0, objects:size() - 1 do
                    local object = objects:get(i)
                    inspectItem(object and object.getItem and object:getItem() or nil)
                    inspectContainer(object and object.getContainer and object:getContainer() or nil)
                    inspectContainer(object and object.getInventory and object:getInventory() or nil)
                end
            end
        end
    end
    if #matches ~= 1 then return nil, nil end
    return matches[1].item, matches[1].path
end

function BurdJournals.Server.findJournalInRequestersInventory(player, journalId, journalUUID, journalFingerprint)
    local inventory = player and player.getInventory and player:getInventory() or nil
    if not (inventory and inventory.getItems) then
        return nil, false
    end
    if journalId ~= nil and BurdJournals.findItemByIdInContainer then
        local byId = BurdJournals.findItemByIdInContainer(inventory, journalId)
        if byId then
            return byId, true
        end
    end
    if journalUUID and BurdJournals.findJournalByUUIDInContainer then
        local byUUID = BurdJournals.findJournalByUUIDInContainer(inventory, journalUUID)
        if byUUID then
            return byUUID, true
        end
    end
    if journalFingerprint and BurdJournals.findJournalByLookupFingerprintInContainer then
        return BurdJournals.findJournalByLookupFingerprintInContainer(inventory, journalFingerprint), true
    end
    return nil, true
end

local function resolveServerCommandJournal(player, args, sourceTag)
    if not player or type(args) ~= "table" then
        return nil, nil, nil, "invalidPayload"
    end

    local requestedJournalUUID = normalizeCommandJournalUUID(args) or resolveCommandJournalUUIDFromIndex(player, args)
    local function getCandidateJournalUUID(candidate)
        local modData = candidate and candidate.getModData and candidate:getModData() or nil
        local journalData = modData and modData.BurdJournals or nil
        if type(journalData) ~= "table" then
            return nil
        end
        local uuid = BurdJournals.getJournalIdentityUUID and BurdJournals.getJournalIdentityUUID(journalData)
            or journalData.uuid or journalData.entryStoreUUID
        if type(uuid) == "string" and uuid ~= "" then
            return uuid
        end
        return nil
    end

    local function candidateConflictsWithRequestedUUID(candidate)
        if type(requestedJournalUUID) ~= "string" or requestedJournalUUID == "" then
            return false
        end
        local candidateUUID = getCandidateJournalUUID(candidate)
        return type(candidateUUID) == "string"
            and candidateUUID ~= ""
            and tostring(candidateUUID) ~= tostring(requestedJournalUUID)
    end

    if args._resolvedJournal and BurdJournals.isValidItem and BurdJournals.isValidItem(args._resolvedJournal) then
        local resolvedJournalId = args._resolvedJournal.getID and args._resolvedJournal:getID() or args.journalId
        local resolvedJournalUUID = requestedJournalUUID
        if not resolvedJournalUUID then
            local resolvedModData = args._resolvedJournal.getModData and args._resolvedJournal:getModData() or nil
            local resolvedData = resolvedModData and resolvedModData.BurdJournals or nil
            resolvedJournalUUID = type(resolvedData) == "table" and resolvedData.uuid or nil
        end
        if candidateConflictsWithRequestedUUID(args._resolvedJournal) then
            BurdJournals.debugPrint("[BurdJournals] Server: Ignoring pre-resolved journal for source="
                .. tostring(sourceTag or "unknown")
                .. " because requested UUID " .. tostring(requestedJournalUUID)
                .. " does not match item UUID " .. tostring(getCandidateJournalUUID(args._resolvedJournal)))
        else
            return args._resolvedJournal, resolvedJournalId, resolvedJournalUUID, "batchResolved"
        end
    end

    local journalId = tonumber(args.journalId) or args.journalId
    local journalUUID = requestedJournalUUID
    local journalFingerprint = normalizeCommandJournalFingerprint(args)
    local exactJournalItem = args.exactJournalItem == true and journalId ~= nil
    -- Fail closed for new commands. Nearby-world interaction must use a
    -- dedicated, reachability-validating resolver rather than silently opting
    -- into the recursive mixed-scope helpers.
    local inventoryOnly = true
    local allowMissingRecovery = BurdJournals.Server.MISSING_JOURNAL_RECOVERY_COMMANDS[sourceTag] == true
    local journal = nil
    local conflictingById = nil
    local skipCommandBootstrap = false
    local resolvePath = "unresolved"

    if journalId ~= nil then
        local byId = nil
        if inventoryOnly then
            byId = BurdJournals.findItemByIdInPlayerInventory
                and BurdJournals.findItemByIdInPlayerInventory(player, journalId) or nil
        end
        if byId and exactJournalItem then
            journal = byId
            resolvePath = "requesterByExactId"
            if candidateConflictsWithRequestedUUID(byId) then
                -- Cursed stack activation is bound to the physical item the
                -- player selected. A stale UUID may be reconciled by the reply,
                -- but it must never retarget activation to a sibling in the stack.
                skipCommandBootstrap = true
            end
        elseif byId and candidateConflictsWithRequestedUUID(byId) then
            -- The same physical held item can temporarily have different client
            -- and server UUIDs after upgrading an existing save or initializing a
            -- fresh journal in MP. Keep the authoritative ID match as a fallback,
            -- but first give a genuinely matching held UUID/fingerprint priority.
            conflictingById = byId
            BurdJournals.debugPrint("[BurdJournals] Server: Rejected journalId candidate for source="
                .. tostring(sourceTag or "unknown")
                .. ", requestedId=" .. tostring(journalId)
                .. ", requestedUUID=" .. tostring(journalUUID)
                .. ", itemUUID=" .. tostring(getCandidateJournalUUID(byId)))
        elseif byId then
            journal = byId
            resolvePath = "requesterById"
        end
    end

    if (not journal) and not exactJournalItem and journalUUID and BurdJournals.findJournalByUUID then
        if inventoryOnly then
            journal = BurdJournals.findJournalByUUIDInPlayerInventory
                and BurdJournals.findJournalByUUIDInPlayerInventory(player, journalUUID) or nil
        end
        if journal then
            resolvePath = "requesterByUUID"
        end
    end

    if (not journal) and not exactJournalItem and journalFingerprint and BurdJournals.findJournalByLookupFingerprint then
        local fingerprintJournal = nil
        if inventoryOnly then
            fingerprintJournal = BurdJournals.findJournalByLookupFingerprintInPlayerInventory
                and BurdJournals.findJournalByLookupFingerprintInPlayerInventory(player, journalFingerprint) or nil
        end
        if fingerprintJournal and candidateConflictsWithRequestedUUID(fingerprintJournal) then
            BurdJournals.debugPrint("[BurdJournals] Server: Rejected fingerprint candidate for source="
                .. tostring(sourceTag or "unknown")
                .. ", requestedUUID=" .. tostring(journalUUID)
                .. ", itemUUID=" .. tostring(getCandidateJournalUUID(fingerprintJournal)))
        elseif fingerprintJournal then
            journal = fingerprintJournal
            resolvePath = "requesterByFingerprint"
        end
    end

    if not journal then
        local worldJournal, worldResolvePath =
            BurdJournals.Server.resolveDirectWorldJournalForCommand(player, args, sourceTag)
        if worldJournal then
            local requestedIdMatches = journalId ~= nil
                and worldJournal.getID
                and tostring(worldJournal:getID()) == tostring(journalId)
            if candidateConflictsWithRequestedUUID(worldJournal) and not requestedIdMatches then
                BurdJournals.debugPrint("[BurdJournals] Server: Rejected reachable world journal for source="
                    .. tostring(sourceTag or "unknown") .. " because its UUID conflicts with the request")
            else
                journal = worldJournal
                resolvePath = worldResolvePath or "reachableWorld"
                if candidateConflictsWithRequestedUUID(worldJournal) then
                    skipCommandBootstrap = true
                end
            end
        end
    end

    -- Missing-journal recovery is inventory-scoped and server-owned. Client
    -- payload data is never used to select a nearby item.
    if not journal and not exactJournalItem and allowMissingRecovery then
        local bootstrapJournal, bootstrapPath = findBootstrapJournalCandidateFromArgs(player, args, false)
        if bootstrapJournal and not candidateConflictsWithRequestedUUID(bootstrapJournal) then
            journal = bootstrapJournal
            resolvePath = bootstrapPath or "bootstrapByCommandType"
        end
    end

    if not journal and conflictingById then
        journal = conflictingById
        resolvePath = "requesterByIdUUIDReconciled"
        -- Never replace the authoritative item's data from a mismatched client
        -- UUID. The normal response payload will hydrate the client with the
        -- server-owned UUID and journal state.
        skipCommandBootstrap = true
        BurdJournals.debugPrint("[BurdJournals] Server: Reconciled stale client UUID using exact held item ID for source="
            .. tostring(sourceTag or "unknown")
            .. ", requestedId=" .. tostring(journalId)
            .. ", requestedUUID=" .. tostring(journalUUID)
            .. ", serverUUID=" .. tostring(getCandidateJournalUUID(journal)))
    end

    if journal then
        journalId = (journal.getID and journal:getID()) or journalId
        if not skipCommandBootstrap then
            journal = bootstrapResolvedJournalFromCommandData(journal, player, args, sourceTag)
        end
        local modData = journal.getModData and journal:getModData() or nil
        local journalData = modData and modData.BurdJournals or nil
        if type(journalData) == "table" and BurdJournals.resolveJournalUUIDForRuntime then
            local repairedUUID = BurdJournals.resolveJournalUUIDForRuntime(journalData, journal, false)
            if repairedUUID then
                journalUUID = repairedUUID
            end
        end
    elseif allowMissingRecovery then
        local materializedJournal, materializePath = materializeServerJournalFromCommandData(player, args, sourceTag)
        if materializedJournal then
            journal = materializedJournal
            resolvePath = materializePath or "materializedFromPayload"
            journalId = journal.getID and journal:getID() or journalId
            local modData = journal.getModData and journal:getModData() or nil
            local journalData = modData and modData.BurdJournals or nil
            if type(journalData) == "table" then
                journalUUID = tostring(journalData.uuid or journalUUID or "")
            end
        end
    end

    if not journal then
        bsjWriteLogLine("[BurdJournals] Server ERROR: Journal not found (source="
            .. tostring(sourceTag or "unknown")
            .. ", journalId=" .. tostring(journalId)
            .. ", journalUUID=" .. tostring(journalUUID)
            .. ", journalFingerprint=" .. tostring(journalFingerprint) .. ")")
    elseif resolvePath ~= "requesterById" then
        BurdJournals.debugPrint("[BurdJournals] Server: Resolved journal via "
            .. tostring(resolvePath)
            .. " for source=" .. tostring(sourceTag or "unknown")
            .. ", requestedId=" .. tostring(journalId)
            .. ", requestedUUID=" .. tostring(journalUUID)
            .. ", requestedFingerprint=" .. tostring(journalFingerprint))
    end

    return journal, journalId, journalUUID, resolvePath
end

local function getResolvedJournalIdentity(journal, resolvedJournalId, resolvedJournalUUID, fallbackJournalId)
    local liveJournalId = resolvedJournalId
    if liveJournalId == nil and journal and journal.getID then
        liveJournalId = journal:getID()
    end
    if liveJournalId == nil then
        liveJournalId = fallbackJournalId
    end

    local liveJournalUUID = resolvedJournalUUID
    if not liveJournalUUID and journal and journal.getModData then
        local modData = journal:getModData()
        local journalData = modData and modData.BurdJournals or nil
        if type(journalData) == "table" then
            liveJournalUUID = (BurdJournals.getJournalIdentityUUID and BurdJournals.getJournalIdentityUUID(journalData))
                or (BurdJournals.resolveJournalUUIDForRuntime and BurdJournals.resolveJournalUUIDForRuntime(journalData, journal, true))
        end
    end

    return liveJournalId, liveJournalUUID
end

local function buildSyncSuccessPayload(journalId, journalData, player)
    local payload = {
        journalId = journalId,
        serverRuntimeMarker = BurdJournals.RUNTIME_LOAD_MARKER
    }
    if type(journalData) ~= "table" then
        payload.needsSync = true
        return payload
    end

    local canonicalUUID = BurdJournals.getJournalIdentityUUID and BurdJournals.getJournalIdentityUUID(journalData) or nil
    local fullSyncEntryLimit = BurdJournals.getJournalFullSyncEntryLimit and BurdJournals.getJournalFullSyncEntryLimit(journalData)
        or math.max(1, tonumber(BurdJournals.FULL_SYNC_ENTRY_LIMIT) or 180)
    local entryCount = BurdJournals.Server.countJournalPayloadEntries(journalData)
    if isStrictMPEmptyJournalShellData(journalData) then
        payload.journalUUID = canonicalUUID
        payload.needsSync = true
        payload.fullJournalDataOmitted = true
        payload.fullJournalDataOmittedReason = "emptyShell"
        payload.entryStoreUnavailable = true
        BurdJournals.debugPrint("[BurdJournals] syncSuccess refused empty strict-MP journal shell for journalId="
            .. tostring(journalId))
        return payload
    end
    -- Entry-store shells are compact in hosted MP too. Treating one as full
    -- journalData works only until the client's hydrated cache is cleared by a
    -- reconnect, after which the journal appears empty despite its durable store.
    if journalData.entryStoreEnabled == true
        or (isStrictMPServer() and entryCount >= fullSyncEntryLimit)
    then
        local expectedEntryStoreCount = BurdJournals.Server.countEntryStoreManifestEntries(journalData)
        local actualEntryStoreCount = nil
        if journalData.entryStoreEnabled == true and BurdJournals.refreshJournalEntryStoreCounts then
            actualEntryStoreCount = BurdJournals.refreshJournalEntryStoreCounts(journalData, "syncSuccessCounts")
            actualEntryStoreCount = tonumber(actualEntryStoreCount) or 0
        end
        payload.journalUUID = canonicalUUID
        payload.entryStoreEnabled = journalData.entryStoreEnabled == true
        payload.entryStoreEntryCounts = type(journalData.entryStoreEntryCounts) == "table" and journalData.entryStoreEntryCounts or nil
        payload.entryStoreUpdatedAt = tonumber(journalData.entryStoreUpdatedAt)
        payload.entryStoreActualCount = actualEntryStoreCount
        payload.entryStoreUnavailable = journalData.entryStoreEnabled == true
            and expectedEntryStoreCount > 0
            and actualEntryStoreCount ~= nil
            and actualEntryStoreCount <= 0
            or false
        local runtimeDelta = BurdJournals.buildRuntimeDeltaForPlayer and BurdJournals.buildRuntimeDeltaForPlayer(journalData, player) or nil
        if type(runtimeDelta) == "table" then
            payload.runtimeDelta = runtimeDelta
        end
        local journalDelta = {}
        local hasJournalDelta = false
        local scalarKeys = {
            "uuid",
            "entryStoreUUID",
            "entryStoreUpdatedAt",
            "isPlayerCreated",
            "isWritten",
            "isWorn",
            "isBloody",
            "wasFromWorn",
            "wasFromBloody",
            "hasBloodyOrigin",
            "isZombieJournal",
            "isCursedJournal",
            "isCursedReward",
            "isYuletideJournal",
            "yuletideState",
            "author",
            "ownerCharacterName",
            "profession",
            "professionName",
            "flavorKey",
            "loreNoteTemplateFamily",
            "lootNotesRollDone",
            "lootNotesRollChance",
            "notes",
        }
        for _, key in ipairs(scalarKeys) do
            if journalData[key] ~= nil then
                journalDelta[key] = BurdJournals.Server.deepCopy and BurdJournals.Server.deepCopy(journalData[key]) or journalData[key]
                hasJournalDelta = true
            end
        end
        if hasJournalDelta then
            payload.journalDelta = journalDelta
        end
        payload.fullJournalDataOmitted = true
        payload.fullJournalDataOmittedReason = journalData.entryStoreEnabled == true and "entryStore" or "largeJournal"
        BurdJournals.debugPrint("[BurdJournals] syncSuccess omitted full journalData before copy for journalId="
            .. tostring(journalId) .. " (entries=" .. tostring(entryCount)
            .. ", storeActual=" .. tostring(actualEntryStoreCount)
            .. ", limit=" .. tostring(fullSyncEntryLimit) .. ")")
        return payload
    end

    local projected = BurdJournals.Server.deepCopy(journalData)
    local runtimeDelta = nil
    if BurdJournals.applyRuntimeProjectionToJournalData then
        runtimeDelta = BurdJournals.applyRuntimeProjectionToJournalData(projected, player)
    end
    payload.journalUUID = BurdJournals.getJournalIdentityUUID and BurdJournals.getJournalIdentityUUID(projected) or nil
    payload.journalData = projected
    if type(runtimeDelta) == "table" then
        payload.runtimeDelta = runtimeDelta
    end

    local softLimit = math.max(1024, tonumber(BurdJournals.FULL_SYNC_SOFT_LIMIT_BYTES) or 48000)
    local estimate = estimatePayloadBytes(payload)
    if estimate > softLimit then
        payload.journalData = nil
        payload.fullJournalDataOmitted = true
        payload.fullJournalDataOmittedReason = "softLimit"
        BurdJournals.debugPrint("[BurdJournals] syncSuccess payload soft-limit exceeded for journalId="
            .. tostring(journalId) .. " (" .. tostring(estimate) .. " > " .. tostring(softLimit)
            .. "), omitting duplicate full journalData")
    end

    return payload
end

local function chooseRandom(list)
    if type(list) ~= "table" or #list == 0 then return nil end
    return list[ZombRand(#list) + 1]
end

local function shuffleArray(list)
    if type(list) ~= "table" then return end
    for i = #list, 2, -1 do
        local j = ZombRand(i) + 1
        list[i], list[j] = list[j], list[i]
    end
end

local function getCursedServerText(key, fallback)
    local text = getText(key)
    if text and text ~= "" and text ~= key then
        return text
    end
    return fallback
end

local function buildCursedRewardSkills(professionId, opts)
    local out = {}
    local allowed = (BurdJournals.getAllowedSkills and BurdJournals.getAllowedSkills()) or {}
    if #allowed == 0 then return out end

    -- opts (optional): forceMaxCount forces the roll to the max skill count;
    -- xpScale multiplies each generated skill's XP (used by severity compensation).
    local forceMaxCount = type(opts) == "table" and opts.forceMaxCount == true
    local xpScale = (type(opts) == "table" and tonumber(opts.xpScale)) or 1

    local minXP = tonumber(BurdJournals.getSandboxOption and BurdJournals.getSandboxOption("CursedJournalMinXP")) or 75
    local maxXP = tonumber(BurdJournals.getSandboxOption and BurdJournals.getSandboxOption("CursedJournalMaxXP")) or 300
    minXP = math.max(1, math.floor(minXP))
    maxXP = math.max(minXP, math.floor(maxXP))

    local minSkills = tonumber(BurdJournals.getSandboxOption and BurdJournals.getSandboxOption("CursedJournalMinSkills")) or 2
    local maxSkills = tonumber(BurdJournals.getSandboxOption and BurdJournals.getSandboxOption("CursedJournalMaxSkills")) or 5
    minSkills = math.max(1, math.floor(minSkills))
    maxSkills = math.max(minSkills, math.floor(maxSkills))
    if forceMaxCount then
        minSkills = maxSkills
    end
    if BurdJournals.rollCoherentSkillsForProfession and professionId then
        local coherentSkills, coreCount, fallbackCount = BurdJournals.rollCoherentSkillsForProfession(
            professionId,
            minSkills,
            maxSkills,
            minXP,
            maxXP
        )
        if coherentSkills and BurdJournals.hasAnyEntries and BurdJournals.hasAnyEntries(coherentSkills) then
            if xpScale > 1 and BurdJournals.Server.scaleCursedRewardSkillXP then
                BurdJournals.Server.scaleCursedRewardSkillXP(coherentSkills, xpScale)
            end
            return coherentSkills, coreCount, fallbackCount
        end
    end

    local numSkills = ZombRand(minSkills, maxSkills + 1)

    local candidates = {}
    for _, skillName in ipairs(allowed) do
        local perk = BurdJournals.getPerkByName and BurdJournals.getPerkByName(skillName)
        if perk then
            candidates[#candidates + 1] = skillName
        end
    end
    shuffleArray(candidates)

    for i = 1, math.min(numSkills, #candidates) do
        local skillName = candidates[i]
        local xp = ZombRand(minXP, maxXP + 1)
        local level = (BurdJournals.getSkillLevelFromXP and BurdJournals.getSkillLevelFromXP(xp, skillName)) or 0
        out[skillName] = {
            xp = xp,
            level = level,
        }
    end
    if xpScale > 1 and BurdJournals.Server.scaleCursedRewardSkillXP then
        BurdJournals.Server.scaleCursedRewardSkillXP(out, xpScale)
    end
    return out, 0, BurdJournals.countTable and BurdJournals.countTable(out) or 0
end

local function buildCursedRewardTraits()
    if BurdJournals.getSandboxOption and BurdJournals.getSandboxOption("EnableCursedJournalTraits") == false then
        return nil
    end

    local traitChance = tonumber(BurdJournals.getSandboxOption and BurdJournals.getSandboxOption("CursedJournalTraitChance")) or 40
    if traitChance <= 0 or ZombRand(100) >= traitChance then
        return nil
    end

    local grantable = (BurdJournals.getGrantableTraitsForJournal
        and BurdJournals.getGrantableTraitsForJournal({ isCursedReward = true, isPlayerCreated = false })) or {}
    if #grantable == 0 then
        return nil
    end

    local pool = {}
    for _, traitId in ipairs(grantable) do
        pool[#pool + 1] = traitId
    end
    shuffleArray(pool)

    local out = {}
    local minTraits = tonumber(BurdJournals.getSandboxOption and BurdJournals.getSandboxOption("CursedJournalMinTraits")) or 1
    local maxTraits = tonumber(BurdJournals.getSandboxOption and BurdJournals.getSandboxOption("CursedJournalMaxTraits")) or 3
    minTraits = math.max(1, math.floor(minTraits))
    maxTraits = math.max(minTraits, math.floor(maxTraits))
    maxTraits = math.min(maxTraits, #pool)
    minTraits = math.min(minTraits, maxTraits)
    local traitCount = ZombRand(minTraits, maxTraits + 1)
    for i = 1, traitCount do
        out[pool[i]] = true
    end
    return out
end

local function buildCursedRewardRecipes()
    if BurdJournals.getSandboxOption and BurdJournals.getSandboxOption("EnableCursedJournalRecipes") == false then
        return nil
    end

    local recipeChance = tonumber(BurdJournals.getSandboxOption and BurdJournals.getSandboxOption("CursedJournalRecipeChance")) or 60
    if recipeChance <= 0 or ZombRand(100) >= recipeChance then
        return nil
    end

    local maxRecipes = tonumber(BurdJournals.getSandboxOption and BurdJournals.getSandboxOption("CursedJournalMaxRecipes")) or 3
    maxRecipes = math.max(1, math.floor(maxRecipes))
    local count = ZombRand(1, maxRecipes + 1)
    if BurdJournals.generateRandomRecipes then
        return BurdJournals.generateRandomRecipes(count)
    end
    return nil
end

-- Scale each skill entry's XP by a multiplier and recompute its level in place.
function BurdJournals.Server.scaleCursedRewardSkillXP(skills, xpScale)
    xpScale = tonumber(xpScale)
    if type(skills) ~= "table" or not xpScale or xpScale <= 1 then
        return skills
    end
    for skillName, entry in pairs(skills) do
        if type(entry) == "table" and tonumber(entry.xp) then
            local scaledXP = math.floor(tonumber(entry.xp) * xpScale)
            entry.xp = scaledXP
            entry.level = (BurdJournals.getSkillLevelFromXP and BurdJournals.getSkillLevelFromXP(scaledXP, skillName)) or entry.level or 0
        end
    end
    return skills
end

-- Resolve severity compensation for a curse category. Returns nil when compensation
-- does not apply (manual rewards, non-severe/persistent curse, or disabled by sandbox).
function BurdJournals.Server.resolveCursedSeverityCompensation(curseCategory, manualRewards)
    if manualRewards == true then
        return nil
    end
    if curseCategory ~= "persistent" and curseCategory ~= "severe" then
        return nil
    end
    if BurdJournals.getSandboxOption and BurdJournals.getSandboxOption("CursedJournalSeverityCompensation") == false then
        return nil
    end

    local comp = { forceForgetSlot = true, forceMaxSkills = false, xpScale = 1 }
    if curseCategory == "severe" then
        comp.forceMaxSkills = true
        local bonusPercent = tonumber(BurdJournals.getSandboxOption and BurdJournals.getSandboxOption("CursedJournalSevereRewardBonusPercent"))
        if bonusPercent == nil then
            bonusPercent = 50
        end
        bonusPercent = math.max(0, bonusPercent)
        comp.xpScale = 1 + (bonusPercent / 100)
    end
    return comp
end

function BurdJournals.Server.generateCursedRewardProfile(sourceData)
    local source = type(sourceData) == "table" and sourceData or {}
    local manualRewards = source.manualRewards == true or source.cursedManualRewards == true
    local severityCompensation = BurdJournals.Server.resolveCursedSeverityCompensation(source.curseCategory, manualRewards)
    local gameTime = type(getGameTime) == "function" and getGameTime() or nil
    local worldAge = gameTime and gameTime:getWorldAgeHours() or 0
    local cursedIdentity = BurdJournals.Server.resolveCursedJournalIdentity and BurdJournals.Server.resolveCursedJournalIdentity(source) or {}
    local professionId = cursedIdentity.profession
    local professionName = cursedIdentity.professionName
    local flavorKey = cursedIdentity.flavorKey

    local sourceSkills = nil
    if manualRewards then
        sourceSkills = type(source.skills) == "table" and source.skills or {}
    else
        sourceSkills = (type(source.skills) == "table" and BurdJournals.hasAnyEntries and BurdJournals.hasAnyEntries(source.skills)) and source.skills or nil
    end
    local skillsCoreCount = tonumber(source.coreSkillCount) or 0
    local skillsFallbackCount = tonumber(source.fallbackSkillCount) or 0
    local generatedSkills = sourceSkills
    if not generatedSkills then
        local skillOpts = nil
        if severityCompensation then
            skillOpts = { forceMaxCount = severityCompensation.forceMaxSkills, xpScale = severityCompensation.xpScale }
        end
        generatedSkills, skillsCoreCount, skillsFallbackCount = buildCursedRewardSkills(professionId, skillOpts)
    elseif severityCompensation and severityCompensation.xpScale and severityCompensation.xpScale > 1 then
        -- Pre-staged (hidden journal) rewards: scale staged skill XP in place so the
        -- revealed set matches what was staged, just severity-compensated.
        BurdJournals.Server.scaleCursedRewardSkillXP(generatedSkills, severityCompensation.xpScale)
    end

    local generatedTraits = nil
    if manualRewards then
        generatedTraits = type(source.traits) == "table" and source.traits or {}
    else
        generatedTraits = (type(source.traits) == "table" and BurdJournals.hasAnyEntries and BurdJournals.hasAnyEntries(source.traits))
            and source.traits or buildCursedRewardTraits()
    end
    local generatedRecipes = nil
    if manualRewards then
        generatedRecipes = type(source.recipes) == "table" and source.recipes or {}
    else
        generatedRecipes = (type(source.recipes) == "table" and BurdJournals.hasAnyEntries and BurdJournals.hasAnyEntries(source.recipes))
            and source.recipes or buildCursedRewardRecipes()
    end

    if BurdJournals.resolveProfessionForGeneratedEntries then
        professionId, professionName, flavorKey = BurdJournals.resolveProfessionForGeneratedEntries(
            professionId,
            professionName,
            flavorKey or "UI_BurdJournals_BloodyFlavor",
            generatedSkills,
            generatedTraits,
            generatedRecipes,
            skillsCoreCount,
            skillsFallbackCount
        )
    end

    local profile = {
        uuid = source.uuid or (BurdJournals.generateUUID and BurdJournals.generateUUID()) or tostring(ZombRand(999999999)),
        author = cursedIdentity.author,
        profession = cursedIdentity.profession or professionId,
        professionName = cursedIdentity.professionName or professionName,
        flavorKey = flavorKey or "UI_BurdJournals_BloodyFlavor",
        flavorText = source.flavorText,
        loreNoteText = source.loreNoteText,
        loreNoteTemplateVersion = tonumber(source.loreNoteTemplateVersion),
        loreNoteTemplateFamily = source.loreNoteTemplateFamily,
        timestamp = tonumber(source.timestamp) or (worldAge - ZombRand(24, 720)),
        skills = generatedSkills or {},
        traits = generatedTraits,
        recipes = generatedRecipes,
        stats = type(source.stats) == "table" and source.stats or {},
        forgetSlot = (severityCompensation and severityCompensation.forceForgetSlot == true and true)
            or (manualRewards
                and (source.forgetSlot == true and true or nil)
                or BurdJournals.rollForgetSlotForType and BurdJournals.rollForgetSlotForType("cursed", source.forgetSlot)
                or (source.forgetSlot == true and true or nil)),
        isWorn = false,
        isBloody = true,
        wasFromBloody = true,
        isPlayerCreated = false,
        isZombieJournal = true,
        condition = tonumber(source.condition) or ZombRand(1, 4),
        claims = type(source.claims) == "table" and source.claims or {},
        claimedSkills = type(source.claimedSkills) == "table" and source.claimedSkills or {},
        claimedTraits = type(source.claimedTraits) == "table" and source.claimedTraits or {},
        claimedRecipes = type(source.claimedRecipes) == "table" and source.claimedRecipes or {},
        claimedStats = type(source.claimedStats) == "table" and source.claimedStats or {},
        claimedForgetSlot = type(source.claimedForgetSlot) == "table" and source.claimedForgetSlot or {},
        isCursedReward = true,
        isCursedJournal = false,
        cursedState = "unleashed",
        cursedSealSoundEvent = source.cursedSealSoundEvent,
        cursedPendingRewards = nil,
        cursedUnleashedByName = source.cursedUnleashedByName,
    }

    if source.lootNotesEligible == true and BurdJournals.Server.tryAttachGeneratedLootNotes then
        BurdJournals.Server.tryAttachGeneratedLootNotes(nil, nil, profile, profile.loreNoteTemplateFamily or "cursed")
    end

    -- Add-on hook: allow companion mods to mutate the profile before it is returned.
    if BurdJournals.runHooks then
        BurdJournals.runHooks("OnCursedRewardProfileGenerated", profile, source)
    end

    return profile
end

