function BurdJournals.Server.resolveYuletideGiftAmmoBoxType(fullType)
    if type(fullType) ~= "string" or fullType == "" then
        return nil
    end

    local scriptManager = getScriptManager and getScriptManager() or ScriptManager and ScriptManager.instance or nil
    if scriptManager and scriptManager.getItem then
        local okItem, scriptItem = pcall(function()
            return scriptManager:getItem(fullType)
        end)
        if okItem and scriptItem and scriptItem.getAmmoBox then
            local okAmmoBox, ammoBoxType = pcall(function()
                return scriptItem:getAmmoBox()
            end)
            if okAmmoBox and type(ammoBoxType) == "string" and ammoBoxType ~= "" then
                return ammoBoxType
            end
        end
    end

    return BurdJournals.Server.YULETIDE_GUN_AMMO_BOX_FALLBACKS[fullType]
end

function BurdJournals.Server.addOrIncrementYuletideGiftEntry(gifts, fullType, count)
    if type(gifts) ~= "table" or type(fullType) ~= "string" or fullType == "" then
        return
    end

    local normalizedCount = math.max(1, math.floor(tonumber(count) or 1))
    for _, gift in ipairs(gifts) do
        if gift.type == fullType then
            gift.count = math.max(1, math.floor(tonumber(gift.count) or 1)) + normalizedCount
            return
        end
    end

    gifts[#gifts + 1] = {
        type = fullType,
        count = normalizedCount,
    }
end

function BurdJournals.Server.appendYuletideGiftEntryWithBundles(gifts, entry)
    if type(entry) ~= "table" or type(entry.type) ~= "string" or entry.type == "" then
        return
    end

    local itemCount = ZombRand(entry.min or 1, (entry.max or entry.min or 1) + 1)
    BurdJournals.Server.addOrIncrementYuletideGiftEntry(gifts, entry.type, itemCount)

    local ammoBoxType = BurdJournals.Server.resolveYuletideGiftAmmoBoxType(entry.type)
    if ammoBoxType then
        BurdJournals.Server.addOrIncrementYuletideGiftEntry(gifts, ammoBoxType, itemCount)
    end
end

local function getYuletideServerText(key, fallback)
    local text = getText(key)
    if text and text ~= "" and text ~= key then
        return text
    end
    return fallback
end

function BurdJournals.Server.normalizeJournalServerText(value)
    if value == nil then
        return nil
    end
    local text = tostring(value)
    text = text:gsub("^%s+", ""):gsub("%s+$", "")
    if text == "" then
        return nil
    end
    return text
end

function BurdJournals.Server.getJournalPlayerDisplayName(player)
    if not player then
        return getYuletideServerText("UI_BurdJournals_UnknownSurvivor", "Unknown Survivor")
    end

    local descriptor = player.getDescriptor and player:getDescriptor() or nil
    if descriptor then
        local forename = BurdJournals.Server.normalizeJournalServerText(descriptor.getForename and descriptor:getForename() or nil)
        local surname = BurdJournals.Server.normalizeJournalServerText(descriptor.getSurname and descriptor:getSurname() or nil)
        if forename and surname then
            return forename .. " " .. surname
        end
        if forename then
            return forename
        end
        if surname then
            return surname
        end
    end

    local displayName = BurdJournals.Server.normalizeJournalServerText(player.getDisplayName and player:getDisplayName() or nil)
    if displayName then
        return displayName
    end

    local username = BurdJournals.Server.normalizeJournalServerText(player.getUsername and player:getUsername() or nil)
    if username then
        return username
    end

    return getYuletideServerText("UI_BurdJournals_UnknownSurvivor", "Unknown Survivor")
end

local function normalizeGeneratedLoreLineBreaks(text)
    if type(text) ~= "string" then
        return text
    end
    return text:gsub("\\r\\n", "\n"):gsub("\\n", "\n")
end

function BurdJournals.Server.getGeneratedLoreText(key, fallback)
    if BurdJournals.Server.getCustomLoreText then
        local customText = BurdJournals.Server.getCustomLoreText(key)
        if customText then
            return normalizeGeneratedLoreLineBreaks(customText)
        end
    end
    local text = getText(key)
    if text and text ~= "" and text ~= key then
        return normalizeGeneratedLoreLineBreaks(text)
    end
    return normalizeGeneratedLoreLineBreaks(fallback)
end

function BurdJournals.Server.appendNormalizedLoreValue(out, seen, value)
    local normalized = BurdJournals.Server.normalizeJournalServerText(value)
    if not normalized then
        return
    end

    local cacheKey = string.lower(normalized)
    if seen[cacheKey] then
        return
    end

    seen[cacheKey] = true
    out[#out + 1] = normalized
end

function BurdJournals.Server.parseLorePoolValues(rawText)
    local out = {}
    local seen = {}
    if type(rawText) ~= "string" then
        return out
    end

    for token in string.gmatch(rawText, "([^|]+)") do
        BurdJournals.Server.appendNormalizedLoreValue(out, seen, token)
    end

    if #out == 0 then
        BurdJournals.Server.appendNormalizedLoreValue(out, seen, rawText)
    end

    return out
end

function BurdJournals.Server.getLorePoolValues(key, fallback)
    local values = BurdJournals.Server.parseLorePoolValues(BurdJournals.Server.getGeneratedLoreText(key, fallback))
    if BurdJournals.Server.applyCustomLorePoolValues then
        return BurdJournals.Server.applyCustomLorePoolValues(key, values)
    end
    return values
end

BurdJournals.CUSTOM_CONTENT_SCHEMA = "BurdJournals.CustomContent"
BurdJournals.CUSTOM_CONTENT_VERSION = 1
BurdJournals.CUSTOM_CONTENT_FILES = {
    "BurdSurvivalJournals/CustomContent.json",
    "BurdSurvivalJournals/CustomLore.json",
    "BurdJournals/CustomContent.json",
    "BurdJournals/CustomLore.json",
    "BurdJournals_CustomContent.json",
    "BurdJournals_CustomLore.json",
}
BurdJournals._customContentLoaded = BurdJournals._customContentLoaded == true
BurdJournals._customContentLoading = false
BurdJournals._customContentSummary = BurdJournals._customContentSummary or {}
BurdJournals._customContentSources = BurdJournals._customContentSources or {}

local function getCustomContentLanguage()
    local core = getCore and getCore() or nil
    local language = nil
    if core then
        if core.getOptionLanguageName then
            language = core:getOptionLanguageName()
        elseif core.getOptionLanguage then
            language = core:getOptionLanguage()
        end
    end
    language = tostring(language or "EN"):upper()
    if language == "" or language == "NULL" then
        language = "EN"
    end
    return language
end

local function getCustomContentCandidateFiles()
    local files = {}
    local seen = {}
    local language = getCustomContentLanguage()
    local function add(path)
        if type(path) ~= "string" or path == "" or seen[path] then
            return
        end
        seen[path] = true
        files[#files + 1] = path
    end
    for _, path in ipairs(BurdJournals.CUSTOM_CONTENT_FILES or {}) do
        add(path)
        local langPath = string.gsub(path, "%.json$", "_" .. language .. ".json")
        add(langPath)
    end
    return files
end

local function customContentFileExists(filename)
    if type(filename) ~= "string" or filename == "" then
        return false
    end
    if not (luajava and luajava.bindClass) then
        return false
    end

    local ok, exists = pcall(function()
        local File = luajava.bindClass("java.io.File")
        local roots = {}
        local function addRoot(root)
            if type(root) == "string" and root ~= "" then
                roots[#roots + 1] = root
            end
        end
        if getMyDocumentFolder then
            local okRoot, root = pcall(getMyDocumentFolder)
            if okRoot then addRoot(root) end
        end
        if getCacheDir then
            local okRoot, root = pcall(getCacheDir)
            if okRoot then addRoot(root) end
        end
        if os and os.getenv then
            local userProfile = os.getenv("USERPROFILE")
            local home = os.getenv("HOME")
            if userProfile then addRoot(userProfile .. "\\Zomboid") end
            if home then addRoot(home .. "\\Zomboid") end
        end

        local direct = File:new(filename)
        if direct and direct:exists() then
            return true
        end
        for _, root in ipairs(roots) do
            local candidate = File:new(root, filename)
            if candidate and candidate:exists() then
                return true
            end
        end
        return false
    end)

    return ok and exists == true
end

local function readCustomContentFile(filename)
    if not (getFileReader and BurdJournals.decodeJournalExportJSON) then
        return nil
    end
    if not customContentFileExists(filename) then
        return nil
    end
    local lines = {}
    local ok = pcall(function()
        local reader = getFileReader(filename, true)
        if not reader then
            return
        end
        local totalBytes = 0
        while true do
            local line = reader:readLine()
            if line == nil then
                break
            end
            totalBytes = totalBytes + string.len(tostring(line))
            if totalBytes > 1024 * 1024 or #lines > 8000 then
                lines = {}
                break
            end
            lines[#lines + 1] = line
        end
        reader:close()
    end)
    if not ok or #lines == 0 then
        return nil
    end
    local decoded, err = BurdJournals.decodeJournalExportJSON(table.concat(lines, "\n"))
    if type(decoded) ~= "table" then
        bsjWriteLogLine("[BurdJournals][CustomContent] ignored " .. tostring(filename) .. ": " .. tostring(err or "invalid JSON"))
        return nil
    end
    return decoded
end

local function customContentArray(raw)
    local values = {}
    local seen = {}
    local function add(value)
        local normalized = BurdJournals.Server.normalizeJournalServerText(value)
        if not normalized then
            return
        end
        local key = string.lower(normalized)
        if seen[key] then
            return
        end
        seen[key] = true
        values[#values + 1] = normalized
    end
    if type(raw) == "string" then
        for token in string.gmatch(raw, "([^|]+)") do
            add(token)
        end
    elseif type(raw) == "table" then
        if #raw > 0 then
            for _, value in ipairs(raw) do
                add(value)
            end
        else
            for key, enabled in pairs(raw) do
                if enabled then
                    add(key)
                end
            end
        end
    end
    return values
end

local function mergeCustomArray(target, raw, replace)
    if type(target) ~= "table" then
        target = {}
    end
    if replace then
        for i = #target, 1, -1 do
            target[i] = nil
        end
    end
    local seen = {}
    for _, value in ipairs(target) do
        local normalized = BurdJournals.Server.normalizeJournalServerText(value)
        if normalized then
            seen[string.lower(normalized)] = true
        end
    end
    for _, value in ipairs(customContentArray(raw)) do
        local key = string.lower(value)
        if not seen[key] then
            seen[key] = true
            target[#target + 1] = value
        end
    end
    return target
end

local function normalizeCustomMode(raw, defaultMode)
    local mode = type(raw) == "table" and raw.mode or nil
    mode = tostring(mode or defaultMode or "append"):lower()
    if mode ~= "replace" then
        mode = "append"
    end
    return mode
end

local function normalizeLorePoolKey(key)
    local raw = tostring(key or "")
    if raw == "" then
        return nil
    end
    if string.sub(raw, 1, 25) == "UI_BurdJournals_LorePool_" then
        return raw
    end
    local lowered = string.lower(raw)
    local map = {
        stashnoun = "UI_BurdJournals_LorePool_StashNoun",
        dangernoun = "UI_BurdJournals_LorePool_DangerNoun",
        supplynoun = "UI_BurdJournals_LorePool_SupplyNoun",
        omennoun = "UI_BurdJournals_LorePool_OmenNoun",
        noun = "UI_BurdJournals_LorePool_Noun",
        nouns = "UI_BurdJournals_LorePool_Noun",
        verb = "UI_BurdJournals_LorePool_Verb",
        verbs = "UI_BurdJournals_LorePool_Verb",
        adjective = "UI_BurdJournals_LorePool_Adjective",
        adjectives = "UI_BurdJournals_LorePool_Adjective",
        adverb = "UI_BurdJournals_LorePool_Adverb",
        adverbs = "UI_BurdJournals_LorePool_Adverb",
        exclamation = "UI_BurdJournals_LorePool_Exclamation",
        exclamations = "UI_BurdJournals_LorePool_Exclamation",
        catchphrase = "UI_BurdJournals_LorePool_Exclamation",
        catchphrases = "UI_BurdJournals_LorePool_Exclamation",
    }
    return map[lowered] or raw
end

local function copyTemplateEntry(raw, fallbackKey)
    if type(raw) == "string" then
        return { text = raw }
    end
    if type(raw) ~= "table" then
        return nil
    end
    local text = raw.text or raw.fallback or raw.template
    local key = raw.key or fallbackKey
    if type(text) ~= "string" and type(key) ~= "string" then
        return nil
    end
    return {
        key = key,
        text = text,
        fallback = text or raw.fallback,
        professionGroups = customContentArray(raw.professionGroups or raw.groups),
        weight = tonumber(raw.weight) or nil,
    }
end

local function applyCustomTextBlock(payload)
    local texts = payload.texts or payload.translations
    if type(texts) ~= "table" then
        return 0
    end
    BurdJournals.Server._customLoreTexts = BurdJournals.Server._customLoreTexts or {}
    local count = 0
    local language = getCustomContentLanguage()
    local function addMap(map)
        if type(map) ~= "table" then
            return
        end
        for key, value in pairs(map) do
            local normalized = nil
            if type(value) ~= "table" then
                normalized = BurdJournals.Server.normalizeJournalServerText(value)
            end
            if type(key) == "string" and normalized then
                BurdJournals.Server._customLoreTexts[key] = normalized
                count = count + 1
            end
        end
    end
    addMap(texts)
    addMap(texts.EN)
    addMap(texts[language])
    return count
end

local function applyCustomNames(payload)
    local names = payload.names or payload.survivorNames
    if type(names) ~= "table" then
        return 0
    end
    local countBefore = #(BurdJournals.RANDOM_FIRST_NAMES or {}) + #(BurdJournals.RANDOM_LAST_NAMES or {})
    BurdJournals.RANDOM_FIRST_NAMES = mergeCustomArray(BurdJournals.RANDOM_FIRST_NAMES, names.first or names.firstNames, names.replaceFirst == true or names.replace == true)
    BurdJournals.RANDOM_LAST_NAMES = mergeCustomArray(BurdJournals.RANDOM_LAST_NAMES, names.last or names.lastNames, names.replaceLast == true or names.replace == true)
    return (#BurdJournals.RANDOM_FIRST_NAMES + #BurdJournals.RANDOM_LAST_NAMES) - countBefore
end

local function applyCustomProfessions(payload)
    local professions = payload.professions
    if type(professions) ~= "table" then
        return 0
    end
    local count = 0
    local profiles = {}
    local byId = {}
    for _, prof in ipairs(BurdJournals.PROFESSIONS or {}) do
        byId[tostring(prof.id)] = prof
    end
    for key, raw in pairs(professions) do
        if type(raw) == "table" then
            local id = raw.id or (type(key) == "string" and key or nil)
            id = BurdJournals.Server.normalizeJournalServerText(id)
            local name = BurdJournals.Server.normalizeJournalServerText(raw.name)
            if id and name then
                local prof = byId[id]
                if not prof then
                    prof = { id = id }
                    BurdJournals.PROFESSIONS[#BurdJournals.PROFESSIONS + 1] = prof
                    byId[id] = prof
                end
                prof.name = name
                prof.nameKey = raw.nameKey
                prof.flavorKey = raw.flavorKey
                profiles[#profiles + 1] = raw
                profiles[#profiles].id = id
                profiles[#profiles].name = name
                count = count + 1
            end
        end
    end
    if #profiles > 0 and BurdJournals.registerProfessionProfiles then
        BurdJournals.registerProfessionProfiles("BSJCustom", profiles)
    end
    return count
end

local function applyCustomLorePools(payload)
    local pools = payload.lorePools or payload.pools or payload.wordPools
    if type(pools) ~= "table" then
        return 0
    end
    BurdJournals.Server._customLorePools = BurdJournals.Server._customLorePools or {}
    local count = 0
    for key, raw in pairs(pools) do
        local normalizedKey = normalizeLorePoolKey(key)
        if normalizedKey then
            local values = type(raw) == "table" and (raw.values or raw.items or raw.words) or raw
            local entry = BurdJournals.Server._customLorePools[normalizedKey] or { values = {}, mode = "append" }
            entry.mode = normalizeCustomMode(raw, entry.mode)
            entry.values = mergeCustomArray(entry.values, values, entry.mode == "replace")
            BurdJournals.Server._customLorePools[normalizedKey] = entry
            count = count + #customContentArray(values)
        end
    end
    return count
end

local function applyCustomLoreTemplates(payload)
    local templates = payload.loreTemplates or payload.templates
    if type(templates) ~= "table" then
        return 0
    end
    BurdJournals.Server._customLoreTemplates = BurdJournals.Server._customLoreTemplates or {}
    local count = 0
    for family, rawList in pairs(templates) do
        local familyId = string.lower(tostring(family or ""))
        if familyId ~= "" then
            local values = type(rawList) == "table" and (rawList.values or rawList.items or rawList.templates) or nil
            if type(values) ~= "table" and type(rawList) == "table" and #rawList > 0 then
                values = rawList
            end
            local entry = BurdJournals.Server._customLoreTemplates[familyId] or { values = {}, mode = "append" }
            entry.mode = normalizeCustomMode(rawList, entry.mode)
            if entry.mode == "replace" then
                entry.values = {}
            end
            if type(values) == "table" then
                for key, raw in pairs(values) do
                    local template = copyTemplateEntry(raw, type(key) == "string" and key or nil)
                    if template then
                        entry.values[#entry.values + 1] = template
                        count = count + 1
                    end
                end
            end
            BurdJournals.Server._customLoreTemplates[familyId] = entry
        end
    end
    return count
end

local function applyCustomProfessionGroups(payload)
    local groups = payload.professionGroups or payload.loreProfessionGroups
    if type(groups) ~= "table" then
        return 0
    end
    BurdJournals.Server.LORE_PROFESSION_GROUPS = BurdJournals.Server.LORE_PROFESSION_GROUPS or {}
    local count = 0
    for groupId, raw in pairs(groups) do
        local normalizedGroup = string.lower(tostring(groupId or ""))
        if normalizedGroup ~= "" then
            local group = BurdJournals.Server.LORE_PROFESSION_GROUPS[normalizedGroup] or {}
            if type(raw) == "table" and raw.mode == "replace" then
                group = {}
            end
            local values = type(raw) == "table" and (raw.values or raw.items or raw.professions) or raw
            for _, professionId in ipairs(customContentArray(values)) do
                group[string.lower(professionId)] = true
                count = count + 1
            end
            BurdJournals.Server.LORE_PROFESSION_GROUPS[normalizedGroup] = group
        end
    end
    return count
end

function BurdJournals.Server.getCustomLoreText(key)
    if BurdJournals.ensureCustomContentLoaded then
        BurdJournals.ensureCustomContentLoaded("getCustomLoreText")
    end
    local text = BurdJournals.Server._customLoreTexts and BurdJournals.Server._customLoreTexts[key] or nil
    return BurdJournals.Server.normalizeJournalServerText(text)
end

function BurdJournals.Server.applyCustomLorePoolValues(key, values)
    if BurdJournals.ensureCustomContentLoaded then
        BurdJournals.ensureCustomContentLoaded("applyCustomLorePoolValues")
    end
    local normalizedKey = normalizeLorePoolKey(key)
    local entry = normalizedKey and BurdJournals.Server._customLorePools and BurdJournals.Server._customLorePools[normalizedKey] or nil
    if type(entry) ~= "table" then
        return values
    end
    local out = {}
    if entry.mode ~= "replace" then
        for _, value in ipairs(values or {}) do
            out[#out + 1] = value
        end
    end
    return mergeCustomArray(out, entry.values, false)
end

function BurdJournals.Server.applyCustomLoreTemplatePool(family, basePool)
    if BurdJournals.ensureCustomContentLoaded then
        BurdJournals.ensureCustomContentLoaded("applyCustomLoreTemplatePool")
    end
    local familyId = string.lower(tostring(family or "worn"))
    local entry = BurdJournals.Server._customLoreTemplates and BurdJournals.Server._customLoreTemplates[familyId] or nil
    if type(entry) ~= "table" then
        return basePool
    end
    local out = {}
    if entry.mode ~= "replace" then
        for _, template in ipairs(basePool or {}) do
            out[#out + 1] = template
        end
    end
    for _, template in ipairs(entry.values or {}) do
        out[#out + 1] = template
    end
    return out
end

function BurdJournals.applyCustomContentPayload(payload, sourceTag)
    if type(payload) ~= "table" then
        return nil
    end
    local summary = {
        source = sourceTag or "unknown",
        texts = applyCustomTextBlock(payload),
        names = applyCustomNames(payload),
        professions = applyCustomProfessions(payload),
        pools = applyCustomLorePools(payload),
        templates = applyCustomLoreTemplates(payload),
        groups = applyCustomProfessionGroups(payload),
    }
    BurdJournals._customContentSummary[#BurdJournals._customContentSummary + 1] = summary
    return summary
end

function BurdJournals.ensureCustomContentLoaded(sourceTag)
    if BurdJournals._customContentLoaded or BurdJournals._customContentLoading then
        return BurdJournals._customContentLoaded
    end
    BurdJournals._customContentLoading = true
    local loaded = 0
    for _, filename in ipairs(getCustomContentCandidateFiles()) do
        local payload = readCustomContentFile(filename)
        if type(payload) == "table" then
            local summary = BurdJournals.applyCustomContentPayload(payload, filename)
            if summary then
                loaded = loaded + 1
                BurdJournals._customContentSources[#BurdJournals._customContentSources + 1] = filename
                bsjWriteLogLine("[BurdJournals][CustomContent] loaded "
                    .. tostring(filename)
                    .. " texts=" .. tostring(summary.texts)
                    .. " names=" .. tostring(summary.names)
                    .. " professions=" .. tostring(summary.professions)
                    .. " pools=" .. tostring(summary.pools)
                    .. " templates=" .. tostring(summary.templates)
                    .. " groups=" .. tostring(summary.groups))
            end
        end
    end
    BurdJournals._customContentLoaded = true
    BurdJournals._customContentLoading = false
    if loaded <= 0 then
        BurdJournals.debugPrint("[BurdJournals] Custom content: no external JSON loaded (" .. tostring(sourceTag or "startup") .. ")")
    end
    return true
end

function BurdJournals.Server.countLoreSentences(text)
    local count = 0
    local source = tostring(text or "")
    for _ in source:gmatch("[%.%!%?]+") do
        count = count + 1
    end
    if count == 0 and BurdJournals.Server.normalizeJournalServerText(source) then
        count = 1
    end
    return count
end

function BurdJournals.Server.trimLoreToMaxSentences(text, maxSentences)
    local normalized = BurdJournals.Server.normalizeJournalServerText(text)
    if not normalized then
        return nil
    end

    local maxCount = math.max(1, tonumber(maxSentences) or 8)
    local pieces = {}
    local sentenceCount = 0
    local lastEnd = 1

    for endIndex in normalized:gmatch("()[%.%!%?]+") do
        local stop = endIndex
        pieces[#pieces + 1] = normalized:sub(lastEnd, stop)
        sentenceCount = sentenceCount + 1
        lastEnd = stop + 1
        if sentenceCount >= maxCount then
            break
        end
    end

    if #pieces == 0 then
        return normalized
    end
    if sentenceCount < maxCount then
        return normalized
    end

    return BurdJournals.Server.normalizeJournalServerText(table.concat(pieces, " "))
end

BurdJournals.Server.LORE_NOTE_TEMPLATE_VERSION = tonumber(BurdJournals.Server and BurdJournals.Server.LORE_NOTE_TEMPLATE_VERSION) or 1
LORE_DYNAMIC_VERSION = tonumber(BurdJournals.Server.LORE_NOTE_TEMPLATE_VERSION) or 1

