BurdJournals.Server.LORE_TEMPLATE_SETS = BurdJournals.Server.LORE_TEMPLATE_SETS or {
    worn = {
        {
            key = "UI_BurdJournals_LoreTemplate_WornPages",
            fallback = "If {{openerName}} finds this, {{authorName}} meant the pages to outlast them. I kept {{entryName}} notes behind {{stashNoun}} after {{noun}} {{verb}} {{adverb}}.",
            professionGroups = {"trades", "outdoors", "medical"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornTrade",
            fallback = "I meant to trade {{recipeName}} with {{survivorName}} before the roads closed. If {{openerName}} reads this now, keep moving. {{exclamation}}.",
            professionGroups = {"trades", "food", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornProfession",
            fallback = "Being a {{professionName}} taught me {{skillNameA}}, but {{traitName}} kept me breathing when things got {{adjective}}. The rest is in the margins.",
            professionGroups = {"medical", "combat", "fitness"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornWarning",
            fallback = "{{authorName}} wrote this after a run through {{dangerNoun}} for {{recipeName}} went bad. Trust {{skillName}} more than the map, and never follow {{noun}} {{adverb}}.",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornQuarantine",
            fallback = "The television kept calling it a disturbance, then an exclusion zone, then nothing at all. {{authorName}} wrote down every broadcast that still came through, especially the ones that mentioned soldiers, roadblocks, and the smell drifting out of Knox County. None of it matched what I saw from the windows.\n\nI was a {{professionName}} before the phones died, so I tried to keep this practical: {{entryNameA}} first, {{entryNameB}} second, and only trust {{supplyNoun}} if you packed it yourself. If {{openerName}} finds these pages, remember that the official voices sounded calm right up until they stopped.",
            professionGroups = {"medical", "combat", "trades"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornRoadblock",
            fallback = "We reached the checkpoint before dawn and the line already stretched past {{noun}}. A man in uniform said the sickness was contained; another had blood on his sleeve and would not look at the families begging to cross. {{survivorName}} said they knew earlier than they admitted, because nobody builds that many barricades overnight.\n\nI do not know if it was the air, the water, or something buried under a lab with no name. I only know {{skillNameA}} kept us alive longer than hope did, and the note on {{recipeName}} belongs to whoever can still use both hands.",
            professionGroups = {"combat", "outdoors", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornRadioLog",
            fallback = "{{authorName}} kept a broadcast log until the voices started repeating yesterday's weather. The emergency station told us to shelter, the governor told us to cooperate, and one exhausted reporter told us the roads south were already gone before someone cut her microphone.\n\nI wrote the useful parts in plain language: {{entryNameA}} for the hands, {{entryNameB}} for the head, and {{supplyNoun}} if you can find any. If {{openerName}} hears a calm voice promising evacuation, check whether the voice is breathing.",
            professionGroups = {"trades", "medical", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornSchoolhouse",
            fallback = "The school became a shelter because it had brick walls, wide doors, and enough chairs to pretend this was temporary. By the third night, {{dangerNoun}} was outside and nobody wanted to say the children were quieter than the adults.\n\nI was only a {{professionName}}, not a leader, but I learned which rooms locked and which windows lied. {{skillName}} mattered more than speeches, {{recipeName}} mattered more than prayer, and {{traitName}} was the sort of thing people noticed after the lights went out.",
            professionGroups = {"medical", "food", "trades"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornBackRoad",
            fallback = "{{survivorName}} said the state roads were traps, so we followed fence lines and mailboxes until the map stopped admitting we existed. Every farmhouse had the same story: one door kicked in, one radio left on, one pot gone cold on the stove.\n\nFor {{openerName}}, the route notes are useless now, but the practice is not. Trust {{skillNameA}}, keep {{entryNameB}} dry, and never assume {{noun}} is empty just because it looks {{adjective}}.",
            professionGroups = {"outdoors", "stealth", "fitness"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornClinic",
            fallback = "The clinic smelled like bleach, sweat, and lies. They told us bites were panic injuries. They told us fever was stress. They told us the coughing people in the back room were being transferred, but the ambulance never moved.\n\n{{authorName}} wrote these notes between shifts because hands need something to do when belief runs out. Use {{skillName}} first, use {{recipeName}} if supplies hold, and do not let {{traitName}} make you generous with masks.",
            professionGroups = {"medical"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornStorefront",
            fallback = "The first riot was not for guns. It was for batteries, formula, and anything with a pull tab. {{authorName}} watched a man trade wedding rings for {{supplyNoun}} while the radio insisted supply lines were stable.\n\nI wrote this after we shuttered the storefront and counted what was left. {{entryNameA}} is what I wish I knew before the shelves emptied. {{entryNameB}} is what I learned after {{noun}} {{verb}} {{adverb}}.",
            professionGroups = {"food", "trades", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornStorm",
            fallback = "Rain made everything worse. It hid the footsteps, washed chalk marks off doors, and turned the ditch by {{noun}} into soup thick enough to keep secrets. By morning, the dead were cleaner than the living.\n\nIf {{openerName}} finds the dry pages, start with {{skillName}}. The rest is just weather and stubbornness, except for the note about {{recipeName}}. That one kept {{survivorName}} alive one more day.",
            professionGroups = {"outdoors", "fitness", "trades"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornChurchBasement",
            fallback = "The church basement filled before the sanctuary did. People trusted concrete more than stained glass once {{dangerNoun}} reached the steps, and the preacher traded sermons for inventory lists by candlelight.\n\n{{authorName}} wrote these pages beside {{stashNoun}} while the radio upstairs promised order. Keep {{entryNameA}} close, copy {{entryNameB}} if the page tears, and remember that locked doors make neighbors honest.",
            professionGroups = {"medical", "food", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornDepot",
            fallback = "The bus depot became a place for people who almost left. Suitcases stayed packed, tickets stayed in pockets, and every schedule board kept insisting another departure was due. {{survivorName}} laughed at that until {{noun}} {{verb}} by the vending machines.\n\nFor {{openerName}}, the route is gone but the method remains. {{skillName}} gets you through crowds, {{recipeName}} gets you through hunger, and {{traitName}} is useful only if it does not make you loud.",
            professionGroups = {"stealth", "fitness", "food"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornPharmacyLine",
            fallback = "The pharmacy line wrapped around the building before sunrise. People coughed into sleeves, into scarves, into the hands they used to push each other when the shutters did not open. A deputy said medicine was being distributed fairly, then slipped a bag to his cousin.\n\nI wrote this after fairness became a rumor. {{entryNameA}} may help {{openerName}} more than a bottle ever did, and {{entryNameB}} is what I wish I knew before {{supplyNoun}} became currency.",
            professionGroups = {"medical", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornRailYard",
            fallback = "The rail yard smelled like diesel, rain, and old promises. Someone said military trains had moved through at night before the broadcasts changed. Someone else said the cars were empty. Nobody wanted to explain the fresh chains.\n\n{{authorName}} kept notes under {{stashNoun}} because paper is lighter than proof. If {{openerName}} can use {{skillName}}, use it quietly. If {{recipeName}} looks foolish now, wait until the pantry is empty.",
            professionGroups = {"trades", "stealth", "outdoors"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornWaterTower",
            fallback = "We climbed the water tower to see where the fires stopped. They did not stop. Smoke marked farms, subdivisions, and one place by the highway where headlights still circled like moths around a bad idea.\n\nThe view made {{authorName}} practical. {{entryNameA}} became a checklist, {{entryNameB}} became a warning, and {{supplyNoun}} became the difference between plans and prayers. If {{openerName}} climbs, count ladders before horizons.",
            professionGroups = {"outdoors", "fitness", "trades"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornDinerShift",
            fallback = "The diner stayed open longer than sense allowed. Coffee made people brave, pancakes made them human, and the bell over the door made everyone reach for something sharp. {{survivorName}} kept saying normal would come back hungry.\n\nIt did not. I left {{skillName}} in the margin beside the old specials and folded {{recipeName}} into the register tape. If {{openerName}} finds the place, do not eat anything from the fridge unless you enjoy regret.",
            professionGroups = {"food", "trades"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornCountyMap",
            fallback = "We pinned the county map to drywall and stabbed it full of guesses. Red for blocked roads, blue for water, black for places nobody came back from. By Friday, black was winning.\n\n{{authorName}} wrote what the map could not. {{entryNameA}} is for moving, {{entryNameB}} is for stopping, and {{traitName}} is for knowing which one you are doing before {{dangerNoun}} decides for you.",
            professionGroups = {"outdoors", "combat", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornMotelRoom",
            fallback = "Room 12 had two beds, one working lamp, and a Bible hollowed out for bullets. The guest book said people came from Louisville, Muldraugh, and places they did not want written down after the fence went up.\n\nI was a {{professionName}} before I was a room number. {{skillName}} kept me useful, {{recipeName}} kept me busy, and {{exclamation}} is what I wrote on the mirror before we left.",
            professionGroups = {"combat", "stealth", "trades"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornLibrary",
            fallback = "The library was quiet in a way that felt expensive. People took medical books first, then maps, then anything thick enough to tape over windows. The children hid in the genealogy aisle because family names felt protective.\n\n{{authorName}} copied {{entryNameA}} from memory and tucked {{entryNameB}} between county records. If {{openerName}} finds this, return nothing. Late fees are a luxury.",
            professionGroups = {"medical", "trades", "food"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornTrailerPark",
            fallback = "The trailer park organized faster than city hall. Folks knew who had tools, who had fuel, and who would steal both if left alone. We strung cans on wire and called it infrastructure.\n\n{{survivorName}} taught me that {{skillName}} matters most when nobody is impressed by it. I added {{recipeName}} after {{noun}} {{verb}} near the mailboxes, and I left {{traitName}} circled because pride gets noisy in thin walls.",
            professionGroups = {"trades", "outdoors", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornFieldHospital",
            fallback = "They put the field hospital on the football field because the bleachers gave people somewhere to watch hope fail. Triage tags moved faster than stretchers, and every mask looked clean until someone spoke through it.\n\nIf {{openerName}} is reading this, use {{entryNameA}} before kindness. Use {{entryNameB}} before panic. {{authorName}} learned both while {{dangerNoun}} waited outside the fence like a patient with no chart.",
            professionGroups = {"medical", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornHardwareStore",
            fallback = "The hardware store sold out of locks before it sold out of hammers. That should have told us plenty. People bought plywood like it was medicine and asked for refunds when the dead did not respect carpentry.\n\n{{authorName}} kept notes by the paint mixer. {{skillName}} is useful, {{recipeName}} is better, and {{supplyNoun}} is worth more than cash if {{openerName}} knows where to hide it.",
            professionGroups = {"trades", "combat", "outdoors"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornBirthday",
            fallback = "Somebody had a birthday during the first week and we sang because not singing felt worse. The cake was canned peaches on crackers. The candles were cigarette lighters. The wish was obvious and still did not come true.\n\nI wrote {{entryNameA}} after the song and {{entryNameB}} after the screaming. If {{openerName}} finds this, celebrate small things quickly. They attract attention if they last too long.",
            professionGroups = {"food", "medical", "fitness"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornMadLibsFence",
            fallback = "{{authorName}} watched {{adjective}} {{noun}} {{verb}} {{adverb}} near {{stashNoun}} while {{survivorName}} argued that {{entryNameA}} was more important than {{entryNameB}}.\n\nIf {{openerName}} finds the page, remember this: {{skillName}} gets {{adjective}} when {{dangerNoun}} {{verb}}, {{recipeName}} belongs beside {{supplyNoun}}, and {{exclamation}}.",
            professionGroups = {"outdoors", "stealth", "trades"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornMadLibsCounty",
            fallback = "The county map said nothing about {{omenNoun}}, {{adjective}} {{noun}}, or the way {{supplyNoun}} {{verb}} {{adverb}} whenever the broadcast used the word contained.\n\n{{openerName}} should keep {{entryNameA}} under {{stashNoun}}, trade {{entryNameB}} only for {{supplyNoun}}, and never trust {{traitName}} when the road looks {{adjective}}.",
            professionGroups = {"combat", "outdoors", "medical"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornSkillOnlyNotebook",
            fallback = "{{authorName}} wrote {{skillNameA}} in big block letters because panic makes small writing useless. The second page is {{skillNameB}}, copied twice, once before the sirens and once after.\n\nIf {{openerName}} finds this, practice both before {{dangerNoun}} gets close. A skill remembered late is just regret with better spelling.",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornSkillOnlyRoutine",
            fallback = "Routine kept us human longer than optimism did. Every morning: check doors, count water, repeat {{skillNameA}}, then repeat {{skillNameB}} until the hands know it without permission.\n\n{{openerName}} should not wait to feel ready. Read the notes, move {{adverb}}, and let {{adjective}} fear watch from the porch.",
            professionGroups = {"fitness", "outdoors", "trades"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornSkillOnlyPractice",
            fallback = "The first try at {{skillNameA}} was ugly. The second was louder. By the fifth, {{authorName}} understood that competence is mostly embarrassment survived in private.\n\n{{skillNameB}} came later, after {{noun}} {{verb}} near {{stashNoun}}. If {{openerName}} has time to laugh at the mistakes, there is still time to learn from them.",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornSkillOnlyFieldNotes",
            fallback = "Field note one: {{skillNameA}} works better before you are tired. Field note two: {{skillNameB}} works better before you are scared. Field note three: you will be both.\n\n{{authorName}} left the rest blank for {{openerName}} to fill with better luck. Keep the page dry and the lesson close.",
            professionGroups = {"outdoors", "medical", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornSkillOnlyRadioLesson",
            fallback = "A calm voice on the radio said survival depended on cooperation. Nobody explained how to cooperate with a locked pharmacy, a dead battery, and {{dangerNoun}} by the window.\n\nSo {{authorName}} wrote down {{skillNameA}} and {{skillNameB}} instead. They are less polite than speeches, but {{openerName}} may find them more useful.",
            professionGroups = {"trades", "stealth", "medical"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornMadLibsQuarantine",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornMadLibsRoadblock",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornMadLibsStorm",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornSkillOnlyTrade",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_WornGeneral",
            fallback = "The first week taught {{authorName}} to distrust clean answers. The television called Knox County a disturbance, then a quarantine, then said less and less while the fences said everything. People argued over air, water, meat, a lab, a prank, a punishment. None of the theories opened a locked pharmacy.\n\nIf {{openerName}} finds these pages, keep them dry and keep moving. I wrote what I could as a {{professionName}}, but the most useful lesson is simpler than any trade: count your supplies before hope, and trust the quiet only after it has stayed quiet all night.",
        },
    },
    bloody = {
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyPage",
            fallback = "{{authorName}} did not make it out of {{dangerNoun}}. The bite looked {{adjective}} until my hands {{verb}}. If {{openerName}} is reading this, do not waste the warning.",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyLastWish",
            fallback = "If {{openerName}} found this on me, let {{survivorName}} know {{traitName}} was not enough. Do better with {{entryName}}. {{exclamation}}.",
            professionGroups = {"combat", "outdoors", "medical"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodySupplies",
            fallback = "I lost too much hauling {{supplyNoun}}, but the note on {{skillName}} might still save someone. I wrote it {{adverb}} while {{noun}} {{verb}} downstairs.",
            professionGroups = {"trades", "food", "fitness"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyNearMiss",
            fallback = "There is blood on the page because {{dangerNoun}} got close. Read the part about {{traitName}} and do better before the world gets {{adjective}} again.",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyBroadcast",
            fallback = "Triple-N said the situation was stabilizing while the sirens ran all night. Then came the cough, the fever, the neighbors hammering boards over doors, and the soldiers firing warning shots at people who only wanted to leave. {{authorName}} kept repeating that the news was behind the truth by a whole day, maybe more.\n\nIf this journal is wet, it is not rain. I bled on the page about {{entryNameA}} after dragging {{supplyNoun}} through {{dangerNoun}}, and I underlined {{entryNameB}} because panic makes hands stupid. Tell {{survivorName}} I was still myself when I wrote this.",
            professionGroups = {"medical", "combat", "fitness"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyHazmat",
            fallback = "I saw hazmat suits outside the fence two days before they admitted anything was wrong. They sprayed the road, bagged a dog, and waved rifles at a woman who kept asking why her husband smelled bleach whenever he coughed. That is when {{authorName}} stopped believing in accidents.\n\nThe dead came later. The fear came first. Use the notes on {{recipeName}} and {{skillName}} if your hands are steadier than mine, and do not let {{traitName}} talk you into trusting a clean uniform.",
            professionGroups = {"medical", "trades", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyFenceLine",
            fallback = "The fence did not fail all at once. It sagged in one place, screamed in another, and then a hundred hands found the weak spots like water finding cracks. {{authorName}} was on the wrong side when {{dangerNoun}} pushed through.\n\nThere is not much clean page left. Read {{entryNameA}} before the stain eats it, and if {{openerName}} still has time, copy {{entryNameB}} somewhere drier than my pocket.",
            professionGroups = {"combat", "fitness", "outdoors"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyAmbulance",
            fallback = "The ambulance stalled near {{noun}} with the lights still turning. We thought the siren would bring help. It brought everything else first, and by the time help arrived, help was wearing masks and pointing rifles.\n\nI wrote what I remembered after the bleeding slowed. {{skillName}} for the next person pinned down, {{recipeName}} for the next person hungry enough to risk a store, and {{traitName}} because fear spends itself faster than blood.",
            professionGroups = {"medical", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyKitchen",
            fallback = "The safehouse kitchen became surgery, confession, and court. We boiled water until the windows sweated and pretended the red towels meant we were prepared. {{survivorName}} kept saying the bite was shallow.\n\nIf {{openerName}} finds this, do not believe shallow. Learn {{skillNameA}}, use {{supplyNoun}} sparingly, and burn anything that starts to smell {{adjective}}.",
            professionGroups = {"medical", "food"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyGasStation",
            fallback = "Everybody needed fuel, so everybody came armed. The pumps clicked dry before noon, but people kept squeezing the handles like mercy might be hiding in the hose. {{authorName}} got cut when {{noun}} {{verb}} and the crowd decided sound meant supplies.\n\nI left notes on {{entryNameA}} and {{entryNameB}} because those were worth more than gasoline by dusk. If you see lights at a station, circle wide.",
            professionGroups = {"trades", "combat", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyBasement",
            fallback = "We used the basement because it had no windows. That was the problem and the comfort. When {{dangerNoun}} found the stairs, every sound became bigger in the dark, and every apology arrived too late.\n\n{{authorName}} wrote this by flashlight with one hand wrapped in a shirt. {{skillName}} is the useful part. {{recipeName}} is the hopeful part. The rest is just proof that I tried.",
            professionGroups = {"stealth", "fitness", "trades"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyTrainTracks",
            fallback = "We followed the tracks because trains felt honest. Rails go somewhere, even when roads lie. Then we found the cars stopped outside Knox, doors chained from the outside, and {{dangerNoun}} moving inside them like cargo that learned to hate.\n\nI bled on the page about {{entryNameA}}, but the note still reads. Keep {{entryNameB}} in your head, keep {{supplyNoun}} in your bag, and do not sleep near metal that rings at night.",
            professionGroups = {"outdoors", "stealth", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyRoadShoulder",
            fallback = "The shoulder of the road was full of almosts: almost escaped, almost rescued, almost enough fuel. {{authorName}} crawled under {{noun}} after the shooting started and wrote with blood because the pen was gone.\n\n{{openerName}} should read {{entryNameA}} before checking the glove boxes. {{entryNameB}} can wait until the road is quiet, which is to say it cannot wait at all.",
            professionGroups = {"combat", "outdoors", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyFirehouse",
            fallback = "The firehouse doors were open and the trucks were gone. Someone had painted HELP on the floor in letters big enough for a helicopter that never came. The stain through the P was mine.\n\nI left {{skillName}} because somebody will need hands that know what to do. I left {{recipeName}} because smoke and hunger make cowards of everyone. Tell {{survivorName}} the siren still worked.",
            professionGroups = {"medical", "combat", "trades"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyGroceryAisle",
            fallback = "Aisle six was soup, beans, and screaming. The lights flickered just enough to make every person look dead twice. {{supplyNoun}} rolled under the shelves while people fought over things they did not know how to cook.\n\nIf {{openerName}} finds this in the red bag, use {{entryNameA}} first. {{entryNameB}} is written on the receipt because the clean pages stuck together.",
            professionGroups = {"food", "stealth", "fitness"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyBridge",
            fallback = "They blocked the bridge with buses and called it containment. Then the buses caught fire, the river took the ash, and people tried swimming with backpacks full of cans. {{authorName}} made it halfway back.\n\nThese pages are lighter than supplies. Keep {{skillName}} in your head, keep {{traitName}} from choosing for you, and do not trust bridges that still have soldiers on only one side.",
            professionGroups = {"combat", "fitness", "outdoors"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyLaundry",
            fallback = "The laundromat was a bad place to hide but a good place to bleed. Machines thumped with clothes nobody would claim, and the front window showed {{dangerNoun}} reflected behind us before we heard it.\n\n{{authorName}} used a dryer sheet to blot the page. {{entryNameA}} survived. {{entryNameB}} smells like soap and pennies. If {{openerName}} laughs at that, good. Laughing means you still can.",
            professionGroups = {"stealth", "trades"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyBarn",
            fallback = "The barn doors held until the horse panicked. After that, everything was hooves, teeth, and people shouting names into dust. {{survivorName}} kept saying animals know sickness before we do.\n\nI believe it now. Read {{skillName}} if you plan to run fences. Read {{recipeName}} if you plan to stay. Avoid {{noun}} when it looks {{adjective}}, even if it used to love you.",
            professionGroups = {"outdoors", "fitness", "food"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyPoliceTape",
            fallback = "Police tape looks official until it is wrapped around a wound. We used it for doors, wrists, and one man who promised he was only scratched. {{authorName}} wrote beside him until his breathing changed.\n\n{{openerName}} gets the lessons without the argument: {{entryNameA}} before pity, {{entryNameB}} before sleep, and {{exclamation}} if anybody says procedure will save us.",
            professionGroups = {"combat", "medical"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyWarehouse",
            fallback = "The warehouse had everything except enough doors. Pallets became walls, forklifts became barricades, and inventory sheets became lists of who was missing after each noise. {{noun}} {{verb}} in the loading bay and the whole place answered.\n\nI wrote {{skillName}} while hiding behind dog food. {{recipeName}} is on the back page. If {{openerName}} finds a key ring, do not trust any key that shines.",
            professionGroups = {"trades", "stealth", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyCampground",
            fallback = "The campground looked peaceful until you counted the tents from inside out. Smoke from wet firewood covered the smell for a while, then the rain stopped and honesty came back.\n\n{{authorName}} put {{entryNameA}} in this journal after losing the map. {{entryNameB}} is for anyone who thinks trees make them safe. Trees mostly give things somewhere to stand.",
            professionGroups = {"outdoors", "stealth", "fitness"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyApartmentStairs",
            fallback = "Apartment stairs are funnels. We learned that after the third floor started screaming and everyone above us tried to become everyone below us. {{survivorName}} fell near the landing and still told me to write.\n\nSo I wrote {{skillName}} with shaking hands. I wrote {{recipeName}} when the hall went quiet. I wrote {{traitName}} because courage is mostly timing with better manners.",
            professionGroups = {"fitness", "combat", "medical"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyDriveIn",
            fallback = "The drive-in screen kept showing a comedy with no sound. People watched from locked cars while the world outside learned to tap on glass. It would have been funny if the blood had not reached the projector booth.\n\n{{openerName}}, use {{entryNameA}} when the lot fills up. Use {{entryNameB}} when the battery dies. Do not sit through the credits.",
            professionGroups = {"stealth", "trades", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyMeatLocker",
            fallback = "The meat locker was cold enough to keep secrets but not cold enough to keep the dead polite. We shut three inside and argued whether they were people until one started knocking in code.\n\n{{authorName}} left {{skillName}} here because practical things do not care what you call the problem. {{recipeName}} is tucked behind the invoice. If {{openerName}} smells thawing meat, leave.",
            professionGroups = {"food", "medical", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyOverpass",
            fallback = "From the overpass, the highway looked like a necklace snapped across the county. Headlights, luggage, smoke, and one school bus rocking long after the children stopped crying.\n\nI bled on {{entryNameA}} but the words held. {{entryNameB}} is cleaner. If {{openerName}} has to cross open road, do it {{adverb}} and never stop for a suitcase unless it calls your name.",
            professionGroups = {"outdoors", "fitness", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyMadLibsStain",
            fallback = "The blood dried {{adverb}} around a {{adjective}} note about {{entryNameA}}. Beside it, {{noun}} {{verb}} like it understood {{traitName}}, and {{dangerNoun}} answered with {{supplyNoun}} in its teeth.\n\n{{openerName}}, copy {{entryNameB}} before the stain gets {{adjective}}. If {{recipeName}} starts looking back, say {{exclamation}} and run.",
            professionGroups = {"combat", "medical", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyMadLibsPocket",
            fallback = "{{authorName}} stuffed {{supplyNoun}}, {{stashNoun}}, and one {{adjective}} {{noun}} into a coat pocket before {{dangerNoun}} {{verb}} {{adverb}}.\n\nThe pocket tore. The page stayed. Learn {{skillName}}, respect {{traitName}}, and never let {{recipeName}} distract you from a {{adjective}} sound behind the door.",
            professionGroups = {"outdoors", "food", "fitness"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodySkillOnlyHands",
            fallback = "{{authorName}} wrote {{skillNameA}} with one clean hand and one hand that would not stop shaking. The page about {{skillNameB}} is worse, but the meaning survived.\n\nIf {{openerName}} reads this, start before the blood dries. Practice is kinder than necessity.",
            professionGroups = {"medical", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodySkillOnlyLastLesson",
            fallback = "Last lesson: {{skillNameA}} saves more time than bravery. Next lesson: {{skillNameB}} saves more noise than luck. Final lesson: learn before {{dangerNoun}} teaches you itself.\n\nThe rest of the page is red. {{openerName}} can still use the clean parts.",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodySkillOnlyFloor",
            fallback = "The journal slid under {{noun}} when everything went bad. {{authorName}} reached it after the screaming stopped and circled {{skillNameA}} so hard the paper tore.\n\n{{skillNameB}} is written on the back in smaller letters. It may not look important until {{openerName}} is on the floor too.",
            professionGroups = {"fitness", "stealth", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodySkillOnlyBandage",
            fallback = "Bandages run out. Tape runs out. Clean water runs out. What stayed useful was {{skillNameA}}, then {{skillNameB}}, then whatever stubborn part of the body kept obeying.\n\n{{authorName}} left this for {{openerName}} because a learned thing weighs nothing and cannot be stolen from your pack.",
            professionGroups = {"medical", "outdoors"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodySkillOnlyDoor",
            fallback = "There was a door, then a mistake, then a lesson. {{skillNameA}} was the lesson before the door opened. {{skillNameB}} was the lesson after.\n\nIf {{openerName}} has a door in front of them now, pause. The dead are patient, but they are not clever. That leaves clever to you.",
            professionGroups = {"stealth", "combat", "trades"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyMadLibsFence",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyMadLibsGasStation",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyMadLibsRoad",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodySkillOnlyAmbulance",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodySkillOnlyBroadcast",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodySkillOnlyFence",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodySkillOnlyKitchen",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodySkillOnlyOverpass",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_BloodyGeneral",
            fallback = "{{authorName}} tried to keep the blood off the useful pages. That was easier before the sirens stopped and every road out of Knox County turned into uniforms, headlights, and people begging to be believed. The official voices kept changing their story, but the fever never changed its work.\n\nIf {{openerName}} is reading this, do not waste time wondering which rumor was true. Pack what you can carry, watch the living as carefully as the dead, and remember that panic makes even familiar streets feel hungry.",
        },
    },
    yuletide = {
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideWarm",
            fallback = "This was wrapped for {{openerName}} with one last bit of {{adjective}} mercy. Keep {{supplyNoun}} close and make it through the week. {{exclamation}}.",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideMercy",
            fallback = "Santa marked {{survivorName}} down for {{traitName}} and a little mercy. The note on {{recipeName}} should help when {{noun}} {{verb}} {{adverb}}.",
            professionGroups = {"medical", "outdoors", "food"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideProfession",
            fallback = "Even a {{professionName}} needs warmth. Keep {{supplyNoun}} close and read the part on {{entryName}} first.",
            professionGroups = {"trades", "medical", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideGift",
            fallback = "I wrapped this so {{openerName}} would have one honest thing left this winter. Use {{recipeName}} before it spoils, and be {{adjective}} about it.",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideEvacuation",
            fallback = "Ho ho no. The old routes are gone, the radios lie, and every chimney in Knox County sounds like something hungry testing the bricks. I found {{survivorName}}'s list beside {{supplyNoun}} and added what I could before the sleigh bells turned into sirens.\n\nFor {{openerName}}, this is not charity. It is a field manual with ribbon on it. Read {{entryNameA}} before nightfall, keep {{entryNameB}} for when the roads ice over, and leave one light burning only if you can afford visitors.",
            professionGroups = {"outdoors", "food", "trades"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideNiceList",
            fallback = "The nice list is mostly ash now, but somebody kept doing the work. I saw barricades where parades used to be, aid stations with no nurses left, and children drawing snowmen on quarantine notices because no one knew what else to give them.\n\nSo I wrapped these pages for {{openerName}}. {{skillName}} is the practical gift, {{recipeName}} is the one you open when the cupboards go quiet, and {{traitName}} is the reminder that surviving the holidays still counts as a miracle.",
            professionGroups = {"medical", "food", "fitness"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideRooftop",
            fallback = "The rooftops were safer before the snow started showing footprints that led nowhere. Santa saw {{authorName}} leave {{supplyNoun}} under a plastic tree and call it tradition. That counts.\n\nFor {{openerName}}, these pages are wrapped in the only paper I could find. {{entryNameA}} is for surviving the cold, {{entryNameB}} is for surviving the living, and the ribbon is mostly there to keep the blood off.",
            professionGroups = {"outdoors", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideMall",
            fallback = "The mall music never stopped. It played over broken glass, evacuation notices, and a food court full of chairs pushed against doors. {{survivorName}} laughed once because the song wished us joy while {{dangerNoun}} waited by the escalator.\n\nI left {{skillName}} and {{recipeName}} in this gift because practical miracles are still miracles. If {{openerName}} finds batteries for the speaker, turn it off.",
            professionGroups = {"food", "trades", "fitness"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideWorkshop",
            fallback = "The workshop is not at the North Pole this year. It is any garage with a locked door, any kitchen with a sharp knife, any clinic with one clean bandage left. Good people make gifts out of whatever keeps someone breathing.\n\nSo here: {{entryNameA}}, {{entryNameB}}, and a little note saying {{exclamation}}. {{openerName}} can decide which part is festive.",
            professionGroups = {"trades", "medical", "food"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideChimney",
            fallback = "Do not use chimneys anymore. Smoke draws eyes, bells draw teeth, and every rooftop in town sounds like claws if you listen too long. {{authorName}} learned that after {{noun}} {{verb}} {{adverb}}.\n\nThe gift is simple: read {{skillName}}, remember {{traitName}}, and keep {{supplyNoun}} where cold hands can find it. Naughty and nice stopped mattering when the dead learned both lists.",
            professionGroups = {"outdoors", "stealth", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideShelter",
            fallback = "Someone hung stockings in the shelter because children were watching. By morning, the stockings held ration crackers, loose nails, and one note from {{survivorName}} asking Santa to bring the phones back.\n\nI could not manage that. I could manage {{entryNameA}} and {{entryNameB}}. If {{openerName}} finds these pages, give someone else the warm corner when you can afford it.",
            professionGroups = {"medical", "food", "trades"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideSnowplow",
            fallback = "The snowplow made it farther than the convoy. It shoved cars, luggage, and bad decisions into the ditch until the fuel died near {{noun}}. After that, winter took the road back one inch at a time.\n\n{{openerName}} gets the useful pieces: {{skillName}} for the body, {{recipeName}} for the pot, and {{traitName}} for whatever stubborn part refuses to lie down.",
            professionGroups = {"fitness", "outdoors", "trades"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideCannedHam",
            fallback = "The best gift I saw that year was a canned ham with a bow made from caution tape. {{survivorName}} cried when it opened, not because it was beautiful, but because it was food nobody had to steal.\n\nThis journal is the same kind of gift. {{entryNameA}} fills the hands, {{entryNameB}} fills the head, and {{openerName}} should take both before the holiday spirit starts scratching at the door.",
            professionGroups = {"food", "medical"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideRadioCarol",
            fallback = "A carol played over the emergency band for eleven minutes before a man cut in and begged someone to let his family through the fence. Then the song started again from the first verse like nothing had happened.\n\nSanta heard it. So did {{authorName}}. The gift for {{openerName}} is {{skillName}}, {{recipeName}}, and the advice to turn the dial if the music knows your name.",
            professionGroups = {"trades", "medical", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideToyStore",
            fallback = "The toy store was untouched because nobody wanted to admit children still existed. We took batteries, blankets, and one stuffed rabbit that smelled like smoke. {{noun}} {{verb}} in the back room and every music box started at once.\n\n{{openerName}} can have the notes on {{entryNameA}} and {{entryNameB}}. Leave the toys unless you need something soft enough to remember mercy.",
            professionGroups = {"stealth", "trades", "medical"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideNaughtyList",
            fallback = "The naughty list used to be a joke. Then the checkpoints started sorting people into useful, exposed, infected, and gone. Santa's handwriting looked kinder than the army forms, but both lists knew where you lived.\n\nI wrapped {{entryNameA}} because {{openerName}} might deserve a chance. I wrapped {{entryNameB}} because deserving stopped being the measure once the snow turned red.",
            professionGroups = {"combat", "stealth", "fitness"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideSoupKitchen",
            fallback = "The soup kitchen kept ladling until the pot was mostly water and hope. People said thank you like manners could keep the fever out. {{authorName}} wrote names on cups so the living could feel counted.\n\nFor {{openerName}}, these pages are hot soup in paper form: {{skillName}} first, {{recipeName}} second, and {{traitName}} if you can carry it without spilling.",
            professionGroups = {"food", "medical"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideTreeFarm",
            fallback = "The tree farm smelled so normal it hurt. Pine, mud, gasoline, and somebody's old thermos coffee. We cut branches for camouflage and pretended the wreaths on the office door were not covering bullet holes.\n\n{{survivorName}} left {{supplyNoun}} there for strangers. I left {{entryNameA}} and {{entryNameB}} for the same reason. If {{openerName}} hears bells in the rows, do not follow them.",
            professionGroups = {"outdoors", "stealth", "trades"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideHospitalWard",
            fallback = "Some nurse hung paper snowflakes in the fever ward. They shook whenever the coughing started, and for a while that was the only weather anyone saw. {{authorName}} kept working after the exits locked.\n\nThis gift is for whoever still opens doors carefully. {{skillName}} may help {{openerName}} live. {{recipeName}} may help someone else. That is close enough to Christmas.",
            professionGroups = {"medical"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideRoofLights",
            fallback = "The rooftop lights came on by timer every night even after the family vanished. They blinked red, green, red, green, inviting every hungry thing on the block to admire the season.\n\n{{authorName}} climbed up to cut the cord and found this journal under the shingles. I added {{entryNameA}} because survival needs maintenance, and {{entryNameB}} because beauty is dangerous when it glows.",
            professionGroups = {"trades", "stealth", "fitness"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideFrozenLake",
            fallback = "The lake froze thin and lied about it. People crossed because the road was worse, dragging sleds full of blankets and cans. The ice made little singing sounds under every mistake.\n\n{{openerName}}, keep {{skillName}} in mind before stepping anywhere white. Keep {{recipeName}} for the far shore. If {{noun}} {{verb}} under the ice, do not look down.",
            professionGroups = {"outdoors", "fitness", "food"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideGiftExchange",
            fallback = "We held a gift exchange with things nobody owned anymore. A screwdriver, two lighters, clean socks, half a bottle of vitamins. {{survivorName}} gave me this journal and asked me to put something useful in it.\n\nSo I did. {{entryNameA}} for the person who opens it first, {{entryNameB}} for the person who survives long enough to need it, and {{exclamation}} for whoever laughs.",
            professionGroups = {"trades", "medical", "food"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletidePostOffice",
            fallback = "The post office kept receiving letters after nobody delivered them. Cards to grandparents, bills, one envelope addressed to Santa in a child's red marker. The dead did not care about mail, which made them poor citizens.\n\nI tucked {{skillName}} and {{recipeName}} behind the sorting bins. If {{openerName}} finds the red envelope, leave it closed. Some wishes deserve privacy.",
            professionGroups = {"stealth", "trades"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideNativity",
            fallback = "The nativity scene outside city hall was missing a shepherd and had gained three sandbags. Somebody tucked ration wrappers in the manger. Somebody else wrote help us where the star should have been.\n\n{{authorName}} left these notes because faith and preparation are not enemies. {{entryNameA}} is practical. {{entryNameB}} is kind. {{openerName}} should try both before deciding which one failed.",
            professionGroups = {"medical", "food", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideBlackout",
            fallback = "The blackout made the holiday lights more precious and more stupid. Every lit window became a promise, every promise became a target, and every target learned to whisper before it broke.\n\nThis package has no batteries, but it has {{entryNameA}} and {{entryNameB}}. That may be better. If {{openerName}} still wants brightness, make it small enough to hide under a coat.",
            professionGroups = {"stealth", "trades", "outdoors"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideMadLibsGift",
            fallback = "Santa wrapped {{adjective}} {{noun}}, {{supplyNoun}}, and a warning that {{omenNoun}} {{verb}} {{adverb}} whenever {{openerName}} looked away.\n\nInside the ribbon: {{entryNameA}} for {{adjective}} mornings, {{entryNameB}} for {{dangerNoun}}, and {{recipeName}} in case {{survivorName}} gets hungry enough to believe in miracles.",
            professionGroups = {"food", "trades", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideMadLibsCarol",
            fallback = "The carol went {{adverb}} through {{noun}} while {{adjective}} snow covered {{stashNoun}}. Every verse ended with {{exclamation}}, which felt festive until {{dangerNoun}} started singing harmony.\n\n{{openerName}} should read {{skillName}} by candlelight, hide {{traitName}} under the wrapping, and save {{entryName}} for the morning after the bells stop.",
            professionGroups = {"medical", "fitness", "outdoors"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideSkillOnlyRibbon",
            fallback = "The ribbon is mostly for morale. The real gift is {{skillNameA}}, written carefully enough for cold fingers, and {{skillNameB}}, written twice because winter makes ink stubborn.\n\n{{openerName}} should open this before the candles burn low. A practical lesson is still a present.",
            professionGroups = {"trades", "medical", "food"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideSkillOnlyStocking",
            fallback = "The stocking held no candy, only folded pages. {{skillNameA}} was tucked in the toe. {{skillNameB}} was pinned near the cuff with a bent safety pin.\n\n{{authorName}} called it a poor holiday. I call it honest. If {{openerName}} survives because of it, the gift worked.",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideSkillOnlySnowLesson",
            fallback = "Snow makes every mistake visible. Footprints, dropped tools, bad routes, panic circles around {{noun}}. {{authorName}} learned {{skillNameA}} by watching what the snow accused them of doing.\n\n{{skillNameB}} came after dark. {{openerName}} should learn both before the next white morning tells on them.",
            professionGroups = {"outdoors", "stealth", "fitness"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideSkillOnlyWorkshop",
            fallback = "Workshop rule: if it keeps someone alive, it is a toy for grownups. {{skillNameA}} belongs on the top shelf. {{skillNameB}} belongs near the door. Everything else is decoration.\n\n{{openerName}} can unwrap the lesson now. No batteries required, no assembly except practice.",
            professionGroups = {"trades", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideSkillOnlyNice",
            fallback = "Nice people share food. Useful people share knowledge. {{authorName}} tried to be both and wrote {{skillNameA}} while the house smelled like smoke.\n\nThe page on {{skillNameB}} is the better gift. {{openerName}} should take it without guilt. Surviving can be polite later.",
            professionGroups = {"medical", "food", "fitness"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideMadLibsEvacuation",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideMadLibsGeneral",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideMadLibsNiceList",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_YuletideGeneral",
            fallback = "This was wrapped because the world kept ending without asking what season it was. Somewhere beyond the fences, someone probably still believed the lights meant safety and the radio meant help. In Knox County, lights draw attention and radios mostly teach you how many ways a calm voice can lie.\n\nFor {{openerName}}, take the gift for what it is: paper, memory, and a little stubborn warmth. Be good if you can. Be alive if you cannot. Either one counts this year.",
        },
    },
    cursed = {
        {
            key = "UI_BurdJournals_LoreTemplate_CursedSeal",
            fallback = "{{openerName}} broke the seal and {{omenNoun}} answered {{adverb}}. {{authorName}} is not the first name it kept.",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedMargin",
            fallback = "{{authorName}} scratched {{recipeName}} in the margin and {{omenNoun}} answered. The debt moved to {{openerName}} when {{noun}} {{verb}}.",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedPrice",
            fallback = "The seal broke because {{traitName}} makes fools brave. Keep the page on {{entryName}} if you want to remember the {{adjective}} price.",
            professionGroups = {"combat", "stealth", "fitness"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedFollower",
            fallback = "I hid this from {{survivorName}}, but {{omenNoun}} followed anyway. It still wants the note on {{recipeName}}. {{exclamation}}.",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedKnoxPrice",
            fallback = "They called it infection because that word fits in a briefing. {{authorName}} called it judgment after {{omenNoun}} appeared in every mirror and the dead began listening for names. The army drew its line around Knox County, but lines only matter to things that respect maps.\n\nThis page remembers {{openerName}} now. Take {{entryNameA}} if you want the lesson, take {{entryNameB}} if you want the warning, and understand that every cure rumor has a price written somewhere smaller than the print.",
            professionGroups = {"medical", "combat", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedExperiment",
            fallback = "{{survivorName}} swore the smell came from a spill, a weapon, a test, anything human enough to blame. I believed that until the margin wrote back. It knew my profession, knew {{traitName}}, and knew which locked doors opened before July Fourth.\n\nIf {{openerName}} can read this without hearing scratching under the paper, use {{skillName}} and {{recipeName}} quickly. The dead are only the loud part of what escaped.",
            professionGroups = {"medical", "trades", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedBroadcast",
            fallback = "The emergency broadcast had a second voice under it. Not an echo. A listener. It repeated {{authorName}}'s name between weather updates and laughed whenever the announcer said contained.\n\n{{openerName}} owns the page now. {{entryNameA}} will help for a while, {{entryNameB}} will help if the road is kind, but {{omenNoun}} already knows which door you prefer.",
            professionGroups = {"stealth", "medical", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedWater",
            fallback = "People blamed the water because water goes everywhere and never testifies. {{survivorName}} boiled it, filtered it, prayed over it, and still dreamed of {{omenNoun}} drinking first.\n\nIf {{openerName}} wants a practical answer, take {{skillName}} and {{recipeName}}. If you want the true answer, ask why the page stays dry when everything else in this county sweats.",
            professionGroups = {"medical", "outdoors", "food"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedCourthouse",
            fallback = "The courthouse burned green for three hours. Nobody mentions that on the radio. They mention disorder, panic, unconfirmed casualties, but not the judge's shadow walking out by itself and pointing toward {{noun}}.\n\nI copied {{entryNameA}} before the ink turned. {{entryNameB}} copied itself. If {{openerName}} sees a signature at the bottom, do not read it aloud.",
            professionGroups = {"combat", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedLabDoor",
            fallback = "There was a door below the clinic that was not on any plan. {{authorName}} found it because {{traitName}} makes people look where they should not. Behind it, {{omenNoun}} breathed like a crowd waiting to be invited.\n\nThe notes on {{skillName}} are clean enough to use. The note on {{recipeName}} has teeth in the margins. Leave that part folded unless hunger wins.",
            professionGroups = {"medical", "trades", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedLedger",
            fallback = "Every name in the ledger had a mark beside it: sick, cleared, missing, useful, owed. {{survivorName}} found {{authorName}} written twice, once in ink and once in something that smelled like pennies.\n\nNow {{openerName}} is in the margin. Use {{entryNameA}} while the page allows it. Hide {{entryNameB}} from mirrors. They read faster than people do.",
            professionGroups = {"combat", "medical", "fitness"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedStormDrain",
            fallback = "The storm drains carried more than rain after the sirens stopped. Whispers came up through the grates near {{noun}}, offering shortcuts, cures, and old names nobody should have known.\n\n{{authorName}} followed one. I found the journal instead. If {{openerName}} keeps it, learn {{skillName}}, forget the whisper, and never trade {{traitName}} for an answer.",
            professionGroups = {"stealth", "outdoors"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedMirror",
            fallback = "The mirror in the motel did not reflect the room after midnight. It reflected the checkpoint, the fence, and {{authorName}} standing in a line that never moved. {{omenNoun}} watched from behind every face.\n\n{{openerName}} can use {{entryNameA}} safely if the glass stays dark. {{entryNameB}} should be read with the mirror covered. Reflections are excellent thieves.",
            professionGroups = {"stealth", "medical"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedSilo",
            fallback = "Something knocked inside the grain silo for three days. Not a person. Not an animal. It knocked in the rhythm of the emergency broadcast and stopped whenever anyone prayed.\n\n{{survivorName}} climbed up with {{supplyNoun}} and came down older. The page on {{skillName}} is theirs. The page on {{recipeName}} is mine. The scratching under both belongs to {{omenNoun}}.",
            professionGroups = {"outdoors", "trades", "food"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedRadioTower",
            fallback = "The radio tower blinked after the power died. Red light, red light, red light, like a heartbeat nobody authorized. Every time it flashed, {{noun}} {{verb}} somewhere closer.\n\nI wrote {{entryNameA}} while counting the flashes and {{entryNameB}} when the count answered back. If {{openerName}} sees the tower from the road, look at your feet instead. It hates being ignored.",
            professionGroups = {"trades", "stealth", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedMeat",
            fallback = "The butcher said the meat came in wrong before people did. Too warm, too sweet, marked with a stamp nobody at the plant recognized. Then customers started asking why it moved when salted.\n\nThe page wants {{openerName}} to blame infection. Do not. Infection does not write recipes in the grease. Take {{skillName}}, take {{recipeName}}, and leave anything that smiles from a hook.",
            professionGroups = {"food", "medical"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedNursery",
            fallback = "The nursery mobiles turned without wind. Ducks, moons, stars, little plastic sheep, all circling over empty cribs while the county alert called for calm. {{authorName}} found names scratched into the paint under each mattress.\n\nOne name is {{openerName}} now. Use {{entryNameA}} while it still looks useful. Use {{entryNameB}} only if the lullaby starts from a room with no children.",
            professionGroups = {"medical", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedConfession",
            fallback = "The confession booth kept whispering after the priest stopped. It knew thefts, lies, checkpoint bargains, and the names people left behind when the road filled with headlights.\n\n{{survivorName}} confessed to surviving. The booth laughed. I wrote {{skillName}} and {{traitName}} because guilt is heavy, but knowledge is portable. {{openerName}} should not kneel unless invited by the living.",
            professionGroups = {"stealth", "medical", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedWell",
            fallback = "The well water was clean until the bucket came up with hair. After that it gave different gifts: teeth, radio parts, a school photograph, one wet page already covered in {{authorName}}'s handwriting.\n\nI added {{entryNameA}} because the page left room. {{entryNameB}} appeared while I slept. If {{openerName}} lowers a bucket, do not ask for water by name.",
            professionGroups = {"outdoors", "medical", "food"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedVotingMachine",
            fallback = "The voting machine in city hall kept printing results after the election was canceled. Sick won by a landslide. Dead took every precinct. One ballot had {{openerName}} written where the office should be.\n\n{{authorName}} took the tape and hid it behind {{stashNoun}}. These notes on {{skillName}} and {{recipeName}} were printed on the back. Democracy has strange handwriting now.",
            professionGroups = {"trades", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedStaticChoir",
            fallback = "There is a choir under the static. You hear it best when the batteries are dying and the room is too tired to lie. It sings numbers, road names, and sometimes the recipe you needed yesterday.\n\n{{openerName}}, take {{entryNameA}} and {{entryNameB}} before the chorus notices. If it harmonizes with your breathing, turn the radio off with a hammer.",
            professionGroups = {"trades", "medical", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedTaxOffice",
            fallback = "The tax office survived the first riots because nobody wanted paperwork at the end of the world. Inside, every filing cabinet had been sorted into sins instead of surnames. {{traitName}} was stamped on more folders than seemed fair.\n\nI found {{authorName}} under penalties due. The notes on {{entryNameA}} were audited. The notes on {{entryNameB}} were forgiven. {{openerName}} should avoid the drawer marked extensions.",
            professionGroups = {"stealth", "trades"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedPuppetShow",
            fallback = "The children's puppet stage in the library performed at noon without hands. It told the Knox story with felt soldiers, paper masks, and a little red moon that swallowed the set.\n\n{{survivorName}} clapped before we could stop them. That is when the journal opened. {{skillName}} is useful. {{recipeName}} is useful. Applause is not.",
            professionGroups = {"medical", "stealth", "food"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedBlackRain",
            fallback = "The rain came down black for nine minutes and left handprints on every car roof. Officials called it soot. The handprints called {{authorName}} by a childhood nickname.\n\nI wrote {{entryNameA}} before the drops dried. {{entryNameB}} bled through from the next page. If {{openerName}} smells smoke during clear weather, keep walking until the sky forgets you.",
            professionGroups = {"outdoors", "combat", "medical"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedElevator",
            fallback = "The elevator in the office building kept opening on floors the building did not have. Basement two smelled like bleach. Basement three smelled like flowers. Basement four had {{omenNoun}} and a clipboard with tomorrow's date.\n\n{{openerName}} should take {{skillName}} from this page and leave the rest in the lobby. If the doors open by themselves, be too busy surviving to step inside.",
            professionGroups = {"trades", "stealth", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedMadLibsMargin",
            fallback = "The margin drew {{adjective}} {{noun}} around {{entryNameA}} until {{omenNoun}} {{verb}} {{adverb}}. Then it asked {{openerName}} for {{supplyNoun}}, {{traitName}}, and a signature in the space where {{authorName}} used to be.\n\nDo not sign. Read {{entryNameB}} if you must. If {{recipeName}} changes shape, whisper {{exclamation}} and close the book.",
            professionGroups = {"stealth", "medical", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedMadLibsDoor",
            fallback = "Behind {{stashNoun}} was a {{adjective}} door. Behind the door, {{dangerNoun}} {{verb}} {{adverb}} with {{noun}} in one hand and {{supplyNoun}} in the other.\n\n{{survivorName}} opened it for {{entryNameA}}. {{authorName}} closed it with {{entryNameB}}. If {{openerName}} hears knocking, count backwards from {{skillName}} and pretend {{traitName}} is not listening.",
            professionGroups = {"trades", "outdoors", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedSkillOnlyInk",
            fallback = "The ink refused every word except {{skillNameA}}. When {{authorName}} tried to write anything else, the page sweated until {{skillNameB}} appeared underneath.\n\n{{openerName}} should learn them in order. The page likes order. It punishes curiosity.",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedSkillOnlyCounting",
            fallback = "Count the dead. Count the doors. Count the lessons. {{skillNameA}} is one. {{skillNameB}} is two. The third count belongs to {{omenNoun}}, so stop early.\n\n{{authorName}} did not stop early. That is why the page has room for {{openerName}}.",
            professionGroups = {"stealth", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedSkillOnlyOffer",
            fallback = "The margin offered power, answers, and the location of every locked pharmacy in Knox County. {{authorName}} chose {{skillNameA}} because it looked least hungry.\n\n{{skillNameB}} chose itself. If {{openerName}} feels the page get warm, close it after the lesson and before the bargain.",
            professionGroups = {"medical", "trades", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedSkillOnlyPractice",
            fallback = "Practice {{skillNameA}} where mirrors cannot watch. Practice {{skillNameB}} where radios cannot listen. If either lesson improves too quickly, thank nobody.\n\n{{authorName}} wrote that warning after {{noun}} {{verb}} {{adverb}}. {{openerName}} should treat it as instruction, not superstition.",
            professionGroups = {"stealth", "fitness", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedSkillOnlyName",
            fallback = "{{skillNameA}} was written in {{authorName}}'s hand. {{skillNameB}} was written in mine. I had not opened the journal yet.\n\nIf {{openerName}} sees their own handwriting later, do not correct the spelling. The page enjoys attention.",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedMadLibsStatic",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedMadLibsWater",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedMadLibsWell",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_CursedGeneral",
            fallback = "{{openerName}} broke the seal, and the page remembered. They called it infection because infection fits inside reports, fences, and orders shouted through masks. Curse is an older word. It explains why the dead listen when no one speaks.\n\n{{authorName}} wrote this before the ink began correcting itself. If the margin offers you a bargain, count your fingers, count your memories, and ask why the government needed guns to contain something it insisted was only sickness.",
        },
    },
    krampus = {
        {
            key = "UI_BurdJournals_LoreTemplate_KrampusTallied",
            fallback = "{{openerName}} was marked when the wrapping split. {{omenNoun}} never needed a second invitation, only a {{adjective}} one.",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_KrampusSnow",
            fallback = "Krampus kept the page on {{skillName}} and left the rest to the snow. {{survivorName}} should have listened when {{noun}} {{verb}}.",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_KrampusBundle",
            fallback = "The bundle was meant for {{openerName}}, not as a gift but a warning. {{omenNoun}} never forgets a debt. {{exclamation}}.",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_KrampusBargain",
            fallback = "Even a {{professionName}} cannot bargain with {{omenNoun}}. Take the note on {{entryName}} and run {{adverb}}.",
            professionGroups = {"combat", "outdoors", "trades"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_KrampusCheckpoints",
            fallback = "Krampus found the checkpoints first. He liked the lists, the stamped passes, the names crossed out by men pretending paperwork could hold back punishment. {{authorName}} saw boot prints in the snow that did not belong to any soldier.\n\nThis bundle is for {{openerName}} because the road still wants payment. Learn {{entryNameA}}, keep {{entryNameB}}, and do not answer if the radio uses your childhood name.",
            professionGroups = {"combat", "stealth", "outdoors"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_KrampusBroadcast",
            fallback = "The broadcast said stay indoors. The voice behind it said be good. Then the signal bent, {{omenNoun}} laughed through the static, and every bad thing we had done felt tall enough to cast a shadow.\n\n{{survivorName}} left these notes before the wrapping sealed itself again. {{skillName}} may keep you warm, {{recipeName}} may keep you fed, but {{traitName}} will decide whether the winter lets you pass.",
            professionGroups = {"food", "fitness", "medical"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_KrampusSchoolList",
            fallback = "The school had two lists on the bulletin board: children accounted for, children missing. Krampus added a third in careful red ink. It was only adults, and every name had made a decision at the checkpoint.\n\n{{openerName}} does not need to know which list this journal came from. Learn {{entryNameA}}, carry {{entryNameB}}, and do not laugh if bells ring from an empty classroom.",
            professionGroups = {"medical", "combat", "stealth"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_KrampusTollBooth",
            fallback = "The toll booth kept taking payment after the road closed. Coins, teeth, wedding rings, confessions. {{authorName}} said the basket was empty every morning and full of frost by noon.\n\nThis gift passed through that booth. {{skillName}} is yours, {{recipeName}} is borrowed, and {{traitName}} may be collected later if {{omenNoun}} decides you underpaid.",
            professionGroups = {"stealth", "outdoors", "combat"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_KrampusCoal",
            fallback = "Coal would have been kinder. The package left soot on {{survivorName}}'s hands and a smell like old churches after rain. Inside were notes, a ribbon, and a warning that changed words whenever nobody watched.\n\nFor {{openerName}}: {{entryNameA}} first, {{entryNameB}} second, and no bargains after sundown. If {{noun}} {{verb}} {{adverb}}, pretend you heard nothing.",
            professionGroups = {"trades", "fitness", "food"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_KrampusParade",
            fallback = "The Christmas parade floats were still parked downtown when the quarantine line went up. By the time {{dangerNoun}} reached Main Street, the papier-mache reindeer had real antlers tied to them and nobody admitted doing it.\n\n{{authorName}} found this journal under the sleigh. I added {{skillName}} because survival is a better gift than spectacle, and {{recipeName}} because hunger makes every holiday honest.",
