            professionGroups = {"outdoors", "combat", "food"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_KrampusSkillOnlyWrapping",
            fallback = "The wrapping paper showed tiny sleighs circling a county map. Every route ended at the same black square. Inside, {{skillNameA}} and {{skillNameB}} were the only things not crossed out.\n\n{{openerName}} should take that as generosity. Or threat. The difference is mostly timing.",
            professionGroups = {"stealth", "outdoors", "trades"},
        },
        {
            key = "UI_BurdJournals_LoreTemplate_KrampusMadLibsBell",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_KrampusMadLibsBundle",
        },
        {
            key = "UI_BurdJournals_LoreTemplate_KrampusMadLibsCoal",
        },
        {
