function BurdJournals.Server.getCursedEffectCategory(effectType)
    if CURSE_SEVERE_EFFECT_TYPES[effectType] == true then
        return "severe"
    end
    if CURSE_PERSISTENT_EFFECT_TYPES[effectType] == true then
        return "persistent"
    end
    return "temporary"
end

function BurdJournals.Server.getWorldAgeHoursSafe()
    local gameTime = getGameTime and getGameTime() or nil
    if not gameTime or not gameTime.getWorldAgeHours then
        return nil
    end
    return tonumber(gameTime:getWorldAgeHours())
end

function BurdJournals.Server.getCursedSandboxPercent(optionName, fallback)
    local rawValue = tonumber(BurdJournals.getSandboxOption and BurdJournals.getSandboxOption(optionName))
    if rawValue == nil then
        return fallback
    end
    return math.max(0, rawValue) / 100
end

function BurdJournals.Server.getCursedEffectBaseWeight(effectType)
    if effectType == "gain_negative_trait" then
        return BurdJournals.Server.getCursedSandboxPercent("CursedJournalNegativeTraitCurseWeight", 0.90)
    end
    if effectType == "lose_positive_trait" then
        return BurdJournals.Server.getCursedSandboxPercent("CursedJournalLosePositiveTraitCurseWeight", 0.12)
    end
    if effectType == "lose_skill_level" then
        return BurdJournals.Server.getCursedSandboxPercent("CursedJournalLoseSkillCurseWeight", 0.10)
    end
    return tonumber(CURSE_EFFECT_BASE_WEIGHTS[effectType]) or 1
end

function BurdJournals.Server.getCursedSevereRepeatChanceMultiplier()
    return BurdJournals.Server.getCursedSandboxPercent("CursedJournalSevereRepeatChancePercent", 0.04)
end

function BurdJournals.Server.getCursedSevereCooldownHours()
    local rawValue = tonumber(BurdJournals.getSandboxOption and BurdJournals.getSandboxOption("CursedJournalSevereCooldownHours"))
    if rawValue == nil then
        return 72
    end
    return math.max(0, math.floor(rawValue))
end

function BurdJournals.Server.getPlayerCursedEffectHistory(player, create)
    if not player or not player.getModData then
        return nil, nil
    end
    local playerModData = player:getModData()
    if type(playerModData) ~= "table" then
        return nil, nil
    end
    if create then
        playerModData.BurdJournals = playerModData.BurdJournals or {}
    end
    local bj = playerModData.BurdJournals
    if type(bj) ~= "table" then
        return nil, nil
    end
    if create and type(bj[CURSE_EFFECT_MEMORY_KEY]) ~= "table" then
        bj[CURSE_EFFECT_MEMORY_KEY] = {}
    end
    return bj[CURSE_EFFECT_MEMORY_KEY], bj
end

function BurdJournals.Server.prunePlayerCursedEffectHistory(history, hoursNow)
    if type(history) ~= "table" then
        return false, {}
    end

    local changed = false
    local kept = {}
    local minHours = hoursNow and (hoursNow - BurdJournals.Server.getCursedSevereCooldownHours()) or nil

    for _, entry in ipairs(history) do
        if type(entry) == "table" then
            local effectType = normalizeCurseEffectType(entry.type)
            local entryHours = tonumber(entry.atHours)
            local keep = effectType ~= nil and effectType ~= "random"
            if keep and minHours ~= nil and entryHours ~= nil and entryHours < minHours then
                keep = false
            end
            if keep then
                kept[#kept + 1] = {
                    type = effectType,
                    atHours = entryHours,
                    category = BurdJournals.Server.getCursedEffectCategory(effectType),
                }
            else
                changed = true
            end
        else
            changed = true
        end
    end

    while #kept > CURSE_EFFECT_MEMORY_MAX do
        table.remove(kept, 1)
        changed = true
    end

    return changed, kept
end

function BurdJournals.Server.getRecentCursedEffectSummary(player)
    local history = BurdJournals.Server.getPlayerCursedEffectHistory(player, false)
    local hoursNow = BurdJournals.Server.getWorldAgeHoursSafe()
    local _, prunedHistory = BurdJournals.Server.prunePlayerCursedEffectHistory(history, hoursNow)
    local summary = {
        exactCounts = {},
        recentPersistentCount = 0,
        recentSevereCount = 0,
        lastEffectType = nil,
        history = prunedHistory,
    }

    local startIndex = math.max(1, #prunedHistory - CURSE_EFFECT_RECENT_LOOKBACK + 1)
    for index = startIndex, #prunedHistory do
        local entry = prunedHistory[index]
        local effectType = entry and entry.type
        if effectType then
            summary.exactCounts[effectType] = (summary.exactCounts[effectType] or 0) + 1
            if CURSE_PERSISTENT_EFFECT_TYPES[effectType] == true then
                summary.recentPersistentCount = summary.recentPersistentCount + 1
            end
            if CURSE_SEVERE_EFFECT_TYPES[effectType] == true then
                summary.recentSevereCount = summary.recentSevereCount + 1
            end
            summary.lastEffectType = effectType
        end
    end

    return summary
end

function BurdJournals.Server.getCursedEffectSelectionWeight(player, effectType, summary)
    effectType = normalizeCurseEffectType(effectType)
    if not effectType or effectType == "random" then
        return 0
    end

    summary = summary or BurdJournals.Server.getRecentCursedEffectSummary(player)
    local weight = BurdJournals.Server.getCursedEffectBaseWeight(effectType)
    local sameCount = (summary.exactCounts and summary.exactCounts[effectType]) or 0
    local isPersistent = CURSE_PERSISTENT_EFFECT_TYPES[effectType] == true
    local isSevere = CURSE_SEVERE_EFFECT_TYPES[effectType] == true

    if sameCount > 0 then
        weight = weight * CURSE_EFFECT_REPEAT_MULTIPLIER
        if summary.lastEffectType == effectType then
            weight = weight * CURSE_EFFECT_LAST_REPEAT_MULTIPLIER
        end
        if sameCount > 1 then
            weight = weight * CURSE_EFFECT_STACKED_REPEAT_MULTIPLIER
        end
    end

    if isPersistent and summary.recentPersistentCount > 0 then
        weight = weight * CURSE_EFFECT_PERSISTENT_FATIGUE_MULTIPLIER
    end
    if isSevere and summary.recentSevereCount > 0 then
        weight = weight * BurdJournals.Server.getCursedSevereRepeatChanceMultiplier()
    end
    if isSevere and summary.recentPersistentCount > 1 then
        weight = weight * CURSE_EFFECT_SEVERE_STREAK_MULTIPLIER
    end

    return math.max(0.01, weight)
end

function BurdJournals.Server.buildWeightedCursedEffectOrder(player, options)
    local summary = BurdJournals.Server.getRecentCursedEffectSummary(player)
    local remaining = {}
    local ordered = {}

    local omenCategory = type(options) == "table" and options.omenCategory or nil

    local function isEffectAllowed(effectType)
        if omenCategory ~= nil then
            if not (BurdJournals.Server.getCurseEffectOmenCategory
                and BurdJournals.Server.getCurseEffectOmenCategory(effectType) == omenCategory) then
                return false
            end
        end
        return true
    end

    -- Build the candidate pool. When an omen category is set, restrict to effects in
    -- that category; if that leaves nothing, fall back to the full pool (never fail).
    for _, effectType in ipairs(CURSE_EFFECT_ORDER) do
        if isEffectAllowed(effectType) then
            remaining[#remaining + 1] = effectType
        end
    end
    if #remaining == 0 then
        for _, effectType in ipairs(CURSE_EFFECT_ORDER) do
            remaining[#remaining + 1] = effectType
        end
    end

    while #remaining > 0 do
        local weightedEntries = {}
        local totalWeight = 0

        for index, effectType in ipairs(remaining) do
            local rawWeight = BurdJournals.Server.getCursedEffectSelectionWeight(player, effectType, summary)
            local scaledWeight = math.max(1, math.floor((rawWeight * 1000) + 0.5))
            totalWeight = totalWeight + scaledWeight
            weightedEntries[#weightedEntries + 1] = {
                index = index,
                scaledWeight = scaledWeight,
            }
        end

        local chosenIndex = nil
        if totalWeight > 0 then
            local roll = ZombRand(totalWeight)
            local cursor = 0
            for _, entry in ipairs(weightedEntries) do
                cursor = cursor + entry.scaledWeight
                if roll < cursor then
                    chosenIndex = entry.index
                    break
                end
            end
        end

        if not chosenIndex then
            chosenIndex = ZombRand(#remaining) + 1
        end

        ordered[#ordered + 1] = table.remove(remaining, chosenIndex)
    end

    return ordered
end

function BurdJournals.Server.recordAppliedCursedEffect(player, effectType)
    effectType = normalizeCurseEffectType(effectType)
    if not effectType or effectType == "random" then
        return
    end

    local history, bj = BurdJournals.Server.getPlayerCursedEffectHistory(player, true)
    if type(history) ~= "table" or type(bj) ~= "table" then
        return
    end

    local hoursNow = BurdJournals.Server.getWorldAgeHoursSafe()
    local _, prunedHistory = BurdJournals.Server.prunePlayerCursedEffectHistory(history, hoursNow)
    prunedHistory[#prunedHistory + 1] = {
        type = effectType,
        atHours = hoursNow,
        category = BurdJournals.Server.getCursedEffectCategory(effectType),
    }

    while #prunedHistory > CURSE_EFFECT_MEMORY_MAX do
        table.remove(prunedHistory, 1)
    end

    bj[CURSE_EFFECT_MEMORY_KEY] = prunedHistory
    if player.transmitModData then
        player:transmitModData()
    end
end

end

-- =====================================================================
-- Curse effect omen categories + add-on curse effect registry
-- Omen categories group curse effects for the binding-omen warning prompt.
-- =====================================================================

CURSE_EFFECT_OMEN_CATEGORY = CURSE_EFFECT_OMEN_CATEGORY or {
    barbed_seal = "pain",
    jammed_breath = "pain",
    seasonal_wave = "pain",
    panic = "pain",
    hexed_tooling = "ruin",
    torn_gear = "ruin",
    pantsed = "ruin",
    gain_negative_trait = "loss",
    lose_positive_trait = "loss",
    lose_skill_level = "loss",
}

function BurdJournals.Server.getCurseEffectOmenCategory(effectType)
    if type(effectType) ~= "string" then
        return nil
    end
    return CURSE_EFFECT_OMEN_CATEGORY[string.lower(effectType)] or "pain"
end

function BurdJournals.Server.setCurseEffectOmenCategory(effectType, omenCategory)
    if type(effectType) ~= "string" or type(omenCategory) ~= "string" then
        return
    end
    CURSE_EFFECT_OMEN_CATEGORY[string.lower(effectType)] = string.lower(omenCategory)
end

-- =====================================================================
-- Expired curses: older cursed journals can go dormant and open safely.
-- =====================================================================

-- Resolve the world-age hours a cursed journal was spawned. Falls back to
-- data.timestamp, then lazily stamps "now" (no expiration credit) if neither exists.
function BurdJournals.Server.getCursedJournalSpawnHours(data, stampIfMissing)
    if type(data) ~= "table" then
        return nil
    end
    local spawnHours = tonumber(data.cursedSpawnedAtHours)
    if spawnHours ~= nil then
        return spawnHours
    end
    spawnHours = tonumber(data.timestamp)
    if spawnHours ~= nil then
        return spawnHours
    end
    if stampIfMissing then
        local now = BurdJournals.Server.getWorldAgeHoursSafe()
        if now ~= nil then
            data.cursedSpawnedAtHours = now
            return now
        end
    end
    return nil
end

-- Compute expiration info for a cursed journal. Missing timestamps never expire.
function BurdJournals.Server.getCursedExpirationInfo(data)
    local info = { expired = false, enabled = false }
    if BurdJournals.getSandboxOption and BurdJournals.getSandboxOption("EnableCursedJournalExpiration") == false then
        return info
    end
    info.enabled = true

    local expirationDays = tonumber(BurdJournals.getSandboxOption and BurdJournals.getSandboxOption("CursedJournalExpirationDays"))
    if expirationDays == nil then
        expirationDays = 30
    end
    if expirationDays <= 0 then
        return info
    end
    info.thresholdDays = expirationDays

    local spawnHours = BurdJournals.Server.getCursedJournalSpawnHours(data, false)
    local now = BurdJournals.Server.getWorldAgeHoursSafe()
    if spawnHours == nil or now == nil then
        return info
    end
    info.spawnHours = spawnHours

    local ageHours = now - spawnHours
    if ageHours <= 0 then
        info.ageDays = 0
        return info
    end
    info.ageDays = ageHours / 24

    if ageHours >= (expirationDays * 24) then
        info.expired = true
    end
    return info
end

-- =====================================================================
-- Binding omens: insight-driven curse category warnings shown before the reader commits.
-- =====================================================================

function BurdJournals.Server.shouldShowCursedOmenForInsight(insightLevel)
    return (tonumber(insightLevel) or 0) >= 2
end

-- Roll a binding-omen category (pain|ruin|loss) using the weighted selection so the
-- omen respects player history. Returns the category string or nil.
function BurdJournals.Server.rollCursedOmenCategory(player)
    local ordered = BurdJournals.Server.buildWeightedCursedEffectOrder(player)
    if type(ordered) ~= "table" then
        return nil
    end
    for _, effectType in ipairs(ordered) do
        local category = BurdJournals.Server.getCurseEffectOmenCategory(effectType)
        if category then
            return category
        end
    end
    return nil
end

-- Localized omen line for a category (or the expired line for dormant journals).
function BurdJournals.Server.getCursedOmenLine(omenCategory, expired)
    if expired then
        return getCursedServerText("UI_BurdJournals_CursedOmenExpired", "The ink has dried and cracked. Whatever slept here has gone quiet.")
    end
    if omenCategory == "ruin" then
        return getCursedServerText("UI_BurdJournals_CursedOmenRuin", "An omen of ruin: your tools and garb will suffer.")
    elseif omenCategory == "loss" then
        return getCursedServerText("UI_BurdJournals_CursedOmenLoss", "An omen of loss: something you have earned may be stripped away.")
    end
    return getCursedServerText("UI_BurdJournals_CursedOmenPain", "An omen of pain: your body will bear the mark.")
end

function BurdJournals.Server.rollCursedInsightEffectType(player, omenCategory)
    local options = {}
    if type(omenCategory) == "string" and omenCategory ~= "" then
        options.omenCategory = omenCategory
    end
    local ordered = BurdJournals.Server.buildWeightedCursedEffectOrder(player, options)
    if type(ordered) == "table" and ordered[1] then
        return normalizeCurseEffectType(ordered[1])
    end
    return nil
end

function BurdJournals.Server.getCursedInsightLine(insightLevel, omenCategory, effectType, expired, hidden)
    insightLevel = tonumber(insightLevel) or 0
    if expired then
        return BurdJournals.Server.getCursedOmenLine(nil, true)
    end
    if insightLevel >= 3 and type(effectType) == "string" and effectType ~= "" then
        local effectName = BurdJournals.getCursedEffectInsightDisplayName
            and BurdJournals.getCursedEffectInsightDisplayName(effectType)
            or effectType
        return BurdJournals.formatText(
            getCursedServerText("UI_BurdJournals_CursedInsightExact", "Your fieldcraft reads the seal: %s."),
            effectName
        )
    end
    if insightLevel >= 2 and type(omenCategory) == "string" and omenCategory ~= "" then
        return BurdJournals.Server.getCursedOmenLine(omenCategory, false)
    end
    if insightLevel >= 1 and hidden == true then
        return getCursedServerText("UI_BurdJournals_CursedInsightHidden", "The blood is wrong. Something has been hidden under it.")
    end
    if insightLevel >= 1 then
        return getCursedServerText("UI_BurdJournals_CursedInsightFaint", "The seal feels wrong under your eyes.")
    end
    return nil
end

function BurdJournals.Server.getCursedInsightPreviewPlayerKey(player)
    if not player then
        return nil
    end
    local username = player.getUsername and player:getUsername() or nil
    if username and username ~= "" then
        return "u:" .. tostring(username)
    end
    local playerNum = player.getPlayerNum and player:getPlayerNum() or nil
    if playerNum ~= nil then
        return "p:" .. tostring(playerNum)
    end
    return tostring(player)
end

function BurdJournals.Server.getCursedInsightPreviewKey(player, journalUUID, journalId)
    local playerKey = BurdJournals.Server.getCursedInsightPreviewPlayerKey(player)
    if not playerKey then
        return nil
    end
    if type(journalUUID) == "string" and journalUUID ~= "" then
        return playerKey .. "|uuid:" .. journalUUID
    end
    if journalId ~= nil then
        return playerKey .. "|id:" .. tostring(journalId)
    end
    return nil
end

function BurdJournals.Server.getCachedCursedInsightPreview(player, journalUUID, journalId)
    local key = BurdJournals.Server.getCursedInsightPreviewKey(player, journalUUID, journalId)
    if not key then
        return nil
    end
    local preview = BurdJournals.Server._cursedInsightPreviewCache[key]
    if type(preview) ~= "table" then
        return nil
    end
    if type(journalUUID) == "string" and journalUUID ~= "" and preview.journalUUID ~= journalUUID then
        return nil
    end
    return preview
end

function BurdJournals.Server.storeCursedInsightPreview(player, preview)
    if type(preview) ~= "table" then
        return nil
    end
    local key = BurdJournals.Server.getCursedInsightPreviewKey(player, preview.journalUUID, preview.journalId)
    if not key then
        return nil
    end
    local cache = BurdJournals.Server._cursedInsightPreviewCache
    local nowMs = (getTimestampMs and getTimestampMs()) or ((os.time() or 0) * 1000)
    preview._bsjCachedAt = nowMs
    cache[key] = preview
    local entries = {}
    for cacheKey, cached in pairs(cache) do
        local storedAt = type(cached) == "table" and tonumber(cached._bsjCachedAt) or 0
        if storedAt > 0 and (nowMs - storedAt) > 1800000 then
            cache[cacheKey] = nil
        else
            entries[#entries + 1] = {key = cacheKey, storedAt = storedAt}
        end
    end
    local maxEntries = 2048
    if #entries > maxEntries then
        table.sort(entries, function(a, b) return a.storedAt < b.storedAt end)
        for index = 1, #entries - maxEntries do
            cache[entries[index].key] = nil
        end
    end
    return preview
end

function BurdJournals.Server.buildCursedInsightPreview(player, item, data, journalId, journalUUID)
    if not player or not item or type(data) ~= "table" then
        return nil
    end

    local insightLevel = BurdJournals.getCursedInsightLevel
        and select(1, BurdJournals.getCursedInsightLevel(player))
        or 0
    if insightLevel <= 0 then
        return nil
    end

    local isHiddenCursed = isHiddenCursedJournalState(item, data)
    local isSealedCursed = BurdJournals.isCursedJournalItem and BurdJournals.isCursedJournalItem(item) or false
    if not isHiddenCursed and not isSealedCursed then
        return nil
    end
    if isSealedCursed and insightLevel < 2 then
        return nil
    end

    local expirationInfo = BurdJournals.Server.getCursedExpirationInfo(data)
    local omenCategory = nil
    local effectType = nil
    local boundPreview = false
    if expirationInfo and expirationInfo.expired then
        effectType = "expired"
    elseif insightLevel >= 3 then
        effectType = normalizeCurseEffectType(data.cursedInsightEffectType)
            or normalizeCurseEffectType(data.cursedForcedEffectType)
        if not effectType then
            effectType = BurdJournals.Server.rollCursedInsightEffectType(player, data.cursedOmenCategory)
            if effectType then
                data.cursedInsightEffectType = effectType
                boundPreview = true
            end
        end
        omenCategory = effectType and BurdJournals.Server.getCurseEffectOmenCategory(effectType) or nil
        if omenCategory and data.cursedOmenCategory ~= omenCategory then
            data.cursedOmenCategory = omenCategory
            boundPreview = true
        end
    elseif insightLevel >= 2 then
        omenCategory = type(data.cursedOmenCategory) == "string"
            and data.cursedOmenCategory
            or BurdJournals.Server.rollCursedOmenCategory(player)
        if omenCategory and data.cursedOmenCategory ~= omenCategory then
            data.cursedOmenCategory = omenCategory
            boundPreview = true
        end
    end

    if boundPreview and item.transmitModData then
        item:transmitModData()
    end

    return BurdJournals.Server.storeCursedInsightPreview(player, {
        journalId = journalId,
        journalUUID = journalUUID,
        insightLevel = insightLevel,
        hiddenCursed = isHiddenCursed == true or nil,
        sealedCursed = isSealedCursed == true or nil,
        omenCategory = omenCategory,
        effectType = effectType,
        curseExpired = expirationInfo and expirationInfo.expired == true or nil,
        curseAgeDays = expirationInfo and expirationInfo.ageDays or nil,
        curseExpirationDays = expirationInfo and expirationInfo.thresholdDays or nil,
    })
end

-- Tooltip previews are the sole gameplay path allowed to inspect a journal
-- outside the requester's inventory. Resolve one exact identity within reach,
-- with a bounded container walk and a capped miss cache; never trust or apply
-- client journalData/fingerprint state.
function BurdJournals.Server.resolveCursedInsightPreviewJournal(player, args)
    if not player or type(args) ~= "table" then return nil end
    local requestedId = args.journalId ~= nil and tonumber(args.journalId) or nil
    local requestedUUID = type(args.journalUUID) == "string" and args.journalUUID ~= "" and args.journalUUID or nil
    if requestedUUID and #requestedUUID > 128 then return nil end
    if (args.journalId ~= nil and requestedId == nil) or (not requestedId and not requestedUUID) then return nil end

    local playerKey = BurdJournals.Server.getCursedInsightPreviewPlayerKey(player)
    if not playerKey then return nil end
    local missKey = playerKey .. "|" .. (requestedUUID and ("uuid:" .. requestedUUID) or ("id:" .. tostring(requestedId)))
    local nowMs = (getTimestampMs and getTimestampMs()) or ((os.time() or 0) * 1000)
    local misses = BurdJournals.Server._cursedInsightPreviewMisses
    local activeMisses = 0
    for key, entry in pairs(misses) do
        if type(entry) ~= "table" or (nowMs - (tonumber(entry.at) or 0)) >= 60000 then
            misses[key] = nil
        else
            activeMisses = activeMisses + 1
        end
    end
    local miss = misses[missKey]
    if type(miss) == "table" and (nowMs - (tonumber(miss.at) or 0)) < 60000 and (tonumber(miss.count) or 0) >= 3 then
        return nil
    elseif type(miss) == "table" and (nowMs - (tonumber(miss.at) or 0)) >= 60000 then
        misses[missKey] = nil
        miss = nil
    end
    if not miss and activeMisses >= 256 then return nil end

    local function matches(candidate)
        if not (candidate and candidate.getID and candidate.getFullType) then return false end
        local fullType = tostring(candidate:getFullType() or "")
        if not fullType:find("^BurdJournals%.") then return false end
        if requestedId and tonumber(candidate:getID()) ~= requestedId then return false end
        if requestedUUID then
            local data = BurdJournals.getJournalData and BurdJournals.getJournalData(candidate) or nil
            if type(data) ~= "table" or tostring(data.uuid or "") ~= requestedUUID then return false end
        end
        return true
    end

    local inventory = player.getInventory and player:getInventory() or nil
    local budget = { remaining = 512, seen = {} }
    local function scanContainer(container)
        if not (container and container.getItems) or budget.remaining <= 0 then return nil end
        local containerKey = tostring(container)
        if budget.seen[containerKey] then return nil end
        budget.seen[containerKey] = true
        local items = container:getItems()
        if not items then return nil end
        for i = 0, items:size() - 1 do
            if budget.remaining <= 0 then return nil end
            budget.remaining = budget.remaining - 1
            local candidate = items:get(i)
            if matches(candidate) then return candidate end
            local nested = candidate and candidate.getInventory and candidate:getInventory() or nil
            local found = nested and scanContainer(nested) or nil
            if found then return found end
        end
        return nil
    end

    local found = scanContainer(inventory)
    if not found then
        -- Keep a separate cap for reachable world containers so a huge modded
        -- player inventory cannot starve natural-loot discovery (1024 max
        -- candidates across both scopes).
        budget = { remaining = 512, seen = {} }
        local origin = player.getCurrentSquare and player:getCurrentSquare() or nil
        local cell = origin and getCell and getCell() or nil
        if origin and cell and cell.getGridSquare then
            local ox, oy, oz = origin:getX(), origin:getY(), origin:getZ()
            for dx = -1, 1 do
                for dy = -1, 1 do
                    local square = cell:getGridSquare(ox + dx, oy + dy, oz)
                    -- Project Zomboid's own container interaction handler uses
                    -- isBlockedTo for this same adjacent-square reachability
                    -- boundary. If an older API lacks it, fail closed off-square.
                    local reachable = square == origin
                    if not reachable and square and origin.isBlockedTo then
                        reachable = not origin:isBlockedTo(square)
                    end
                    local objects = reachable and square and square.getObjects and square:getObjects() or nil
                    if objects then
                        for i = 0, objects:size() - 1 do
                            local object = objects:get(i)
                            local worldItem = object and object.getItem and object:getItem() or nil
                            if matches(worldItem) then found = worldItem; break end
                            local container = object and object.getContainer and object:getContainer() or nil
                            found = container and scanContainer(container) or nil
                            if not found then
                                local objectInventory = object and object.getInventory and object:getInventory() or nil
                                found = objectInventory and scanContainer(objectInventory) or nil
                            end
                            if found then break end
                        end
                    end
                    if found then break end
                end
                if found then break end
            end
        end
    end

    if not found then
        misses[missKey] = { count = (type(miss) == "table" and (tonumber(miss.count) or 0) or 0) + 1, at = nowMs }
        return nil
    end
    misses[missKey] = nil
    local data = BurdJournals.getJournalData and BurdJournals.getJournalData(found) or nil
    return found, found:getID(), type(data) == "table" and data.uuid or nil
end

function BurdJournals.Server.handleRequestCursedInsightPreview(player, args)
    if not player or type(args) ~= "table" then
        return
    end

    local item, resolvedJournalId, resolvedJournalUUID = BurdJournals.Server.resolveCursedInsightPreviewJournal(player, args)
    if not item then
        return
    end
    local modData = item:getModData()
    modData.BurdJournals = modData.BurdJournals or {}
    local data = modData.BurdJournals
    normalizeCursedJournalStateForType(item, "requestCursedInsightPreview")
    resolvedJournalUUID = resolvedJournalUUID
        or (BurdJournals.resolveJournalUUIDForRuntime and BurdJournals.resolveJournalUUIDForRuntime(data, item, true))
        or data.uuid

    local preview = BurdJournals.Server.buildCursedInsightPreview(
        player,
        item,
        data,
        resolvedJournalId or (item.getID and item:getID()) or nil,
        resolvedJournalUUID
    )
    if preview then
        BurdJournals.Server.sendToClient(player, "cursedInsightPreview", preview)
    end
end

-- Register a new curse effect from an add-on. spec fields:
--   handler(context) -> resultTable|nil  (context: player, forcedTraitId, forcedSkillName, effectType, journalItem, journalData)
--   baseWeight (number, optional)
--   category "temporary"|"persistent"|"severe" (optional, default temporary)
--   omenCategory "pain"|"ruin"|"loss" (optional, default pain)
function BurdJournals.Server.registerCurseEffect(id, spec)
    if type(id) ~= "string" or id == "" or type(spec) ~= "table" then
        return false
    end
    local normalizedId = string.lower(id)
    local handler = spec.handler
    if type(handler) ~= "function" then
        return false
    end

    -- Adapter: core calls handlers as (player, forcedTraitId, forcedSkillName);
    -- registered handlers receive a single context table instead.
    CURSE_EFFECT_HANDLERS[normalizedId] = function(player, forcedTraitId, forcedSkillName, extraContext)
        local context = type(extraContext) == "table" and extraContext or {}
        context.player = player
        context.forcedTraitId = forcedTraitId
        context.forcedSkillName = forcedSkillName
        context.effectType = normalizedId
        return handler(context)
    end

    local inOrder = false
    for _, existing in ipairs(CURSE_EFFECT_ORDER) do
        if existing == normalizedId then
            inOrder = true
            break
        end
    end
    if not inOrder then
        CURSE_EFFECT_ORDER[#CURSE_EFFECT_ORDER + 1] = normalizedId
    end

    if tonumber(spec.baseWeight) then
        CURSE_EFFECT_BASE_WEIGHTS[normalizedId] = tonumber(spec.baseWeight)
    end

    local category = spec.category
    if category == "severe" then
        CURSE_SEVERE_EFFECT_TYPES[normalizedId] = true
        CURSE_PERSISTENT_EFFECT_TYPES[normalizedId] = true
    elseif category == "persistent" then
        CURSE_PERSISTENT_EFFECT_TYPES[normalizedId] = true
    end

    if type(spec.omenCategory) == "string" then
        BurdJournals.Server.setCurseEffectOmenCategory(normalizedId, spec.omenCategory)
    end

    return true
end

function BurdJournals.Server.normalizeCursedSealSoundEvent(soundEvent)
    if soundEvent == nil then
        return nil
    end
    if type(soundEvent) ~= "string" then
        return nil
    end

    local trimmed = string.gsub(soundEvent, "^%s+", "")
    trimmed = string.gsub(trimmed, "%s+$", "")
    if trimmed == "" then
        return nil
    end

    local lowered = string.lower(trimmed)
    if lowered == "default" then
        return nil
    end
    if lowered == "random" then
        return nil
    end
    if lowered == "none" or lowered == "off" or lowered == "silent" then
        return "none"
    end

    return trimmed
end

function BurdJournals.Server.applyCursedEffect(player, forcedType, forcedTraitId, forcedSkillName, context)
    context = type(context) == "table" and context or {}
    local function finish(result)
        if result and BurdJournals.runHooks then
            BurdJournals.runHooks("OnCurseApplied", player, result, context.journalItem)
        end
        return result
    end

    local normalizedForcedType = normalizeCurseEffectType(forcedType)
    if normalizedForcedType and normalizedForcedType ~= "random" then
        local forced = CURSE_EFFECT_HANDLERS[normalizedForcedType]
        if forced then
            local result = forced(player, forcedTraitId, forcedSkillName, context)
            if result then
                BurdJournals.Server.recordAppliedCursedEffect(player, result.type)
                return finish(result)
            end
        end
        if BurdJournals.debugPrint then
            BurdJournals.debugPrint("[BurdJournals] Forced cursed effect '" .. tostring(normalizedForcedType) .. "' had no valid target; falling back to panic")
        end
        local panicResult = cursePanic(player, nil, nil)
        if panicResult then
            BurdJournals.Server.recordAppliedCursedEffect(player, panicResult.type)
        end
        return finish(panicResult)
    end

    local effectTypes = BurdJournals.Server.buildWeightedCursedEffectOrder(player, {
        omenCategory = context.omenCategory,
    })
    for _, effectType in ipairs(effectTypes) do
        local fn = CURSE_EFFECT_HANDLERS[effectType]
        local result = fn and fn(player, nil, nil, context) or nil
        if result then
            BurdJournals.Server.recordAppliedCursedEffect(player, result.type)
            return finish(result)
        end
    end
    local panicResult = cursePanic(player, nil, nil)
    if panicResult then
        BurdJournals.Server.recordAppliedCursedEffect(player, panicResult.type)
    end
    return finish(panicResult)
end

function BurdJournals.Server.materializeCursedRewardJournal(player, sourceItem, rewardData, replacementFullType, allowSourceFallback)
    if not player or not sourceItem or type(rewardData) ~= "table" then
        return nil
    end

    local sourceModData = sourceItem:getModData()
    local sourceContainer = (sourceItem.getContainer and sourceItem:getContainer()) or nil
    local targetContainer = sourceContainer or (player and player.getInventory and player:getInventory()) or nil
    local inventory = player and player.getInventory and player:getInventory() or nil

    local targetFullType = type(replacementFullType) == "string" and replacementFullType ~= ""
        and replacementFullType
        or "BurdJournals.FilledSurvivalJournal_Bloody"
    local journal = nil
    if targetContainer and targetContainer.AddItem then
        journal = addJournalItemToContainerCompat(targetContainer, targetFullType)
    end
    if not journal and inventory and inventory ~= targetContainer then
        journal = addJournalItemToContainerCompat(inventory, targetFullType)
        if journal then
            targetContainer = inventory
        end
    end

    if not journal and allowSourceFallback == false then
        return nil
    end

    -- Keep the upgraded source item as a safe fallback so unexpected B41
    -- creation failures never strand or delete the player's journal.
    if not journal then
        sourceModData.BurdJournals = {}
        for key, value in pairs(rewardData) do
            sourceModData.BurdJournals[key] = value
        end
        if BurdJournals.updateJournalName then
            BurdJournals.updateJournalName(sourceItem, true)
        end
        if BurdJournals.updateJournalIcon then
            BurdJournals.updateJournalIcon(sourceItem)
        end
        if (isServer and isServer()) and sourceItem.transmitModData then
            sourceItem:transmitModData()
        end
        if targetContainer and targetContainer.setDrawDirty then
            targetContainer:setDrawDirty(true)
        end
        if inventory and inventory ~= targetContainer and inventory.setDrawDirty then
            inventory:setDrawDirty(true)
        end
        if player and player.syncInventory then
            BurdJournals.safePcall(function()
                player:syncInventory()
            end)
        end
        return sourceItem
    end

    local modData = journal:getModData()
    modData.BurdJournals = {}
    for key, value in pairs(rewardData) do
        modData.BurdJournals[key] = value
    end

    if BurdJournals.updateJournalName then
        BurdJournals.updateJournalName(journal, true)
    end
    if BurdJournals.updateJournalIcon then
        BurdJournals.updateJournalIcon(journal)
    end
    if targetContainer and targetContainer.setDrawDirty then
        targetContainer:setDrawDirty(true)
    end
    if targetContainer and sendAddItemToContainer then
        sendAddItemToContainer(targetContainer, journal)
    end
    if (isServer and isServer()) and journal.transmitModData then
        journal:transmitModData()
    end

    if sourceContainer and sourceContainer.Remove then
        sourceContainer:Remove(sourceItem)
        if sourceContainer.setDrawDirty then
            sourceContainer:setDrawDirty(true)
        end
        if sendRemoveItemFromContainer then
            sendRemoveItemFromContainer(sourceContainer, sourceItem)
        end
    end
    if inventory and inventory ~= sourceContainer and inventory.contains and inventory:contains(sourceItem) then
        inventory:Remove(sourceItem)
        if inventory.setDrawDirty then
            inventory:setDrawDirty(true)
        end
        if sendRemoveItemFromContainer then
            sendRemoveItemFromContainer(inventory, sourceItem)
        end
    end

    if player and player.syncInventory then
        BurdJournals.safePcall(function()
            player:syncInventory()
        end)
    end
    return journal
end

function BurdJournals.Server.applyCursedRewardDataToExistingJournal(journal, rewardData)
    if not journal or type(rewardData) ~= "table" then
        return false
    end

    local modData = journal:getModData()
    modData.BurdJournals = {}
    for key, value in pairs(rewardData) do
        modData.BurdJournals[key] = value
    end

    if BurdJournals.updateJournalName then
        BurdJournals.updateJournalName(journal, true)
    end
    if BurdJournals.updateJournalIcon then
        BurdJournals.updateJournalIcon(journal)
    end
    if journal.transmitModData and not BurdJournals.Server.shouldDeferBatchTransmit() then
            journal:transmitModData()
    end
    return true
end

function BurdJournals.Server.getHiddenCursedClaimBlockedMessage()
    return getCursedServerText("UI_BurdJournals_CursedHiddenClaimBlocked", "Open the journal first.")
end

function BurdJournals.Server.handleOpenCursedJournal(player, args)
    if not player or type(args) ~= "table" then
        BurdJournals.Server.sendToClient(player, "error", {message = "Invalid cursed journal request."})
        return
    end

    local journalId = tonumber(args.journalId)
    local journalUUID = normalizeCommandJournalUUID(args)
    local confirm = args.confirm == true
    if not journalId and not journalUUID then
        BurdJournals.Server.sendToClient(player, "error", {message = "Invalid cursed journal request."})
        return
    end

    local item, resolvedJournalId, resolvedJournalUUID = resolveServerCommandJournal(player, args, "openCursedJournal")
    if not item then
        BurdJournals.Server.sendToClient(player, "error", {message = "That cursed journal could not be found."})
        return
    end

    if not maybeMigrateRuntimeOnTouch(item, player, "openCursedJournal") then
        return
    end
    if not enforceJournalLightRequirement(player, "openCursedJournal") then
        return
    end
    local fullType = item.getFullType and item:getFullType() or ""
    local modData = item:getModData()
    modData.BurdJournals = modData.BurdJournals or {}
    local data = modData.BurdJournals
    normalizeCursedJournalStateForType(item, "openCursedJournal")
    local isHiddenCursed = isHiddenCursedJournalState(item, data)
    resolvedJournalUUID = resolvedJournalUUID
        or (BurdJournals.resolveJournalUUIDForRuntime and BurdJournals.resolveJournalUUIDForRuntime(data, item, true))
        or data.uuid

    if fullType ~= (BurdJournals.CURSED_ITEM_TYPE or "BurdJournals.CursedJournal") then
        if fullType == "BurdJournals.FilledSurvivalJournal_Bloody" and data.isCursedReward == true then
            local revealedExistingReward = markLootRewardsRevealed(player, item, data)
            if revealedExistingReward and item.transmitModData then
                item:transmitModData()
            end
            BurdJournals.Server.sendToClient(player, "cursedOpened", {
                journalId = item:getID(),
                journalUUID = resolvedJournalUUID,
                journalData = data,
                curseType = data.cursedEffectType or "none",
                curseMessage = getCursedServerText("UI_BurdJournals_CursedAlreadyUnleashed", "The curse has already taken its price."),
                soundEvent = nil,
            })
            return
        end
        if isHiddenCursed ~= true then
            BurdJournals.Server.sendToClient(player, "error", {message = "That item is not a cursed journal."})
            return
        end
    end

    if data.isCursedReward == true and data.cursedState == "unleashed" then
        BurdJournals.Server.sendToClient(player, "cursedOpened", {
            journalId = item:getID(),
            journalUUID = resolvedJournalUUID,
            journalData = data,
            curseType = data.cursedEffectType or "none",
            curseMessage = getCursedServerText("UI_BurdJournals_CursedAlreadyUnleashed", "The curse has already taken its price."),
            soundEvent = nil,
        })
        return
    end

    if not confirm and isHiddenCursed ~= true then
        local journalFingerprint = BurdJournals.buildJournalLookupFingerprint
            and BurdJournals.buildJournalLookupFingerprint(item, data)
            or nil
        local cursedInsightLevel = BurdJournals.getCursedInsightLevel
            and select(1, BurdJournals.getCursedInsightLevel(player))
            or 0
        local expirationInfo = BurdJournals.Server.getCursedExpirationInfo(data)
        local preview = BurdJournals.Server.getCachedCursedInsightPreview(player, resolvedJournalUUID, resolvedJournalId or journalId)
        if preview and tonumber(preview.insightLevel or 0) < cursedInsightLevel then
            preview = nil
        end
        if not preview and BurdJournals.Server.buildCursedInsightPreview then
            preview = BurdJournals.Server.buildCursedInsightPreview(
                player,
                item,
                data,
                resolvedJournalId or (item.getID and item:getID()) or journalId,
                resolvedJournalUUID
            )
        end
        local omenCategory = preview and type(preview.omenCategory) == "string" and preview.omenCategory
            or (type(data.cursedOmenCategory) == "string" and data.cursedOmenCategory or nil)
        local insightEffectType = preview and type(preview.effectType) == "string" and preview.effectType
            or normalizeCurseEffectType(data.cursedInsightEffectType)
            or normalizeCurseEffectType(data.cursedForcedEffectType)
        local promptBoundPreview = false
        if cursedInsightLevel >= 3 and not insightEffectType and not (expirationInfo and expirationInfo.expired) then
            insightEffectType = BurdJournals.Server.rollCursedInsightEffectType(player, omenCategory)
            if insightEffectType then
                data.cursedInsightEffectType = insightEffectType
                promptBoundPreview = true
            end
        end
        if insightEffectType and not omenCategory and BurdJournals.Server.getCurseEffectOmenCategory then
            omenCategory = BurdJournals.Server.getCurseEffectOmenCategory(insightEffectType)
            if omenCategory and data.cursedOmenCategory ~= omenCategory then
                data.cursedOmenCategory = omenCategory
                promptBoundPreview = true
            end
        end
        if promptBoundPreview then
            BurdJournals.Server.storeCursedInsightPreview(player, {
                journalId = (item.getID and item:getID()) or resolvedJournalId or journalId,
                journalUUID = resolvedJournalUUID,
                insightLevel = cursedInsightLevel,
                sealedCursed = true,
                omenCategory = omenCategory,
                effectType = insightEffectType,
                curseExpired = expirationInfo and expirationInfo.expired == true or nil,
                curseAgeDays = expirationInfo and expirationInfo.ageDays or nil,
                curseExpirationDays = expirationInfo and expirationInfo.thresholdDays or nil,
            })
            if item.transmitModData then
                item:transmitModData()
            end
        end
        local omenLine = nil
        if expirationInfo and expirationInfo.expired then
            omenLine = BurdJournals.Server.getCursedOmenLine(nil, true)
        else
            local canReadOmen = BurdJournals.Server.shouldShowCursedOmenForInsight(cursedInsightLevel)
            if not omenCategory and canReadOmen then
                local rolled = BurdJournals.Server.rollCursedOmenCategory(player)
                if rolled then
                    omenCategory = rolled
                    data.cursedOmenCategory = rolled
                    if item.transmitModData then item:transmitModData() end
                end
            end
            omenLine = BurdJournals.Server.getCursedInsightLine(
                cursedInsightLevel,
                omenCategory,
                insightEffectType,
                false,
                false
            )
            if not omenLine and canReadOmen then
                omenLine = BurdJournals.Server.getCursedOmenLine(omenCategory, false)
            end
        end

        BurdJournals.Server.sendToClient(player, "cursedOpenPrompt", {
            journalId = (item.getID and item:getID()) or resolvedJournalId or journalId,
            journalUUID = resolvedJournalUUID,
            journalFingerprint = journalFingerprint,
            exactJournalItem = true,
            loreLine = getCursedServerText("UI_BurdJournals_CursedPromptLore", "Ink writhes across the page. Something waits beneath these words."),
            consequenceLine = getCursedServerText("UI_BurdJournals_CursedPromptConsequence", "The first soul to read it will be marked."),
            omenLine = omenLine,
            omenCategory = omenCategory,
            cursedInsightLevel = cursedInsightLevel,
            cursedInsightEffectType = insightEffectType,
            curseExpired = expirationInfo and expirationInfo.expired == true or nil,
            curseAgeDays = expirationInfo and expirationInfo.ageDays or nil,
            curseExpirationDays = expirationInfo and expirationInfo.thresholdDays or nil,
        })
        return
    end

    -- Authoritative state re-check prevents double-curse races.
    local liveItem, liveJournalId, liveJournalUUID = resolveServerCommandJournal(player, {
        journalId = resolvedJournalId or journalId,
        journalUUID = resolvedJournalUUID or journalUUID,
        journalFingerprint = args.journalFingerprint,
        exactJournalItem = args.exactJournalItem == true,
    }, "openCursedJournalConfirm")
    if not liveItem then
        BurdJournals.Server.sendToClient(player, "error", {message = "That cursed journal could not be found."})
        return
    end
    local liveModData = liveItem:getModData()
    liveModData.BurdJournals = liveModData.BurdJournals or {}
    local liveData = liveModData.BurdJournals
    if not maybeMigrateRuntimeOnTouch(liveItem, player, "openCursedJournalConfirm") then
        return
    end
    if not enforceJournalLightRequirement(player, "openCursedJournalConfirm") then
        return
    end
    normalizeCursedJournalStateForType(liveItem, "openCursedJournalConfirm")
    local liveHiddenCursed = isHiddenCursedJournalState(liveItem, liveData)
    local liveCursedInsightLevel = BurdJournals.getCursedInsightLevel and select(1, BurdJournals.getCursedInsightLevel(player)) or 0
    liveJournalUUID = liveJournalUUID
        or (BurdJournals.resolveJournalUUIDForRuntime and BurdJournals.resolveJournalUUIDForRuntime(liveData, liveItem, true))
        or liveData.uuid
    if liveData.isCursedReward == true and liveData.cursedState == "unleashed" then
        local revealedLiveReward = markLootRewardsRevealed(player, liveItem, liveData)
        if revealedLiveReward and liveItem.transmitModData then
            liveItem:transmitModData()
        end
        BurdJournals.Server.sendToClient(player, "cursedOpened", {
            journalId = liveJournalId or (liveItem.getID and liveItem:getID()) or nil,
            journalUUID = liveJournalUUID,
            journalData = liveData,
            curseType = liveData.cursedEffectType or "none",
            curseMessage = getCursedServerText("UI_BurdJournals_CursedAlreadyUnleashed", "The curse has already taken its price."),
            soundEvent = nil,
        })
        return
    end

    local cachedInsightPreview = BurdJournals.Server.getCachedCursedInsightPreview(player, liveJournalUUID, liveJournalId)
    if cachedInsightPreview
        and tonumber(cachedInsightPreview.insightLevel or 0) ~= liveCursedInsightLevel
    then
        cachedInsightPreview = nil
    end

    local forcedCurseType = normalizeCurseEffectType(liveData.cursedForcedEffectType)
        or (cachedInsightPreview and normalizeCurseEffectType(cachedInsightPreview.effectType))
        or normalizeCurseEffectType(liveData.cursedInsightEffectType)
    local forcedCurseTraitId = normalizeForcedTraitId(liveData.cursedForcedTraitId)
    local forcedCurseSkillName = normalizeForcedSkillName(liveData.cursedForcedSkillName)
    -- Binding omen: constrain the roll to the pre-rolled omen category.
    -- Hidden journals stay
    -- omen-free (no stored category), preserving their surprise identity.
    local liveExpirationInfo = BurdJournals.Server.getCursedExpirationInfo(liveData)
    local curseContext = {
        journalItem = liveItem,
        journalData = liveData,
        curseExpired = liveExpirationInfo and liveExpirationInfo.expired == true or nil,
        curseAgeDays = liveExpirationInfo and liveExpirationInfo.ageDays or nil,
        curseExpirationDays = liveExpirationInfo and liveExpirationInfo.thresholdDays or nil,
    }
    local previewOmenCategory = cachedInsightPreview
        and type(cachedInsightPreview.omenCategory) == "string"
        and cachedInsightPreview.omenCategory
        or nil
    if previewOmenCategory then
        curseContext.omenCategory = previewOmenCategory
    elseif BurdJournals.Server.shouldShowCursedOmenForInsight(liveCursedInsightLevel)
        and type(liveData.cursedOmenCategory) == "string"
    then
        curseContext.omenCategory = liveData.cursedOmenCategory
    end
    local curseResult = nil
    if liveExpirationInfo and liveExpirationInfo.expired == true then
        curseResult = {
            type = "expired",
            expired = true,
            skipped = true,
            message = getCursedServerText("UI_BurdJournals_CursedMsgExpired", "The seal breaks, but the curse has already burned out."),
            ageDays = liveExpirationInfo.ageDays,
            thresholdDays = liveExpirationInfo.thresholdDays,
        }
    else
        curseResult = BurdJournals.Server.applyCursedEffect(
            player,
            forcedCurseType,
            forcedCurseTraitId,
            forcedCurseSkillName,
            curseContext
        )
    end
    local ambushNoiseBase = nil
    local ambushNoiseRadiusApplied = nil
    local ambushNoiseVolumeApplied = nil
    if curseResult and curseResult.type == "panic" then
        ambushNoiseBase = getCursedAmbushNoiseRadius()
        local pullRadius, pullVolume, nudgeRadius = getCursedAmbushPullProfile()
        ambushNoiseRadiusApplied = pullRadius
        ambushNoiseVolumeApplied = pullVolume
        if pullRadius > 0 then
            -- Multi-pulse AI noise + direct path nudges improve ambush reliability for freshly spawned zombies.
            emitCursedSilentAIPull(player, pullRadius, pullVolume)
            nudgeCursedAmbushZombiesToward(player, nudgeRadius)
            nudgeCursedAmbushZombiesTowardDelayed(player, nudgeRadius, 900)
            nudgeCursedAmbushZombiesTowardDelayed(player, nudgeRadius, 1700)
            emitCursedSilentAIPullDelayed(player, pullRadius, pullVolume, 650)
            emitCursedSilentAIPullDelayed(player, pullRadius, pullVolume, 1250)
            emitCursedSilentAIPullDelayed(player, pullRadius, pullVolume, 1850)
        end
    end

    local rewardSeed = nil
    if type(liveData.cursedPendingRewards) == "table" then
        rewardSeed = BurdJournals.normalizeJournalData and BurdJournals.normalizeJournalData(liveData.cursedPendingRewards) or liveData.cursedPendingRewards
    end
    rewardSeed = rewardSeed or {}
    rewardSeed.uuid = rewardSeed.uuid or liveData.uuid
    rewardSeed.author = rewardSeed.author or liveData.author
    rewardSeed.profession = rewardSeed.profession or liveData.profession
    rewardSeed.professionName = rewardSeed.professionName or liveData.professionName
    rewardSeed.flavorKey = rewardSeed.flavorKey or liveData.flavorKey
    rewardSeed.flavorText = rewardSeed.flavorText or liveData.flavorText
    rewardSeed.loreNoteText = rewardSeed.loreNoteText or liveData.loreNoteText
    rewardSeed.loreNoteTemplateVersion = rewardSeed.loreNoteTemplateVersion or liveData.loreNoteTemplateVersion
    rewardSeed.loreNoteTemplateFamily = rewardSeed.loreNoteTemplateFamily or liveData.loreNoteTemplateFamily
    rewardSeed.lootNotesEligible = rewardSeed.lootNotesEligible == true or liveData.lootNotesEligible == true
    rewardSeed.timestamp = rewardSeed.timestamp or liveData.timestamp
    rewardSeed.cursedSealSoundEvent = BurdJournals.Server.normalizeCursedSealSoundEvent(liveData.cursedSealSoundEvent)
    -- Severity compensation: tell the profile generator how harsh the applied curse was.
    rewardSeed.curseCategory = curseResult and curseResult.type
        and BurdJournals.Server.getCursedEffectCategory(curseResult.type)
        or nil

    local rewards = BurdJournals.Server.generateCursedRewardProfile(rewardSeed)
    if tonumber(rewards.loreNoteTemplateVersion) == LORE_DYNAMIC_VERSION
        and not BurdJournals.Server.normalizeJournalServerText(rewards.loreNoteText)
    then
        local loreNoteText = nil
        local openerName = nil
        if BurdJournals.Server.buildCursedLoreNote then
            loreNoteText, openerName, rewards.loreNoteTemplateFamily = BurdJournals.Server.buildCursedLoreNote(player, rewards)
        end
        rewards.loreNoteText = loreNoteText
        rewards.cursedUnleashedByName = openerName
    end
    rewards.isCursedJournal = false
    rewards.isHiddenCursedJournal = false
    rewards.cursedState = "unleashed"
    rewards.isCursedReward = true
    rewards.cursedEffectType = curseResult and curseResult.type or "panic"
    rewards.cursedUnleashedByCharacterId = BurdJournals.getPlayerCharacterId and BurdJournals.getPlayerCharacterId(player) or nil
    rewards.cursedUnleashedByUsername = player.getUsername and player:getUsername() or nil
    rewards.cursedUnleashedByName = rewards.cursedUnleashedByName
        or BurdJournals.Server.getJournalPlayerDisplayName(player)
    rewards.cursedUnleashedAtHours = getGameTime() and getGameTime():getWorldAgeHours() or 0
    if curseResult and curseResult.expired == true then
        rewards.curseExpired = true
        rewards.cursedAgeDaysAtOpen = curseResult.ageDays
        rewards.cursedExpirationDays = curseResult.thresholdDays
        rewards.cursedSourceTimestamp = liveData.timestamp or liveData.cursedSpawnedAtHours
    end
    rewards.cursedForcedEffectType = nil
    rewards.cursedForcedTraitId = nil
    rewards.cursedForcedSkillName = nil
    rewards.cursedInsightEffectType = nil
    rewards.cursedPendingRewards = nil

    local rewardJournal = nil
    local liveFullType = liveItem.getFullType and tostring(liveItem:getFullType() or "") or ""
    local canReuseHiddenCursedItem = liveHiddenCursed
        and liveFullType ~= (BurdJournals.CURSED_ITEM_TYPE or "BurdJournals.CursedJournal")
    if canReuseHiddenCursedItem then
        if not BurdJournals.Server.applyCursedRewardDataToExistingJournal(liveItem, rewards) then
            BurdJournals.Server.sendToClient(player, "error", {message = "Failed to materialize cursed rewards."})
            return
        end
        rewardJournal = liveItem
    else
        rewardJournal = BurdJournals.Server.materializeCursedRewardJournal(player, liveItem, rewards)
    end
    if not rewardJournal then
        BurdJournals.Server.sendToClient(player, "error", {message = "Failed to materialize cursed rewards."})
        return
    end

    local revealedReward = markLootRewardsRevealed(player, rewardJournal, rewards)
    if revealedReward and rewardJournal.transmitModData then
        rewardJournal:transmitModData()
    end

    if rewardJournal ~= liveItem then
        -- B41 inventory add/remove replication can arrive out of order, so send an
        -- explicit replacement notice to swap the sealed item for the bloody reward.
        BurdJournals.Server.sendToClient(player, "journalMaterialized", {
            oldJournalId = liveJournalId or (liveItem.getID and liveItem:getID()) or nil,
            oldJournalUUID = liveJournalUUID,
            newJournalId = rewardJournal.getID and rewardJournal:getID() or nil,
            journalUUID = rewards.uuid or liveJournalUUID,
            journalData = rewards,
            source = "openCursedJournal",
            exactOldJournalItem = true,
        })
        -- Add-on hook: a new reward journal item replaced the sealed one.
        if BurdJournals.runHooks then
            BurdJournals.runHooks("OnJournalMaterialized", player, liveItem, rewardJournal, rewards)
        end
    end

    local revealLead = nil
    local sealSoundEvent = nil
    if liveHiddenCursed then
        revealLead = getCursedServerText("UI_BurdJournals_CursedHiddenRevealLead", "The page turns. Something answers.")
    else
        sealSoundEvent = BurdJournals.Server.normalizeCursedSealSoundEvent(liveData.cursedSealSoundEvent)
        if sealSoundEvent == "none" then
            sealSoundEvent = nil
        end
        if not sealSoundEvent or sealSoundEvent == "" then
            if BurdJournals.getRandomCursedSealSoundEvent then
                sealSoundEvent = BurdJournals.getRandomCursedSealSoundEvent()
            end
        end
        if not sealSoundEvent or sealSoundEvent == "" then
            sealSoundEvent = BurdJournals.CURSED_DEFAULT_SOUND_EVENT or "PaperRip"
        end
    end

    -- Always emit a world sound when the seal breaks so nearby zombies react.
    emitCursedSealWorldSound(player, CURSED_SEAL_WORLD_SOUND_RADIUS, CURSED_SEAL_WORLD_SOUND_VOLUME)

    -- Add-on hook: the cursed journal has been fully opened and rewards materialized.
    if BurdJournals.runHooks then
        BurdJournals.runHooks("OnCursedJournalOpened", player, rewardJournal, rewards, curseResult)
    end

    BurdJournals.Server.sendToClient(player, "cursedOpened", {
        journalId = rewardJournal:getID(),
        journalUUID = rewards.uuid or liveJournalUUID,
        journalData = rewards,
        curseType = rewards.cursedEffectType or "panic",
        curseMessage = curseResult and curseResult.message or getCursedServerText("UI_BurdJournals_CursedMsgPanic", "A curse takes hold..."),
        curseExpired = curseResult and curseResult.expired == true or nil,
        curseAgeDays = curseResult and curseResult.ageDays or nil,
        curseExpirationDays = curseResult and curseResult.thresholdDays or nil,
        compatEffect = curseResult and curseResult.compatEffect or nil,
        soundEvent = sealSoundEvent,
        revealLead = revealLead,
        focusText = curseResult and curseResult.focusText or nil,
        focusType = curseResult and curseResult.focusType or nil,
        ambushNoiseRadius = ambushNoiseBase,
        ambushNoiseRadiusApplied = ambushNoiseRadiusApplied,
        ambushNoiseVolumeApplied = ambushNoiseVolumeApplied,
    })
end

function BurdJournals.Server.handleOpenYuletideJournal(player, args)
    if not player or type(args) ~= "table" then
        BurdJournals.Server.sendToClient(player, "error", {message = "Invalid Yuletide journal request."})
        return
    end

    local journalId = tonumber(args.journalId)
    local journalUUID = normalizeCommandJournalUUID(args)
    local confirm = args.confirm == true
    if not journalId and not journalUUID then
        BurdJournals.Server.sendToClient(player, "error", {message = "Invalid Yuletide journal request."})
        return
    end

    local item, resolvedJournalId, resolvedJournalUUID = resolveServerCommandJournal(player, args, "openYuletideJournal")
    if not item then
        BurdJournals.Server.sendToClient(player, "error", {message = "That Yuletide journal could not be found."})
        return
    end

    if not maybeMigrateRuntimeOnTouch(item, player, "openYuletideJournal") then
        return
    end
    if not enforceJournalLightRequirement(player, "openYuletideJournal") then
        return
    end
    local fullType = item.getFullType and item:getFullType() or ""
    local data = normalizeYuletideJournalStateForType(item, "openYuletideJournal")
    local healedPromptData = BurdJournals.Server.ensureYuletideJournalProfileData and BurdJournals.Server.ensureYuletideJournalProfileData(data)
    if fullType ~= (BurdJournals.YULETIDE_ITEM_TYPE or "BurdJournals.YuletideJournal")
        and not (type(data) == "table" and data.isYuletideJournal == true)
    then
        BurdJournals.Server.sendToClient(player, "error", {message = "That item is not a Yuletide journal."})
        return
    end

    resolvedJournalUUID = resolvedJournalUUID or getYuletideJournalUUID(item, data)
    if type(data) == "table" and data.yuletideState == BurdJournals.YULETIDE_STATE_UNWRAPPED then
        local recoveredGifts = {}
        local shouldRecoverGifts = not hasVerifiedYuletideGiftGrant(data)
        if shouldRecoverGifts then
            recoveredGifts = BurdJournals.Server.grantYuletideImmediateGifts(player, item, data)
        end
        local promptGifts = (#recoveredGifts > 0)
            and recoveredGifts
            or (shouldRecoverGifts and {} or sanitizeYuletideGiftList(data.yuletideImmediateGifts))
        local revealedPromptData = markLootRewardsRevealed(player, item, data)
        if (healedPromptData or revealedPromptData) and item.transmitModData then
            item:transmitModData()
        end
        BurdJournals.Server.sendToClient(player, "yuletideOpened", {
            journalId = item:getID(),
            journalUUID = resolvedJournalUUID,
            journalFingerprint = BurdJournals.buildJournalLookupFingerprint
                and BurdJournals.buildJournalLookupFingerprint(item, data)
                or nil,
            journalData = data,
            giftTier = data.yuletideGiftTier or "practical",
            gifts = promptGifts,
            clientMaterializeGifts = data.yuletidePendingClientGiftGrant == true and #promptGifts > 0,
            giftGrantToken = data.yuletideGiftGrantToken,
            messageKey = "UI_BurdJournals_YuletideAlreadyOpened",
            message = getYuletideServerText("UI_BurdJournals_YuletideAlreadyOpened", "The wrapping is already gone."),
        })
        return
    end

    if not confirm then
        local journalFingerprint = BurdJournals.buildJournalLookupFingerprint
            and BurdJournals.buildJournalLookupFingerprint(item, data)
            or nil
        BurdJournals.Server.sendToClient(player, "yuletideOpenPrompt", {
            journalId = (item.getID and item:getID()) or resolvedJournalId or journalId,
            journalUUID = resolvedJournalUUID,
            journalFingerprint = journalFingerprint,
            exactJournalItem = true,
            loreLine = getYuletideServerText(
                "UI_BurdJournals_YuletidePromptLore",
                "The wrapping is neat, the paper still bright. A gift waits inside."
            ),
            consequenceLine = getYuletideServerText(
                "UI_BurdJournals_YuletidePromptConsequence",
                "Unwrapping it will reveal the journal and its bundled supplies."
            ),
        })
        return
    end

    local liveItem, liveJournalId, liveJournalUUID = resolveServerCommandJournal(player, {
        journalId = resolvedJournalId or journalId,
        journalUUID = resolvedJournalUUID or journalUUID,
        journalFingerprint = args.journalFingerprint,
        exactJournalItem = args.exactJournalItem == true,
    }, "openYuletideJournalConfirm")
    if not liveItem then
        BurdJournals.Server.sendToClient(player, "error", {message = "That Yuletide journal could not be found."})
        return
    end

    if not maybeMigrateRuntimeOnTouch(liveItem, player, "openYuletideJournalConfirm") then
        return
    end
    if not enforceJournalLightRequirement(player, "openYuletideJournalConfirm") then
        return
    end
    local liveData = normalizeYuletideJournalStateForType(liveItem, "openYuletideJournalConfirm")
    local healedLiveData = BurdJournals.Server.ensureYuletideJournalProfileData and BurdJournals.Server.ensureYuletideJournalProfileData(liveData)
    liveJournalUUID = liveJournalUUID or getYuletideJournalUUID(liveItem, liveData)
    if type(liveData) ~= "table" or liveData.isYuletideJournal ~= true then
        BurdJournals.Server.sendToClient(player, "error", {message = "That item is not a Yuletide journal."})
        return
    end
    if liveData.yuletideState == BurdJournals.YULETIDE_STATE_UNWRAPPED then
        local recoveredLiveGifts = {}
        local shouldRecoverLiveGifts = not hasVerifiedYuletideGiftGrant(liveData)
        if shouldRecoverLiveGifts then
            recoveredLiveGifts = BurdJournals.Server.grantYuletideImmediateGifts(player, liveItem, liveData)
        end
        local livePromptGifts = (#recoveredLiveGifts > 0)
            and recoveredLiveGifts
            or (shouldRecoverLiveGifts and {} or sanitizeYuletideGiftList(liveData.yuletideImmediateGifts))
        local revealedLiveData = markLootRewardsRevealed(player, liveItem, liveData)
        if (healedLiveData or revealedLiveData) and liveItem.transmitModData then
            liveItem:transmitModData()
        end
        BurdJournals.Server.sendToClient(player, "yuletideOpened", {
            journalId = liveJournalId or (liveItem.getID and liveItem:getID()) or nil,
            journalUUID = liveJournalUUID,
            journalFingerprint = BurdJournals.buildJournalLookupFingerprint
                and BurdJournals.buildJournalLookupFingerprint(liveItem, liveData)
                or nil,
            journalData = liveData,
            giftTier = liveData.yuletideGiftTier or "practical",
            gifts = livePromptGifts,
            clientMaterializeGifts = liveData.yuletidePendingClientGiftGrant == true and #livePromptGifts > 0,
            giftGrantToken = liveData.yuletideGiftGrantToken,
            messageKey = "UI_BurdJournals_YuletideAlreadyOpened",
            message = getYuletideServerText("UI_BurdJournals_YuletideAlreadyOpened", "The wrapping is already gone."),
        })
        return
    end

    local grantedGifts = {}
    if not hasVerifiedYuletideGiftGrant(liveData) then
        grantedGifts = BurdJournals.Server.grantYuletideImmediateGifts(player, liveItem, liveData)
    end
    local unwrappedPayload = BurdJournals.normalizeJournalData and BurdJournals.normalizeJournalData(liveData) or nil
    if type(unwrappedPayload) ~= "table" then
        BurdJournals.Server.sendToClient(player, "error", {message = "Failed to prepare the Yuletide journal."})
        return
    end
    if tonumber(unwrappedPayload.loreNoteTemplateVersion) == LORE_DYNAMIC_VERSION
        and not BurdJournals.Server.normalizeJournalServerText(unwrappedPayload.loreNoteText)
    then
        local loreNoteText = nil
        local openerName = nil
        if BurdJournals.Server.buildYuletideLoreNote then
            loreNoteText, openerName, unwrappedPayload.loreNoteTemplateFamily = BurdJournals.Server.buildYuletideLoreNote(player, unwrappedPayload)
        end
        unwrappedPayload.loreNoteText = loreNoteText
        unwrappedPayload.yuletideOpenedByName = openerName
    end
    unwrappedPayload.yuletideOpenedByName = unwrappedPayload.yuletideOpenedByName
        or BurdJournals.Server.getJournalPlayerDisplayName(player)
    unwrappedPayload.yuletideState = BurdJournals.YULETIDE_STATE_UNWRAPPED
    unwrappedPayload.yuletidePendingDelivery = false
    markLootRewardsRevealed(player, liveItem, unwrappedPayload)

    unwrappedPayload.yuletideBeacon = nil

    local unwrappedItem = BurdJournals.Server.materializeCursedRewardJournal(
        player,
        liveItem,
        unwrappedPayload,
        BurdJournals.YULETIDE_ITEM_TYPE or "BurdJournals.YuletideJournal",
        false
    )
    if not unwrappedItem then
        BurdJournals.Server.sendToClient(player, "error", {message = "Failed to unwrap the Yuletide journal."})
        return
    end
    local store = BurdJournals.Server.getYuletideDeliveryStore()
    if store and clearYuletideBeacon(store, liveJournalUUID) then
        BurdJournals.Server.transmitYuletideDeliveryStore()
    end
    local unwrappedModData = unwrappedItem.getModData and unwrappedItem:getModData() or nil
    local unwrappedData = unwrappedModData and unwrappedModData.BurdJournals or unwrappedPayload
    if unwrappedItem ~= liveItem then
        BurdJournals.Server.sendToClient(player, "journalMaterialized", {
            oldJournalId = liveJournalId or (liveItem.getID and liveItem:getID()) or nil,
            oldJournalUUID = liveJournalUUID,
            newJournalId = unwrappedItem.getID and unwrappedItem:getID() or nil,
            journalUUID = liveJournalUUID,
            journalData = unwrappedData,
            source = "openYuletideJournal",
            exactOldJournalItem = true,
        })
    end

    BurdJournals.Server.sendToClient(player, "yuletideOpened", {
        journalId = unwrappedItem.getID and unwrappedItem:getID() or liveJournalId,
        journalUUID = liveJournalUUID,
        journalFingerprint = BurdJournals.buildJournalLookupFingerprint
            and BurdJournals.buildJournalLookupFingerprint(unwrappedItem, unwrappedData)
            or nil,
        journalData = unwrappedData,
        exactJournalItem = true,
        giftTier = unwrappedData.yuletideGiftTier or "practical",
        gifts = grantedGifts,
        clientMaterializeGifts = unwrappedData.yuletidePendingClientGiftGrant == true and #grantedGifts > 0,
        giftGrantToken = unwrappedData.yuletideGiftGrantToken,
        messageKey = "UI_BurdJournals_YuletideOpened",
        message = getYuletideServerText("UI_BurdJournals_YuletideOpened", "You unwrap the gift and find a journal inside."),
        soundEvent = (BurdJournals.getRandomYuletideUnwrapSoundEvent and BurdJournals.getRandomYuletideUnwrapSoundEvent())
            or BurdJournals.YULETIDE_DEFAULT_UNWRAP_SOUND_EVENT
            or BurdJournals.YULETIDE_UNWRAP_SOUND_EVENT
            or "PaperRip",
    })
end

-- =====================================================================
-- Generic sealed-journal "break the seal" handler.
-- ---------------------------------------------------------------------
-- Serves any journal registered via BurdJournals.registerSealedJournalType.
-- Flips sealedState sealed -> broken, reveals hidden reward contents, fires
-- the "OnJournalSealBroken" hook (add-ons inject their unseal payload here,
-- e.g. Curses & Blessings applies blessings), then refreshes name/icon and
-- notifies the client. Idempotent: re-breaking an already-broken seal just
-- re-sends the "opened" acknowledgement without re-firing the payload hook.
-- =====================================================================
function BurdJournals.Server.handleBreakJournalSeal(player, args)
    if not player or type(args) ~= "table" then
        BurdJournals.Server.sendToClient(player, "error", {message = "Invalid sealed journal request."})
        return
    end

    local item = resolveServerCommandJournal(player, args, "breakJournalSeal")
    if not item then
        BurdJournals.Server.sendToClient(player, "error", {message = "That sealed journal could not be found."})
        return
    end

    if not maybeMigrateRuntimeOnTouch(item, player, "breakJournalSeal") then
        return
    end
    if not enforceJournalLightRequirement(player, "breakJournalSeal") then
        return
    end

    local sealedEntry, data = BurdJournals.getSealedJournalType(item)
    if sealedEntry and type(data) ~= "table" and item.getModData then
        local md = item:getModData()
        md.BurdJournals = type(md.BurdJournals) == "table" and md.BurdJournals or {}
        data = md.BurdJournals
        data.journalTypeId = data.journalTypeId or sealedEntry.fullType
        data.journalKind = data.journalKind or "reward"
        data.sourceType = data.sourceType or "loot"
        data.originMode = data.originMode or "loot"
        data.sealedState = data.sealedState or BurdJournals.SEALED_STATE_SEALED
        data.sealedTypeKey = data.sealedTypeKey or sealedEntry.fullType
        data.lootRewardsRevealed = data.lootRewardsRevealed == true
        data.isPlayerCreated = false
        if type(sealedEntry.dataMarker) == "string" and sealedEntry.dataMarker ~= "" then
            data[sealedEntry.dataMarker] = true
        end
    end
    if not sealedEntry or type(data) ~= "table" then
        BurdJournals.Server.sendToClient(player, "error", {message = "That item is not a sealed journal."})
        return
    end

    local journalUUID = nil
    if BurdJournals.resolveJournalUUIDForRuntime then
        journalUUID = BurdJournals.resolveJournalUUIDForRuntime(data, item, true)
    end
    journalUUID = journalUUID or data.uuid

    local alreadyBroken = data.sealedState == BurdJournals.SEALED_STATE_BROKEN

    if not alreadyBroken then
        -- Flip the seal and reveal any concealed reward contents.
        BurdJournals.setSealedState(item, BurdJournals.SEALED_STATE_BROKEN)
        markLootRewardsRevealed(player, item, data)
        data.sealBrokenByName = data.sealBrokenByName
            or BurdJournals.Server.getJournalPlayerDisplayName(player)

        -- Add-on payload injection point. Handlers receive everything needed to
        -- mutate the live item's journalData and apply effects to the player.
        BurdJournals.runHooks("OnJournalSealBroken", player, item, data, sealedEntry)

        BurdJournals.updateJournalName(item, true)
        BurdJournals.updateJournalIcon(item)
        if item.transmitModData then
            item:transmitModData()
        end
    end

    BurdJournals.Server.sendToClient(player, "journalSealBroken", {
        journalId = item.getID and item:getID() or nil,
        journalUUID = journalUUID,
        journalFingerprint = BurdJournals.buildJournalLookupFingerprint
            and BurdJournals.buildJournalLookupFingerprint(item, data)
            or nil,
        journalData = data,
        sealedTypeKey = sealedEntry.fullType,
        themeKey = sealedEntry.themeKey,
        alreadyBroken = alreadyBroken,
        breakCommand = sealedEntry.breakCommand,
    })
end

function BurdJournals.Server.handleYuletideGiftMaterialized(player, args)
    if not player or type(args) ~= "table" then
        return
    end

    local item = resolveServerCommandJournal(player, args, "yuletideGiftMaterialized")
    if not item then
        BurdJournals.debugPrint("[BurdJournals] Yuletide gift materialize ack ignored because journal could not be found.")
        return
    end
    local data = normalizeYuletideJournalStateForType(item, "yuletideGiftMaterialized")
    if type(data) ~= "table" or data.isYuletideJournal ~= true then
        return
    end

    local expectedToken = tostring(data.yuletideGiftGrantToken or "")
    local receivedToken = tostring(args.giftGrantToken or "")
    if expectedToken == "" or receivedToken == "" or expectedToken ~= receivedToken then
        BurdJournals.debugPrint("[BurdJournals] Yuletide gift materialize ack rejected for token mismatch.")
        return
    end

    if data.yuletidePendingClientGiftGrant == true then
        data.yuletideGiftGranted = true
        data.yuletideGiftGrantVersion = YULETIDE_GIFT_GRANT_VERSION
        data.yuletidePendingClientGiftGrant = nil
        data.yuletidePendingClientGifts = nil
        if item.transmitModData then
            item:transmitModData()
        end
        BurdJournals.debugPrint("[BurdJournals] Yuletide client gift grant acknowledged for "
            .. tostring(getYuletideJournalUUID(item, data)))
    end
end

-- Server-side function to get skill baseline - checks server cache first, then player modData
function BurdJournals.Server.getSkillBaselineForPlayer(player, skillName)
    if not player or not skillName then return 0 end

    local cacheXP = nil
    -- First, try to get baseline from server cache (more reliable on dedicated servers)
    local characterId = BurdJournals.getPlayerCharacterId(player)
    if characterId then
        local cachedBaseline = BurdJournals.Server.getCachedBaseline(characterId, player)
        if cachedBaseline and cachedBaseline.skillBaseline then
            local xp = cachedBaseline.skillBaseline[skillName]
            if xp then
                cacheXP = math.max(0, tonumber(xp) or 0)
            end
        end
    end

    local storedBaselineXP = 0
    local modData = nil
    if player.getModData then
        modData = player:getModData()
    end
    if modData and modData.BurdJournals and modData.BurdJournals.skillBaseline then
        storedBaselineXP = math.max(0, tonumber(modData.BurdJournals.skillBaseline[skillName]) or 0)
    end

    local resolvedBaselineXP = cacheXP ~= nil and cacheXP or storedBaselineXP
    if resolvedBaselineXP > 0 then
        if cacheXP ~= nil then
            BurdJournals.debugPrint("[BurdJournals] Server: Got baseline for " .. skillName .. " from SERVER CACHE: " .. tostring(cacheXP))
        elseif storedBaselineXP > 0 then
            BurdJournals.debugPrint("[BurdJournals] Server: Got baseline for " .. skillName .. " from player/shared baseline: " .. tostring(storedBaselineXP))
        end
    end
    return resolvedBaselineXP
end

function BurdJournals.Server.getMediaSkillBaselineForPlayer(player, skillName)
    if not player or not skillName then return 0 end

    local characterId = BurdJournals.getPlayerCharacterId(player)
    if characterId then
        local cachedBaseline = BurdJournals.Server.getCachedBaseline(characterId, player)
        if cachedBaseline then
            if type(cachedBaseline.mediaSkillBaseline) ~= "table" then
                cachedBaseline.mediaSkillBaseline = BurdJournals.getPlayerVhsSkillXPMapCopy
                    and BurdJournals.getPlayerVhsSkillXPMapCopy(player)
                    or {}
                if characterId then
                    BurdJournals.Server.storeBaselineArchiveRecord(characterId, cachedBaseline, true)
                end
                if BurdJournals.Server.transmitBaselineStores then
                    BurdJournals.Server.transmitBaselineStores(true)
                elseif ModData.transmit and BurdJournals.Server.isTrueSinglePlayerContext and BurdJournals.Server.isTrueSinglePlayerContext() then
                    ModData.transmit("BurdJournals_PlayerBaselines")
                end
            end

            local xp = tonumber(cachedBaseline.mediaSkillBaseline[skillName]) or 0
            if xp > 0 then
                return xp
            end
        end
    end

    local modData = player:getModData()
    if modData and modData.BurdJournals and modData.BurdJournals.mediaSkillBaseline then
        local xp = tonumber(modData.BurdJournals.mediaSkillBaseline[skillName]) or 0
        if xp > 0 then
            return xp
        end
    end

    return 0
end

function BurdJournals.Server.getSkillExportBaselineForPlayer(player, skillName)
    if not player or not skillName then return 0 end

    local cacheXP = nil
    local characterId = BurdJournals.getPlayerCharacterId(player)
    if characterId then
        local cachedBaseline = BurdJournals.Server.getCachedBaseline(characterId, player)
        if cachedBaseline and cachedBaseline.skillExportBaseline then
            local xp = cachedBaseline.skillExportBaseline[skillName]
            if xp then
                cacheXP = math.max(0, tonumber(xp) or 0)
            end
        end
    end

    local storedXP = 0
    local modData = player.getModData and player:getModData() or nil
    if modData and modData.BurdJournals and modData.BurdJournals.skillExportBaseline then
        storedXP = math.max(0, tonumber(modData.BurdJournals.skillExportBaseline[skillName]) or 0)
    end

    return cacheXP ~= nil and cacheXP or storedXP
end

function BurdJournals.Server.getMediaSkillExportBaselineForPlayer(player, skillName)
    if not player or not skillName then return 0 end

    local characterId = BurdJournals.getPlayerCharacterId(player)
    if characterId then
        local cachedBaseline = BurdJournals.Server.getCachedBaseline(characterId, player)
        if cachedBaseline and type(cachedBaseline.mediaSkillExportBaseline) == "table" then
            return math.max(0, tonumber(cachedBaseline.mediaSkillExportBaseline[skillName]) or 0)
        end
    end

    local modData = player:getModData()
    if modData and modData.BurdJournals and type(modData.BurdJournals.mediaSkillExportBaseline) == "table" then
        return math.max(0, tonumber(modData.BurdJournals.mediaSkillExportBaseline[skillName]) or 0)
    end

    return 0
end

function BurdJournals.Server.getTrackedVhsSkillXPForPlayer(player, skillName)
    if not player or not skillName then
        return 0
    end

    if BurdJournals.getPlayerVhsSkillXP then
        return math.max(0, tonumber(BurdJournals.getPlayerVhsSkillXP(player, skillName)) or 0)
    end

    local modData = player:getModData()
    local xpMap = modData and modData.BurdJournals and modData.BurdJournals.vhsSkillXP
    if type(xpMap) == "table" then
        return math.max(0, tonumber(xpMap[skillName]) or 0)
    end

    return 0
end

function BurdJournals.Server.getTrackedVhsSkillXPDeltaForPlayer(player, skillName, useBaseline)
    local trackedTotal = BurdJournals.Server.getTrackedVhsSkillXPForPlayer(player, skillName)
    if trackedTotal <= 0 then
        return 0, trackedTotal, 0
    end

    if not useBaseline then
        return trackedTotal, trackedTotal, 0
    end

    local trackedBaseline = BurdJournals.Server.getMediaSkillBaselineForPlayer(player, skillName)
    local trackedDelta = math.max(0, trackedTotal - trackedBaseline)
    return trackedDelta, trackedTotal, trackedBaseline
end

function BurdJournals.Server.markJournalSkillMediaLinesKnown(player, skillData, skillName, context)
    if not player or type(skillData) ~= "table" then
        return 0
    end

    local lineMap = skillData.vhsMediaLines or skillData.mediaLines
    if type(lineMap) ~= "table" then
        return 0
    end

    local marked = 0
    local modData = nil
    if player.getModData then
        modData = player:getModData()
    end
    local bj = nil
    if modData then
        modData.BurdJournals = modData.BurdJournals or {}
        bj = modData.BurdJournals
        bj.vhsJournalKnownLines = bj.vhsJournalKnownLines or {}
    end

    for lineGuid, lineData in pairs(lineMap) do
        local guid = type(lineGuid) == "string" and lineGuid or nil
        if not guid and type(lineData) == "table" and type(lineData.lineGuid) == "string" then
            guid = lineData.lineGuid
        end

        if guid and guid ~= "" then
            local appliesToSkill = true
            if type(skillName) == "string" and type(lineData) == "table" and type(lineData.skills) == "table" then
                appliesToSkill = (tonumber(lineData.skills[skillName]) or 0) > 0
            end

            if appliesToSkill then
                local alreadyKnown = false
                if player.isKnownMediaLine then
                    alreadyKnown = player:isKnownMediaLine(guid) == true
                end
                if not alreadyKnown and player.addKnownMediaLine then
                    player:addKnownMediaLine(guid)
                    marked = marked + 1
                end
                if bj and type(bj.vhsJournalKnownLines) == "table" then
                    bj.vhsJournalKnownLines[guid] = true
                end
            end
        end
    end

    if marked > 0 and player.transmitModData and not BurdJournals.Server.shouldDeferBatchTransmit(context) then
        player:transmitModData()
    end

    return marked
end

-- Debug baseline edits are intentionally synthetic and should not force
-- minimum claim XP floors for player journals.
function BurdJournals.Server.isBaselineDebugModifiedForPlayer(player)
    if not player then return false end

    local characterId = BurdJournals.getPlayerCharacterId(player)
    if characterId then
        local cachedBaseline = BurdJournals.Server.getCachedBaseline(characterId, player)
        if cachedBaseline and cachedBaseline.debugModified ~= nil then
            return cachedBaseline.debugModified == true
        end
    end

    local modData = player:getModData()
    if modData and modData.BurdJournals and modData.BurdJournals.debugModified == true then
        return true
    end

    return false
end

-- Resolve the post-claim total XP target for a journal claim.
-- Baseline-aware player journals store earned/delta XP, so their effective
-- target is the player's current total plus that earned delta. Legacy absolute
-- entries remain exact/set targets for backward compatibility.
function BurdJournals.Server.getSkillClaimTargetXP(player, journalData, skillName, recordedXP, baselineXPHint)
    local targetXP = math.max(0, tonumber(recordedXP) or 0)
    local baselineXP = 0
    local baselineSuppressed = false
    local claimUsesEarnedDeltaGrant = false
    local recordedLevel = 0
    if type(journalData) == "table" and type(journalData.skills) == "table" then
        local storedSkillKey = BurdJournals.resolveSkillKey and BurdJournals.resolveSkillKey(journalData.skills, skillName) or skillName
        if type(journalData.skills[storedSkillKey]) == "table" then
            recordedLevel = tonumber(journalData.skills[storedSkillKey].level) or 0
        end
    end
    local useBaselineMode = BurdJournals.getJournalSkillRecordingMode
        and BurdJournals.getJournalSkillRecordingMode(journalData, player)
        or (type(journalData) == "table" and journalData.recordedWithBaseline == true)

    if player
        and type(journalData) == "table"
        and journalData.isPlayerCreated == true
        and useBaselineMode == true
    then
        baselineSuppressed = BurdJournals.Server.isBaselineDebugModifiedForPlayer
            and BurdJournals.Server.isBaselineDebugModifiedForPlayer(player)
            or false
        if not baselineSuppressed then
            baselineXP = math.max(0, tonumber(BurdJournals.Server.getSkillBaselineForPlayer(player, skillName)) or 0)
        end
        local legacyAbsolute = BurdJournals.isLikelyLegacyAbsoluteSkillEntry
            and BurdJournals.isLikelyLegacyAbsoluteSkillEntry(journalData, player, skillName, targetXP, recordedLevel, nil, baselineXP)
            or false
        if not legacyAbsolute then
            local perk = BurdJournals.getPerkByName and BurdJournals.getPerkByName(skillName)
            local currentXP = 0
            if perk and player and player.getXp then
                currentXP = math.max(
                    0,
                    tonumber(BurdJournals.getPlayerSkillTotalXP and BurdJournals.getPlayerSkillTotalXP(player, perk, skillName) or player:getXp():getXP(perk)) or 0
                )
            end
            if not baselineSuppressed then
                local hintedBaselineXP = math.max(0, tonumber(baselineXPHint) or 0)
                hintedBaselineXP = math.min(currentXP, hintedBaselineXP)
                if hintedBaselineXP > baselineXP then
                    BurdJournals.debugPrint("[BurdJournals] Server: Using restrictive claim baseline hint for "
                        .. tostring(skillName) .. " (server=" .. tostring(baselineXP)
                        .. ", hint=" .. tostring(hintedBaselineXP) .. ")")
                    baselineXP = hintedBaselineXP
                end
            end
            local currentLevel = 0
            if perk and player and player.getPerkLevel then
                currentLevel = math.max(0, tonumber(player:getPerkLevel(perk)) or 0)
            end
            -- Detect a genuinely MISSING baseline record (vs a legitimate baseline
            -- of 0). On long-running servers the cached baseline can be pruned/lost;
            -- with baselineXP defaulting to 0 the earned-delta math below would clamp
            -- the grant to the player's current XP and silently award nothing.
            local baselineRecordMissing = false
            if not baselineSuppressed and baselineXP == 0 then
                local hasRecord = false
                local cid = BurdJournals.getPlayerCharacterId and BurdJournals.getPlayerCharacterId(player)
                if cid and BurdJournals.Server.getCachedBaseline then
                    local cb = BurdJournals.Server.getCachedBaseline(cid, player)
                    if cb and cb.skillBaseline then hasRecord = true end
                end
                if not hasRecord then
                    local md = player.getModData and player:getModData()
                    if md and md.BurdJournals and md.BurdJournals.skillBaseline then hasRecord = true end
                end
                baselineRecordMissing = not hasRecord
            end
            local isPassiveSkill = (BurdJournals.isPassiveSkill and BurdJournals.isPassiveSkill(skillName))
                or (skillName == "Fitness" or skillName == "Strength")
            if recordedLevel > 0 and (currentLevel > recordedLevel or (isPassiveSkill and currentLevel >= recordedLevel)) then
                targetXP = currentXP
            elseif baselineRecordMissing then
                -- Cannot compute the earned delta without a baseline; grant the
                -- recorded earned XP additively (it is the player's own progress)
                -- rather than awarding nothing. The claim-lock check below still
                -- prevents re-granting on a reusable player journal.
                targetXP = currentXP + math.max(0, tonumber(targetXP) or 0)
                BurdJournals.debugPrint("[BurdJournals] Server: baseline record missing for "
                    .. tostring(skillName) .. "; granting recorded earned XP additively")
            else
                local currentEarnedXP = math.max(0, currentXP - baselineXP)
                local missingEarnedXP = math.max(0, targetXP - currentEarnedXP)
                targetXP = currentXP + missingEarnedXP
            end
            if BurdJournals.getActivePlayerJournalSkillClaimLock
                and BurdJournals.getActivePlayerJournalSkillClaimLock(journalData, player, skillName, recordedXP, targetXP, currentXP, currentLevel) then
                targetXP = currentXP
            end
            claimUsesEarnedDeltaGrant = true
        end
    end

    return targetXP, baselineXP, baselineSuppressed, claimUsesEarnedDeltaGrant
end

local function isLikelyAbsoluteSkillEntryForBaseline(storedXP, earnedXP, actualXP)
    local stored = math.max(0, tonumber(storedXP) or 0)
    local earned = math.max(0, tonumber(earnedXP) or 0)
    local actual = math.max(0, tonumber(actualXP) or 0)
    if stored <= 0 or actual <= 0 then
        return false
    end
    return stored > (earned + 0.001) and stored <= (actual + 0.001)
end

function BurdJournals.Server.validateSkillPayload(skills, player, useBaselineOverride, journalData)
    if skills == nil then return nil end
    if type(skills) ~= "table" then
        bsjWriteLogLine("[BurdJournals] WARNING: Invalid skills payload (not a table) from " .. tostring(player and player:getUsername() or "unknown"))
        return nil
    end

    local validSkills = {}
    local allowedSkills = BurdJournals.getAllowedSkills and BurdJournals.getAllowedSkills() or {}
    local allowedSet = {}
    for _, name in ipairs(allowedSkills) do allowedSet[name] = true end
    local playerJournalContext = {isPlayerCreated = true}

    -- Get baseline using the correct accessor
    local useBaseline
    if type(useBaselineOverride) == "boolean" then
        useBaseline = useBaselineOverride
    else
        useBaseline = BurdJournals.shouldUseBaselineForPlayerJournalRecording and BurdJournals.shouldUseBaselineForPlayerJournalRecording(player) or false
    end
    if useBaseline and BurdJournals.Server.isBaselineDebugModifiedForPlayer and BurdJournals.Server.isBaselineDebugModifiedForPlayer(player) then
        useBaseline = false
        BurdJournals.debugPrint("[BurdJournals] validateSkillPayload: baseline restriction suppressed because debug baseline edits are active")
    end
    local allowVhsSkillRecording = BurdJournals.isVhsSkillRecordingEnabled and BurdJournals.isVhsSkillRecordingEnabled() or false

    -- Debug: Check if we have cached baseline for this player
    local characterId = BurdJournals.getPlayerCharacterId(player)
    local hasCachedBaseline = false
    local hasModDataBaseline = false
    local cachedBaseline = nil

    if characterId then
        cachedBaseline = BurdJournals.Server.getCachedBaseline(characterId, player)
        hasCachedBaseline = cachedBaseline ~= nil and cachedBaseline.skillBaseline ~= nil
    end

    -- Also check player modData
    local modData = player:getModData()
    if modData and modData.BurdJournals and modData.BurdJournals.skillBaseline then
        hasModDataBaseline = true
    end

    BurdJournals.debugPrint("[BurdJournals] validateSkillPayload: useBaseline=" .. tostring(useBaseline) .. ", characterId=" .. tostring(characterId) .. ", hasCachedBaseline=" .. tostring(hasCachedBaseline) .. ", hasModDataBaseline=" .. tostring(hasModDataBaseline))

    -- WARNING: If baseline restriction is enabled but we have NO baseline data, log a warning
    -- This could cause skills to be rejected incorrectly
    if useBaseline and not hasCachedBaseline and not hasModDataBaseline then
        bsjWriteLogLine("[BurdJournals] WARNING: Baseline restriction enabled but NO baseline data found for player " .. tostring(player:getUsername()) .. "! This may cause skills to be rejected incorrectly.")
        BurdJournals.debugPrint("[BurdJournals] The player's baseline may not have been captured. Consider asking them to close and reopen the journal, or disable 'Only Record Earned Progress' sandbox option.")
    end

    for skillName, skillData in pairs(skills) do
        local requestedSkillName = skillName
        if type(skillName) == "string" and not allowedSet[skillName] and BurdJournals.resolveSkillKey then
            local resolvedAllowedSkillName = BurdJournals.resolveSkillKey(allowedSet, skillName)
            if resolvedAllowedSkillName and allowedSet[resolvedAllowedSkillName] then
                skillName = resolvedAllowedSkillName
            end
        end

        if type(requestedSkillName) ~= "string" then
            bsjWriteLogLine("[BurdJournals] WARNING: Invalid skill name type: " .. type(requestedSkillName))

        elseif not allowedSet[skillName] then
            bsjWriteLogLine("[BurdJournals] WARNING: Unknown skill name: " .. requestedSkillName)

        elseif BurdJournals.isSkillEnabledForJournal and not BurdJournals.isSkillEnabledForJournal(playerJournalContext, skillName) then
            BurdJournals.debugPrint("[BurdJournals] validateSkillPayload: Skipping disabled skill for player journals: " .. tostring(skillName))

        elseif type(skillData) ~= "table" then
            bsjWriteLogLine("[BurdJournals] WARNING: Invalid skill data type for " .. skillName .. ": " .. type(skillData))
        else
            -- SERVER-SIDE VALIDATION: Get actual player XP, don't trust client values
            local perk = BurdJournals.getPerkByName(skillName)
            if perk then
                local actualXP = BurdJournals.getPlayerSkillTotalXP and BurdJournals.getPlayerSkillTotalXP(player, perk, skillName) or player:getXp():getXP(perk)
                local actualLevel = player:getPerkLevel(perk)

                -- Apply baseline if enabled (Only Record Earned Progress)
                local earnedXP = actualXP
                local baselineXP = 0
                local baselineHintXP = math.max(0, tonumber(skillData and skillData.baselineXP) or 0)
                local exportGateXP = actualXP
                local exportBaselineXP = 0
                local trackedTotal = 0
                local trackedBaseline = 0
                local trackedExportBaseline = 0
                if useBaseline then
                    -- Use server-side baseline retrieval (checks cache first)
                    baselineXP = BurdJournals.Server.getSkillBaselineForPlayer(player, skillName) or 0
                    baselineHintXP = math.min(math.max(0, tonumber(actualXP) or 0), baselineHintXP)
                    if baselineHintXP > baselineXP then
                        BurdJournals.debugPrint("[BurdJournals] validateSkillPayload: " .. skillName
                            .. " using restrictive baseline hint fallback (server=" .. tostring(baselineXP)
                            .. ", hint=" .. tostring(baselineHintXP) .. ")")
                        baselineXP = baselineHintXP
                    end
                    earnedXP = math.max(0, actualXP - baselineXP)
                    exportBaselineXP = math.max(
                        baselineXP,
                        tonumber(BurdJournals.Server.getSkillExportBaselineForPlayer(player, skillName)) or 0
                    )
                    exportGateXP = math.max(0, actualXP - exportBaselineXP)
                    BurdJournals.debugPrint("[BurdJournals] validateSkillPayload: " .. skillName .. " actualXP=" .. tostring(actualXP) .. ", baselineXP=" .. tostring(baselineXP) .. ", earnedXP=" .. tostring(earnedXP))
                else
                    BurdJournals.debugPrint("[BurdJournals] validateSkillPayload: " .. skillName .. " actualXP=" .. tostring(actualXP) .. " (baseline disabled)")
                end

                local rawEarnedXP = math.max(0, tonumber(earnedXP) or 0)
                local vhsExcludedXP = 0
                local trackedDelta = 0
                trackedDelta, trackedTotal, trackedBaseline = BurdJournals.Server.getTrackedVhsSkillXPDeltaForPlayer(player, skillName, useBaseline)
                if not allowVhsSkillRecording then
                    if trackedDelta > 0 then
                        local earnedBeforeVhs = math.max(0, tonumber(earnedXP) or 0)
                        local safeTrackedDelta = math.max(0, tonumber(trackedDelta) or 0)

                        -- Guard against stale/duplicated VHS tracking data.
                        -- If tracked VHS exceeds currently earned XP, subtracting it would
                        -- incorrectly zero out legitimate progress and break recording.
                        if safeTrackedDelta > (earnedBeforeVhs + 0.001) then
                            BurdJournals.debugPrint("[BurdJournals] validateSkillPayload: " .. skillName
                                .. " VHS tracking out of sync; skipping subtraction (trackedDelta=" .. tostring(safeTrackedDelta)
                                .. ", earnedBeforeVhs=" .. tostring(earnedBeforeVhs)
                                .. ", total=" .. tostring(trackedTotal)
                                .. ", baseline=" .. tostring(trackedBaseline) .. ")")
                            safeTrackedDelta = 0
                        end

                        if safeTrackedDelta > 0 then
                            earnedXP = math.max(0, earnedBeforeVhs - safeTrackedDelta)
                            vhsExcludedXP = math.max(0, earnedBeforeVhs - earnedXP)
                            BurdJournals.debugPrint("[BurdJournals] validateSkillPayload: " .. skillName
                                .. " subtracting VHS XP delta=" .. tostring(safeTrackedDelta)
                                .. " (total=" .. tostring(trackedTotal)
                                .. ", baseline=" .. tostring(trackedBaseline)
                                .. "), finalEarned=" .. tostring(earnedXP))
                        end
                    end

                    if useBaseline and trackedTotal > 0 then
                        trackedExportBaseline = math.max(
                            trackedBaseline,
                            tonumber(BurdJournals.Server.getMediaSkillExportBaselineForPlayer(player, skillName)) or 0
                        )
                        local trackedExportDelta = math.max(0, trackedTotal - trackedExportBaseline)
                        if trackedExportDelta > (exportGateXP + 0.001) then
                            BurdJournals.debugPrint("[BurdJournals] validateSkillPayload: " .. skillName
                                .. " export VHS tracking out of sync; skipping export subtraction (trackedDelta=" .. tostring(trackedExportDelta)
                                .. ", exportGate=" .. tostring(exportGateXP)
                                .. ", total=" .. tostring(trackedTotal)
                                .. ", exportBaseline=" .. tostring(trackedExportBaseline) .. ")")
                            trackedExportDelta = 0
                        end
                        if trackedExportDelta > 0 then
                            exportGateXP = math.max(0, exportGateXP - trackedExportDelta)
                        end
                    end
                end

                local currentJournalXP = 0
                if type(journalData) == "table" and type(journalData.skills) == "table" then
                    local existingSkillKey = BurdJournals.resolveSkillKey and BurdJournals.resolveSkillKey(journalData.skills, skillName) or skillName
                    local existingSkill = journalData.skills[existingSkillKey]
                    currentJournalXP = math.max(0, tonumber(type(existingSkill) == "table" and existingSkill.xp or existingSkill) or 0)
                end

                -- Only record if there's actual earned XP
                local shouldAccept = earnedXP > 0
                if shouldAccept and useBaseline then
                    if currentJournalXP > 0 then
                        shouldAccept = earnedXP > (currentJournalXP + 0.001)
                    end
                end

                if shouldAccept then
                    if actualLevel <= 0
                        and (skillName == "Fitness" or skillName == "Strength")
                        and actualXP > 0
                        and BurdJournals.getSkillLevelFromXP
                    then
                        actualLevel = math.max(0, tonumber(BurdJournals.getSkillLevelFromXP(actualXP, skillName)) or 0)
                    end
                    local vhsMediaLines = nil
                    if allowVhsSkillRecording and trackedTotal > 0 and BurdJournals.getPlayerVhsMediaLinesForSkill then
                        vhsMediaLines = BurdJournals.getPlayerVhsMediaLinesForSkill(player, skillName, useBaseline and trackedBaseline or 0)
                    end
                    validSkills[skillName] = {
                        xp = earnedXP,
                        level = actualLevel,
                        rawXP = rawEarnedXP,
                        vhsExcludedXP = vhsExcludedXP,
                        exportSkillXP = math.max(0, tonumber(actualXP) or 0),
                        exportMediaSkillXP = math.max(0, tonumber(trackedTotal) or 0),
                        vhsMediaLines = vhsMediaLines
                    }
                    BurdJournals.debugPrint("[BurdJournals] validateSkillPayload: " .. skillName .. " ACCEPTED")
                else
                    BurdJournals.debugPrint("[BurdJournals] validateSkillPayload: " .. skillName .. " REJECTED (no new exportable earned XP)")
                end
            else
                bsjWriteLogLine("[BurdJournals] WARNING: Could not find perk for skill: " .. skillName)
            end
        end
    end

    return validSkills
end

function BurdJournals.Server.validateTraitPayload(traits, player, useBaselineOverride, journalData)
    if traits == nil then return nil end

    -- Check if trait recording is enabled for player journals
    if BurdJournals.getSandboxOption("EnableTraitRecordingPlayer") == false then
        BurdJournals.debugPrint("[BurdJournals] Trait recording disabled for player journals")
        return nil
    end

    if type(traits) ~= "table" then
        bsjWriteLogLine("[BurdJournals] WARNING: Invalid traits payload (not a table) from " .. tostring(player and player:getUsername() or "unknown"))
        return nil
    end

    local bsjTraitValidateStartMs = getTimestampMs and getTimestampMs() or nil
    local validTraits = {}
    local rejectedTraits = {}
    local incomingTraitCount = 0

    -- Check if baseline restriction is enabled
    local useBaseline
    if type(useBaselineOverride) == "boolean" then
        useBaseline = useBaselineOverride
    else
        useBaseline = BurdJournals.shouldUseBaselineForPlayerJournalRecording and BurdJournals.shouldUseBaselineForPlayerJournalRecording(player) or false
    end

    local playerJournalContext = { isPlayerCreated = true }
    local traitBaseline = useBaseline and BurdJournals.getTraitBaseline and BurdJournals.getTraitBaseline(player) or nil
    local traitExportBaseline = useBaseline and BurdJournals.getTraitExportBaseline and BurdJournals.getTraitExportBaseline(player) or nil
    local traitBaselineLookup = type(traitBaseline) == "table"
        and BurdJournals.buildTraitLookup
        and BurdJournals.buildTraitLookup(traitBaseline)
        or nil
    local journalTraitLookup = type(journalData) == "table"
        and BurdJournals.buildTraitLookup
        and BurdJournals.buildTraitLookup(journalData.traits or {})
        or nil

    local playerTraitLookup = {}
    local playerTraitLookupBuilt = false
    local function addTraitLookupValue(value)
        if value == nil then return end
        local normalized = BurdJournals.normalizeTraitId and BurdJournals.normalizeTraitId(value) or tostring(value)
        if not normalized or normalized == "" then return end
        playerTraitLookup[normalized] = true
        playerTraitLookup[string.lower(tostring(normalized))] = true
        if BurdJournals.getTraitAliases then
            for _, alias in ipairs(BurdJournals.getTraitAliases(normalized)) do
                if alias then
                    local aliasNorm = BurdJournals.normalizeTraitId and BurdJournals.normalizeTraitId(alias) or tostring(alias)
                    if aliasNorm and aliasNorm ~= "" then
                        playerTraitLookup[aliasNorm] = true
                        playerTraitLookup[string.lower(tostring(aliasNorm))] = true
                    end
                end
            end
        end
    end

    local runtimeTraits = nil
    local runtimeTraitShape = "none"
    if player and player.getTraits then
        local okTraits, traitsObj = BurdJournals.safePcall(function()
            return player:getTraits()
        end)
        runtimeTraits = okTraits and traitsObj or nil
        if runtimeTraits and runtimeTraits.size and runtimeTraits.get then
            runtimeTraitShape = "size_get"
            playerTraitLookupBuilt = true
            for i = 0, runtimeTraits:size() - 1 do
                addTraitLookupValue(runtimeTraits:get(i))
            end
        elseif runtimeTraits and runtimeTraits.contains then
            runtimeTraitShape = "contains"
            playerTraitLookupBuilt = true
        elseif runtimeTraits then
            runtimeTraitShape = "opaque"
        end
    end

    local submittedTraitDefinitionLookup = {}
    local function addTraitVerificationCandidate(list, seen, value)
        if value == nil then return end
        local key = tostring(value)
        if key == "" or seen[key] then return end
        seen[key] = true
        list[#list + 1] = value
    end
    local function addCharacterTraitLookupCandidate(list, seen, traitName)
        if not traitName or traitName == "" then return end
        if CharacterTrait and CharacterTrait.get and ResourceLocation and ResourceLocation.of then
            local lookupNames = { tostring(traitName) }
            local normalizedName = BurdJournals.normalizeTraitId and BurdJournals.normalizeTraitId(traitName) or tostring(traitName)
            if normalizedName and normalizedName ~= "" then
                lookupNames[#lookupNames + 1] = normalizedName
                lookupNames[#lookupNames + 1] = string.lower(tostring(normalizedName))
                if not string.find(tostring(normalizedName), ":") then
                    lookupNames[#lookupNames + 1] = "base:" .. tostring(normalizedName)
                    lookupNames[#lookupNames + 1] = "base:" .. string.lower(tostring(normalizedName))
                end
            end
            for _, lookupName in ipairs(lookupNames) do
                local okTrait, traitObj = BurdJournals.safePcall(function()
                    return CharacterTrait.get(ResourceLocation.of(lookupName))
                end)
                if okTrait and traitObj then
                    addTraitVerificationCandidate(list, seen, traitObj)
                end
            end
        end
    end
    local function addSubmittedTraitDefinition(traitId, traitObj, defName)
        if not traitId or not traitObj then return end
        local candidates = { __bsjTraitCandidates = true }
        local seen = {}
        addTraitVerificationCandidate(candidates, seen, traitObj)
        if traitObj and traitObj.getName then
            local okName, runtimeName = BurdJournals.safePcall(function()
                return traitObj:getName()
            end)
            if okName and runtimeName then
                addCharacterTraitLookupCandidate(candidates, seen, tostring(runtimeName))
            end
        end
        addCharacterTraitLookupCandidate(candidates, seen, defName)
        if defName then
            local normalizedName = BurdJournals.normalizeTraitId and BurdJournals.normalizeTraitId(defName) or tostring(defName)
            addCharacterTraitLookupCandidate(candidates, seen, normalizedName)
        end
        local normalized = BurdJournals.normalizeTraitId and BurdJournals.normalizeTraitId(traitId) or tostring(traitId)
        if normalized and normalized ~= "" then
            submittedTraitDefinitionLookup[normalized] = candidates
            submittedTraitDefinitionLookup[string.lower(tostring(normalized))] = candidates
        end
        if BurdJournals.getTraitAliases then
            for _, alias in ipairs(BurdJournals.getTraitAliases(normalized or traitId)) do
                local aliasNorm = BurdJournals.normalizeTraitId and BurdJournals.normalizeTraitId(alias) or tostring(alias)
                if aliasNorm and aliasNorm ~= "" then
                    submittedTraitDefinitionLookup[aliasNorm] = candidates
                    submittedTraitDefinitionLookup[string.lower(tostring(aliasNorm))] = candidates
                end
            end
        end
    end

    -- Resolve only submitted trait IDs once. This keeps server validation
    -- authoritative without repeatedly scanning the full trait registry.
    if CharacterTraitDefinition and CharacterTraitDefinition.getTraits then
        local allTraits = CharacterTraitDefinition.getTraits()
        if allTraits and allTraits.size and allTraits.get then
            local wanted = {}
            for traitId, _ in pairs(traits) do
                if type(traitId) == "string" then
                    local normalized = BurdJournals.normalizeTraitId and BurdJournals.normalizeTraitId(traitId) or tostring(traitId)
                    wanted[string.lower(tostring(normalized))] = true
                    if BurdJournals.getTraitAliases then
                        for _, alias in ipairs(BurdJournals.getTraitAliases(normalized)) do
                            local aliasNorm = BurdJournals.normalizeTraitId and BurdJournals.normalizeTraitId(alias) or tostring(alias)
                            wanted[string.lower(tostring(aliasNorm))] = true
                        end
                    end
                end
            end

            for i = 0, allTraits:size() - 1 do
                local def = allTraits:get(i)
                local defType = def and def.getType and def:getType() or nil
                local defLabel = def and def.getLabel and def:getLabel() or nil
                local defName = nil
                if defType then
                    if defType.getName then
                        defName = defType:getName()
                    else
                        defName = tostring(defType)
                    end
                end
                local candidates = { defLabel, defName }
                local matched = false
                for _, candidate in ipairs(candidates) do
                    local candidateNorm = BurdJournals.normalizeTraitId and BurdJournals.normalizeTraitId(candidate) or tostring(candidate or "")
                    if candidateNorm and wanted[string.lower(tostring(candidateNorm))] then
                        matched = true
                        break
                    end
                end
                if matched then
                    for traitId, _ in pairs(traits) do
                        if type(traitId) == "string" then
                            local traitNorm = BurdJournals.normalizeTraitId and BurdJournals.normalizeTraitId(traitId) or tostring(traitId)
                            local traitLower = string.lower(tostring(traitNorm))
                            local defLabelNorm = BurdJournals.normalizeTraitId and BurdJournals.normalizeTraitId(defLabel) or tostring(defLabel or "")
                            local defNameNorm = BurdJournals.normalizeTraitId and BurdJournals.normalizeTraitId(defName) or tostring(defName or "")
                            if traitLower == string.lower(tostring(defLabelNorm))
                                or traitLower == string.lower(tostring(defNameNorm))
                                or (BurdJournals.traitIdsMatch and (BurdJournals.traitIdsMatch(traitId, defLabel) or BurdJournals.traitIdsMatch(traitId, defName))) then
                                addSubmittedTraitDefinition(traitId, defType, defName)
                            end
                        end
                    end
                end
            end
        end
    end

    local function traitContainsFast(traitId)
        if not (runtimeTraits and runtimeTraits.contains) then
            return false
        end
        local candidates = { traitId }
        if BurdJournals.getTraitAliases then
            for _, alias in ipairs(BurdJournals.getTraitAliases(traitId)) do
                candidates[#candidates + 1] = alias
            end
        end
        for _, candidate in ipairs(candidates) do
            if candidate then
                local normalized = BurdJournals.normalizeTraitId and BurdJournals.normalizeTraitId(candidate) or tostring(candidate)
                local okContains, contains = BurdJournals.safePcall(function()
                    return runtimeTraits:contains(normalized)
                end)
                if okContains and contains == true then
                    return true
                end
                if normalized ~= candidate then
                    okContains, contains = BurdJournals.safePcall(function()
                        return runtimeTraits:contains(candidate)
                    end)
                    if okContains and contains == true then
                        return true
                    end
                end
            end
        end
        return false
    end

    local function hasPlayerTraitFast(traitId)
        if playerTraitLookupBuilt and BurdJournals.isTraitInLookup and BurdJournals.hasAnyEntries and BurdJournals.hasAnyEntries(playerTraitLookup) then
            return BurdJournals.isTraitInLookup(playerTraitLookup, traitId) == true
        end
        if traitContainsFast(traitId) then
            return true
        end
        if player and player.HasTrait then
            local candidates = { traitId }
            if BurdJournals.getTraitAliases then
                for _, alias in ipairs(BurdJournals.getTraitAliases(traitId)) do
                    candidates[#candidates + 1] = alias
                end
            end
            for _, candidate in ipairs(candidates) do
                local okHas, hasTrait = BurdJournals.safePcall(function()
                    return player:HasTrait(candidate)
                end)
                if okHas and hasTrait == true then
                    return true
                end
            end
        end
        if player and player.hasTrait then
            local normalized = BurdJournals.normalizeTraitId and BurdJournals.normalizeTraitId(traitId) or tostring(traitId)
            local traitObjects = submittedTraitDefinitionLookup[normalized] or submittedTraitDefinitionLookup[string.lower(tostring(normalized))]
            if traitObjects then
                if type(traitObjects) == "table" and traitObjects.__bsjTraitCandidates == true then
                    for _, traitObj in ipairs(traitObjects) do
                        local okHas, hasTrait = BurdJournals.safePcall(function()
                            return player:hasTrait(traitObj)
                        end)
                        if okHas and hasTrait == true then
                            return true
                        end
                    end
                else
                    local okHas, hasTrait = BurdJournals.safePcall(function()
                        return player:hasTrait(traitObjects)
                    end)
                    if okHas and hasTrait == true then
                        return true
                    end
                end
            end
        end
        if BurdJournals.playerHasTrait then
            local okShared, hasShared = BurdJournals.safePcall(function()
                return BurdJournals.playerHasTrait(player, traitId)
            end)
            if okShared and hasShared == true then
                return true
            end
        end
        return false
    end

    local function isBaselineTraitFast(traitId)
        if not useBaseline then
            return false
        end
        if BurdJournals.isPassiveSkillTrait and BurdJournals.isPassiveSkillTrait(traitId) then
            return false
        end
        if traitBaselineLookup and BurdJournals.isTraitInLookup then
            return BurdJournals.isTraitInLookup(traitBaselineLookup, traitId) == true
        end
        return BurdJournals.isStartingTrait and BurdJournals.isStartingTrait(player, traitId) == true
    end

    for traitId, _ in pairs(traits) do
        incomingTraitCount = incomingTraitCount + 1

        if type(traitId) ~= "string" then
            bsjWriteLogLine("[BurdJournals] WARNING: Invalid trait ID type: " .. type(traitId))

        elseif string.len(traitId) > 100 then
            bsjWriteLogLine("[BurdJournals] WARNING: Trait ID too long: " .. string.sub(traitId, 1, 50) .. "...")
        else
            if BurdJournals.isTraitEnabledForJournal and not BurdJournals.isTraitEnabledForJournal(playerJournalContext, traitId) then
                BurdJournals.debugPrint("[BurdJournals] validateTraitPayload: Rejected trait " .. traitId .. " - blocked by compatibility settings")
                rejectedTraits[#rejectedTraits + 1] = tostring(traitId) .. ":blocked"
            -- SERVER-SIDE VALIDATION: Verify player actually has this trait
            elseif hasPlayerTraitFast(traitId) then
                -- Check if trait was in baseline (shouldn't record starting traits if enabled)
                local isBaselineTrait = isBaselineTraitFast(traitId)
                -- Trait export markers are historical/audit state. The active
                -- journal contents and starting baseline are the authoritative
                -- duplicate guards for a record operation.
                local isExportedTrait = false
                local journalAlreadyHasTrait = journalTraitLookup
                    and BurdJournals.isTraitInLookup
                    and BurdJournals.isTraitInLookup(journalTraitLookup, traitId)
                if not isBaselineTrait and not isExportedTrait and not journalAlreadyHasTrait then
                    validTraits[traitId] = true
                else
                    local reason = isBaselineTrait and "baseline" or (isExportedTrait and "exported" or "already_recorded")
                    rejectedTraits[#rejectedTraits + 1] = tostring(traitId) .. ":" .. reason
                end
            else
                BurdJournals.debugPrint("[BurdJournals] Rejected trait " .. traitId .. " - player doesn't have it")
                rejectedTraits[#rejectedTraits + 1] = tostring(traitId) .. ":missing"
            end
        end
    end

    local validTraitCount = BurdJournals.countTable and BurdJournals.countTable(validTraits) or 0
    if incomingTraitCount > validTraitCount and #rejectedTraits > 0 then
        local sample = {}
        for i = 1, math.min(#rejectedTraits, 8) do
            sample[#sample + 1] = rejectedTraits[i]
        end
        bsjWriteLogLine("[BurdJournals] validateTraitPayload mismatch for "
            .. tostring(player and player:getUsername() or "unknown")
            .. ": incoming=" .. tostring(incomingTraitCount)
            .. ", accepted=" .. tostring(validTraitCount)
            .. ", rejectedSample=" .. table.concat(sample, ", "))
    end

    local bsjTraitValidateEndMs = getTimestampMs and getTimestampMs() or nil
    if bsjTraitValidateStartMs and bsjTraitValidateEndMs and bsjWriteLogLine then
        bsjWriteLogLine("[BurdJournals][TraitValidatePerf] player=" .. tostring(player and player:getUsername() or "unknown")
            .. " incoming=" .. tostring(incomingTraitCount)
            .. " accepted=" .. tostring(validTraitCount)
            .. " rejected=" .. tostring(math.max(0, incomingTraitCount - validTraitCount))
            .. " baseline=" .. tostring(useBaseline == true)
            .. " hasBaseline=" .. tostring(traitExportBaseline ~= nil)
            .. " hasJournalLookup=" .. tostring(journalTraitLookup ~= nil)
            .. " playerLookup=" .. tostring(playerTraitLookupBuilt == true)
            .. " traitShape=" .. tostring(runtimeTraitShape)
            .. " traitDefs=" .. tostring(BurdJournals.countTable and BurdJournals.countTable(submittedTraitDefinitionLookup) or 0)
            .. " ms=" .. tostring(math.max(0, bsjTraitValidateEndMs - bsjTraitValidateStartMs)))
    end

    return validTraits
end
function BurdJournals.Server.validateStatsPayload(stats, player)
    if stats == nil then return nil end
    if type(stats) ~= "table" then
        bsjWriteLogLine("[BurdJournals] WARNING: Invalid stats payload (not a table) from " .. tostring(player and player:getUsername() or "unknown"))
        return nil
    end

    local validStats = {}

    for statId, statData in pairs(stats) do

        if type(statId) ~= "string" then
            bsjWriteLogLine("[BurdJournals] WARNING: Invalid stat ID type: " .. type(statId))

        elseif string.len(statId) > 100 then
            bsjWriteLogLine("[BurdJournals] WARNING: Stat ID too long: " .. string.sub(statId, 1, 50) .. "...")

        elseif type(statData) ~= "table" then
            bsjWriteLogLine("[BurdJournals] WARNING: Invalid stat data type for " .. statId .. ": " .. type(statData))
        else

            -- Server-authoritative stat value (do not trust client)
            local value = nil
            if BurdJournals.getStatValue then
                value = BurdJournals.getStatValue(player, statId)
            end
            if value == nil then
                value = statData.value
                if type(value) ~= "number" and type(value) ~= "string" then
                    value = tostring(value)
                end
            end
            validStats[statId] = { value = value }
        end
    end

    return validStats
end

function BurdJournals.Server.validateRecipePayload(recipes, player, useBaselineOverride, journalData)
    if recipes == nil then return nil end

    -- Check if recipe recording is enabled for player journals
    if BurdJournals.getSandboxOption("EnableRecipeRecordingPlayer") == false then
        BurdJournals.debugPrint("[BurdJournals] Recipe recording disabled for player journals")
        return nil
    end

    if type(recipes) ~= "table" then
        bsjWriteLogLine("[BurdJournals] WARNING: Invalid recipes payload (not a table) from " .. tostring(player and player:getUsername() or "unknown"))
        return nil
    end

    local validRecipes = {}
    local rejectedRecipes = {}
    local incomingRecipeCount = 0

    -- Check if baseline restriction is enabled
    local useBaseline
    if type(useBaselineOverride) == "boolean" then
        useBaseline = useBaselineOverride
    else
        useBaseline = BurdJournals.shouldUseBaselineForPlayerJournalRecording and BurdJournals.shouldUseBaselineForPlayerJournalRecording(player) or false
    end

    local function isClientReportedTransferableRecipe(recipeName, recipeData)
        if type(recipeName) ~= "string" or recipeName == "" or type(recipeData) ~= "table" then
            return false
        end

        local source = type(recipeData.source) == "string" and recipeData.source or nil
        local expectedSource = BurdJournals.getMagazineForRecipe and BurdJournals.getMagazineForRecipe(recipeName) or nil
        if source and expectedSource and source == expectedSource then
            return true
        end

        local recipeScript = BurdJournals.getRecipeScript and BurdJournals.getRecipeScript(recipeName) or nil
        if recipeScript and recipeScript.needToBeLearn and recipeScript:needToBeLearn() then
            return true
        end

        return false
    end

    for recipeName, recipeData in pairs(recipes) do
        incomingRecipeCount = incomingRecipeCount + 1

        if type(recipeName) ~= "string" then
            bsjWriteLogLine("[BurdJournals] WARNING: Invalid recipe name type: " .. type(recipeName))

        elseif string.len(recipeName) > 200 then
            bsjWriteLogLine("[BurdJournals] WARNING: Recipe name too long: " .. string.sub(recipeName, 1, 50) .. "...")
        else
            local canonicalRecipeName = BurdJournals.getRecipeCanonicalName and BurdJournals.getRecipeCanonicalName(recipeName) or recipeName
            -- SERVER-SIDE VALIDATION: Verify player actually knows a transferable recipe
            local serverKnowsRecipe = BurdJournals.isTransferableRecipeKnown(player, canonicalRecipeName, false)
            local clientReportedTransferable = false
            if not serverKnowsRecipe then
                clientReportedTransferable = isClientReportedTransferableRecipe(canonicalRecipeName, recipeData)
            end
            if serverKnowsRecipe or clientReportedTransferable then
                -- Check if recipe was in baseline (shouldn't record starting recipes if enabled)
                local isBaselineRecipe = useBaseline and BurdJournals.isStartingRecipe(player, canonicalRecipeName)
                local recipeExportBaseline = useBaseline and BurdJournals.getRecipeExportBaseline and BurdJournals.getRecipeExportBaseline(player) or nil
                -- Recipe export markers are historical/audit state. They must not block
                -- recording into the active journal, especially across multi-batch record-all
                -- flows where a previous attempt may have exported the recipe before the
                -- current journal reflected it.
                local isExportedRecipe = false
                local journalAlreadyHasRecipe = type(journalData) == "table"
                    and type(journalData.recipes) == "table"
                    and BurdJournals.resolveRecipeKey
                    and BurdJournals.resolveRecipeKey(journalData.recipes, canonicalRecipeName) ~= nil
                if not isBaselineRecipe and not isExportedRecipe and not journalAlreadyHasRecipe then
                    validRecipes[canonicalRecipeName] = true
                else
                    local reason = isBaselineRecipe and "baseline" or (isExportedRecipe and "exported" or "already_recorded")
                    rejectedRecipes[#rejectedRecipes + 1] = tostring(recipeName) .. ":" .. reason
                end
            else
                BurdJournals.debugPrint("[BurdJournals] Rejected recipe " .. recipeName .. " - player doesn't know a transferable version of it")
                rejectedRecipes[#rejectedRecipes + 1] = tostring(recipeName) .. ":unknown"
            end
        end
    end

    local validRecipeCount = BurdJournals.countTable and BurdJournals.countTable(validRecipes) or 0
    if incomingRecipeCount > validRecipeCount and #rejectedRecipes > 0 then
        local sample = {}
        for i = 1, math.min(#rejectedRecipes, 8) do
            sample[#sample + 1] = rejectedRecipes[i]
        end
        bsjWriteLogLine("[BurdJournals] validateRecipePayload mismatch for "
            .. tostring(player and player:getUsername() or "unknown")
            .. ": incoming=" .. tostring(incomingRecipeCount)
            .. ", accepted=" .. tostring(validRecipeCount)
            .. ", rejectedSample=" .. table.concat(sample, ", "))
    end

    return validRecipes
end

function BurdJournals.Server.hasActiveBatchRewardJobs()
    local queue = BurdJournals.Server.BatchRewardQueue
    if not queue or type(queue.jobs) ~= "table" then
        return false
    end
    if queue.activeCount ~= nil then
        return (tonumber(queue.activeCount) or 0) > 0
    end
    for _, job in ipairs(queue.jobs) do
        if not job.completed then
            return true
        end
    end
    return false
end

function BurdJournals.Server.shouldDeferBatchTransmit(context)
    -- Batch deferral is carried explicitly by the handler request instead of a
    -- server-global execution flag. An exception therefore cannot strand all
    -- unrelated persistence in a deferred state.
    return type(context) == "table" and context._deferBatchTransmit == true
end

BurdJournals.Server.BATCH_INTERMEDIATE_RESPONSE_COMMANDS = {
    error = true,
    learnSuccess = true,
    claimSuccess = true,
    absorbSuccess = true,
    skillMaxed = true,
    traitAlreadyKnown = true,
    recipeAlreadyKnown = true,
    forgetSlotClaimed = true,
    journalDissolved = true,
}

BurdJournals.Server._batchResponseScopes = BurdJournals.Server._batchResponseScopes or {}

function BurdJournals.Server.invokeBatchRewardHandler(job, handler, ...)
    local callArgs = {...}
    local requestContext = type(callArgs[2]) == "table" and callArgs[2] or nil
    if requestContext then requestContext._deferBatchTransmit = true end
    local player = callArgs[1]
    local playerKey = BurdJournals.Server.getBatchRewardPlayerKey
        and BurdJournals.Server.getBatchRewardPlayerKey(player)
        or tostring(player)
    local token = {}
    BurdJournals.Server._batchResponseScopes[playerKey] = {
        token = token,
        expiresAt = ((getTimestampMs and getTimestampMs()) or ((os.time() or 0) * 1000)) + 1500,
    }
    local unpackArgs = table.unpack or unpack
    local resultA, resultB, resultC, resultD = handler(unpackArgs(callArgs))
    local activeScope = BurdJournals.Server._batchResponseScopes[playerKey]
    if activeScope and activeScope.token == token then
        BurdJournals.Server._batchResponseScopes[playerKey] = nil
    end
    return resultA, resultB, resultC, resultD
end

function BurdJournals.Server.sendToClient(player, command, args)
    local playerKey = BurdJournals.Server.getBatchRewardPlayerKey
        and BurdJournals.Server.getBatchRewardPlayerKey(player)
        or tostring(player)
    local scope = BurdJournals.Server._batchResponseScopes[playerKey]
    if scope then
        local nowMs = (getTimestampMs and getTimestampMs()) or ((os.time() or 0) * 1000)
        if nowMs >= (tonumber(scope.expiresAt) or 0) then
            BurdJournals.Server._batchResponseScopes[playerKey] = nil
            scope = nil
        end
    end
    if scope and BurdJournals.Server.BATCH_INTERMEDIATE_RESPONSE_COMMANDS[command] == true then return end
    -- Validate player before sending command (prevents crashes with mods that wrap sendServerCommand)
    if not player then
        bsjWriteLogLine("[BurdJournals] WARNING: sendToClient called with nil player for command: " .. tostring(command))
        return
    end

    -- Check if player is fully initialized (Username can be null during connection)
    if player.getUsername and player:getUsername() == nil then
        bsjWriteLogLine("[BurdJournals] WARNING: sendToClient called with uninitialized player for command: " .. tostring(command))
        return
    end

    if not sendServerCommand then
        bsjWriteLogLine("[BurdJournals] ERROR: sendServerCommand is not available for command '" .. tostring(command) .. "'")
        return
    end

    args = type(args) == "table" and args or {}
    -- OnServerCommand does not provide a player argument. Include stable target
    -- identity so local co-op clients route the response to the character whose
    -- command the server handled instead of blindly using player zero.
    if args.responseTargetUsername == nil and player.getUsername then
        args.responseTargetUsername = player:getUsername()
    end
    if args.responseTargetOnlineId == nil and player.getOnlineID then
        args.responseTargetOnlineId = player:getOnlineID()
    end
    if args.responseTargetCharacterId == nil and BurdJournals.getPlayerCharacterId then
        args.responseTargetCharacterId = BurdJournals.getPlayerCharacterId(player)
    end

    -- Legacy extensions may still omit a code. Keep their failure deterministic,
    -- but never infer gameplay semantics from mutable English prose.
    if command == "error" and type(args) == "table" and not args.errorCode then
        args.errorCode = "requestRejected"
        bsjWriteLogLine("[BurdJournals] WARNING: legacy error response omitted errorCode")
    end

    -- Data-shape hardening: claim/absorb responses carry ~10 debug_* diagnostic
    -- fields per event. On mod-heavy servers these add up across every claim. Only
    -- ship them when verbose logging is enabled; strip otherwise (no gameplay use).
    if type(args) == "table"
        and not (BurdJournals.shouldDebugLog and BurdJournals.shouldDebugLog()) then
        for key in pairs(args) do
            if type(key) == "string" and key:sub(1, 6) == "debug_" then
                args[key] = nil
            end
        end
    end

    sendServerCommand(player, "BurdJournals", command, args)

    local localPlayer = getPlayer and getPlayer()
    local isTrueSinglePlayer = localPlayer ~= nil and not isClient()

    if isTrueSinglePlayer then
        local ticksToWait = 1
        local ticksWaited = 0
        local invokeClient
        invokeClient = function()
            ticksWaited = ticksWaited + 1
            if ticksWaited >= ticksToWait then
                Events.OnTick.Remove(invokeClient)
                if BurdJournals.Client and BurdJournals.Client.onServerCommand then
                    BurdJournals.Client.onServerCommand("BurdJournals", command, args)
                end
            end
        end
        Events.OnTick.Add(invokeClient)
    end
end

function BurdJournals.Server.getAdminPolicyStore()
    local key = BurdJournals.ADMIN_POLICY_MODDATA_KEY or "BurdJournals_AdminPolicyV1"
    local store = nil
    if ModData and ModData.getOrCreate then
        store = ModData.getOrCreate(key)
    end
    if type(store) ~= "table" then
        store = BurdJournals.AdminPolicy or {}
    end
    store.skills = type(store.skills) == "table" and store.skills or {}
    store.traits = type(store.traits) == "table" and store.traits or {}
    store.recipes = type(store.recipes) == "table" and store.recipes or {}
    if BurdJournals.setAdminPolicy then
        BurdJournals.setAdminPolicy(store)
    end
    return store
end

function BurdJournals.Server.transmitAdminPolicyStore()
    local key = BurdJournals.ADMIN_POLICY_MODDATA_KEY or "BurdJournals_AdminPolicyV1"
    if ModData and ModData.transmit then
        ModData.transmit(key)
    end
end

function BurdJournals.Server.normalizeAdminPolicyMutation(args)
    args = type(args) == "table" and args or {}
    local kind = BurdJournals.normalizeAdminPolicyKind and BurdJournals.normalizeAdminPolicyKind(args.kind) or nil
    local scope = BurdJournals.normalizeAdminPolicyScope and BurdJournals.normalizeAdminPolicyScope(args.scope) or nil
    local id = args.id and tostring(args.id) or nil
    local policy = BurdJournals.normalizeAdminPolicyValue and BurdJournals.normalizeAdminPolicyValue(args.policy) or nil
    if not (kind and scope and id and id ~= "") then
        return nil
    end
    local rawPolicy = tostring(args.policy or "inherit")
    if rawPolicy ~= "inherit" and rawPolicy ~= "allow" and rawPolicy ~= "ban" and rawPolicy ~= "" then
        return nil
    end
    return kind, id, scope, policy
end

function BurdJournals.Server.applyAdminPolicyMutation(store, kind, id, scope, policy)
    if not (store and kind and id and scope) then return false end
    store[kind] = type(store[kind]) == "table" and store[kind] or {}
    local bucket = store[kind]
    bucket[id] = type(bucket[id]) == "table" and bucket[id] or {}
    bucket[id][scope] = policy
    if bucket[id].player == nil and bucket[id].loot == nil then
        bucket[id] = nil
    end
    return true
end

function BurdJournals.Server.sendAdminPolicyToClient(player, message)
    local store = BurdJournals.Server.getAdminPolicyStore()
    BurdJournals.Server.sendToClient(player, "debugAdminPolicy", {
        policy = BurdJournals.Server.deepCopy(store),
        message = message,
    })
end

function BurdJournals.Server.handleDebugRequestAdminPolicy(player, _args)
    if not BurdJournals.Server.isDebugAllowed(player) then
        BurdJournals.Server.sendToClient(player, "debugError", {message = "Debug commands not allowed"})
        return
    end
    BurdJournals.Server.sendAdminPolicyToClient(player)
end

function BurdJournals.Server.handleDebugSetAdminPolicy(player, args)
    if not BurdJournals.Server.isDebugAllowed(player) then
        BurdJournals.Server.sendToClient(player, "debugError", {message = "Debug commands not allowed"})
        return
    end
    local kind, id, scope, policy = BurdJournals.Server.normalizeAdminPolicyMutation(args)
    if not kind then
        BurdJournals.Server.sendToClient(player, "debugError", {message = "Invalid whitelist policy request"})
        return
    end
    local store = BurdJournals.Server.getAdminPolicyStore()
    BurdJournals.Server.applyAdminPolicyMutation(store, kind, id, scope, policy)
    BurdJournals.Server.transmitAdminPolicyStore()
    BurdJournals.Server.sendAdminPolicyToClient(player, BurdJournals.safeGetText and BurdJournals.safeGetText("UI_BurdJournals_DebugWhitelistPolicyUpdated", "Whitelist policy updated.") or "Whitelist policy updated.")
end

function BurdJournals.Server.handleDebugBulkSetAdminPolicy(player, args)
    if not BurdJournals.Server.isDebugAllowed(player) then
        BurdJournals.Server.sendToClient(player, "debugError", {message = "Debug commands not allowed"})
        return
    end
    args = type(args) == "table" and args or {}
    local kind = BurdJournals.normalizeAdminPolicyKind and BurdJournals.normalizeAdminPolicyKind(args.kind) or nil
    local scope = BurdJournals.normalizeAdminPolicyScope and BurdJournals.normalizeAdminPolicyScope(args.scope) or nil
    local policy = BurdJournals.normalizeAdminPolicyValue and BurdJournals.normalizeAdminPolicyValue(args.policy) or nil
    local rawPolicy = tostring(args.policy or "inherit")
    if not (kind and scope and type(args.ids) == "table") or (rawPolicy ~= "inherit" and rawPolicy ~= "allow" and rawPolicy ~= "ban" and rawPolicy ~= "") then
        BurdJournals.Server.sendToClient(player, "debugError", {message = "Invalid whitelist bulk request"})
        return
    end
    local store = BurdJournals.Server.getAdminPolicyStore()
    local count = 0
    for _, rawId in ipairs(args.ids) do
        local id = rawId and tostring(rawId) or nil
        if id and id ~= "" then
            if BurdJournals.Server.applyAdminPolicyMutation(store, kind, id, scope, policy) then
                count = count + 1
            end
        end
    end
    BurdJournals.Server.transmitAdminPolicyStore()
    BurdJournals.Server.sendAdminPolicyToClient(player, BurdJournals.formatText(BurdJournals.safeGetText and BurdJournals.safeGetText("UI_BurdJournals_DebugWhitelistPolicyUpdatedCount", "Whitelist policy updated: %1 entrie(s).") or "Whitelist policy updated: %1 entrie(s).", count))
end

function BurdJournals.Server.handleDebugResetAdminPolicy(player, _args)
    if not BurdJournals.Server.isDebugAllowed(player) then
        BurdJournals.Server.sendToClient(player, "debugError", {message = "Debug commands not allowed"})
        return
    end
    local store = BurdJournals.Server.getAdminPolicyStore()
    store.skills = {}
    store.traits = {}
    store.recipes = {}
    if BurdJournals.setAdminPolicy then
        BurdJournals.setAdminPolicy(store)
    end
    BurdJournals.Server.transmitAdminPolicyStore()
    BurdJournals.Server.sendAdminPolicyToClient(player, BurdJournals.safeGetText and BurdJournals.safeGetText("UI_BurdJournals_DebugWhitelistPolicyReset", "Whitelist policy reset.") or "Whitelist policy reset.")
end


function BurdJournals.Server.init()
    -- Server started - verify baseline cache is properly loaded
    BurdJournals.debugPrint("[BurdJournals] Server.init() called - checking baseline cache...")
    
    -- Reset the logged flag so we report cache state on next access
    BurdJournals.Server._baselineCacheLogged = false

    -- Fallback for environments where OnInitGlobalModData may not fire reliably.
    -- IMPORTANT: Don't force-create global keys here or we may mask persisted keys
    -- during startup ordering races (observed during workshop update restarts).
    if not BurdJournals.Server._modDataInitialized and BurdJournals.Server.ensureBaselineModDataReady then
        local ready = BurdJournals.Server.ensureBaselineModDataReady(false)
        BurdJournals.debugPrint("[BurdJournals] Server.init: baseline ModData ready before init event = " .. tostring(ready))
    end
    
    -- Trigger a cache access to log current state
    local cache = BurdJournals.Server.getBaselineCache()
    local archive = BurdJournals.Server.getBaselineArchive and BurdJournals.Server.getBaselineArchive() or nil
    if BurdJournals.Server.backfillBaselineArchiveFromCache then
        BurdJournals.Server.backfillBaselineArchiveFromCache("server_init")
        archive = BurdJournals.Server.getBaselineArchive and BurdJournals.Server.getBaselineArchive() or archive
    end
    if BurdJournals.Server.seedBaselineSnapshotsFromExistingStores then
        BurdJournals.Server.seedBaselineSnapshotsFromExistingStores("server_init")
    end
    local playerCount = 0
    for _ in pairs(cache.players or {}) do playerCount = playerCount + 1 end
    local archivedCount = 0
    if archive and archive.byCharacterId then
        for _ in pairs(archive.byCharacterId) do archivedCount = archivedCount + 1 end
    end
    local snapshotCount = 0
    local snapshots = BurdJournals.Server.getBaselineSnapshotStore and BurdJournals.Server.getBaselineSnapshotStore() or nil
    if snapshots and snapshots.bySnapshotId then
        for _ in pairs(snapshots.bySnapshotId) do snapshotCount = snapshotCount + 1 end
    end
    local mirrorCount = 0
    local mirrorField = BurdJournals.Server.BASELINE_SNAPSHOT_ARCHIVE_MIRROR_FIELD or "baselineSnapshotsMirrorV1"
    local legacyMirrorField = BurdJournals.Server.BASELINE_SNAPSHOT_ARCHIVE_MIRROR_FIELD_LEGACY or "_baselineSnapshotsMirrorV1"
    local mirror = archive and (archive[mirrorField] or archive[legacyMirrorField]) or nil
    if type(mirror) == "table" and type(mirror.bySnapshotId) == "table" then
        for _ in pairs(mirror.bySnapshotId) do
            mirrorCount = mirrorCount + 1
        end
    end
    BurdJournals.debugPrint("[BurdJournals] Server init complete. Baseline cache has " .. playerCount
        .. " player baseline(s), archive has " .. archivedCount .. " entry(ies), snapshots have "
        .. snapshotCount .. " entry(ies), snapshot mirror has " .. mirrorCount .. " entry(ies)")
end

-- Called when global ModData is initialized/loaded from disk
function BurdJournals.Server.onInitGlobalModData(isNewGame)
    BurdJournals.debugPrint("[BurdJournals] OnInitGlobalModData called (isNewGame=" .. tostring(isNewGame) .. ")")
    
    -- CRITICAL: Invalidate cached instance so we re-fetch from ModData
    -- This ensures we get the properly loaded data from disk
    BurdJournals.Server._baselineCacheInstance = nil
    BurdJournals.Server._baselineArchiveInstance = nil
    BurdJournals.Server._baselineSnapshotInstance = nil
    BurdJournals.Server._baselineSnapshotSeeded = false
    
    -- Mark that ModData has been initialized - this is critical for knowing when it's safe to trust cache state
    BurdJournals.Server._modDataInitialized = true
    
    -- Reset flag to ensure we log the loaded cache state
    BurdJournals.Server._baselineCacheLogged = false
    
    -- Access the cache to ensure it's properly loaded and logged
    local cache = BurdJournals.Server.getBaselineCache()
    local archive = BurdJournals.Server.getBaselineArchive and BurdJournals.Server.getBaselineArchive() or nil
    if BurdJournals.Server.backfillBaselineArchiveFromCache then
        BurdJournals.Server.backfillBaselineArchiveFromCache("onInitGlobalModData")
        archive = BurdJournals.Server.getBaselineArchive and BurdJournals.Server.getBaselineArchive() or archive
    end
    if BurdJournals.Server.seedBaselineSnapshotsFromExistingStores then
        BurdJournals.Server.seedBaselineSnapshotsFromExistingStores("onInitGlobalModData")
    end
    local playerCount = 0
    local debugModifiedCount = 0
    for id, data in pairs(cache.players or {}) do 
        playerCount = playerCount + 1
        if data and data.debugModified then
            debugModifiedCount = debugModifiedCount + 1
            BurdJournals.debugPrint("[BurdJournals]   - Player " .. tostring(id) .. " has debug-modified baseline")
        end
    end
    local archivedCount = 0
    if archive and archive.byCharacterId then
        for _ in pairs(archive.byCharacterId) do
            archivedCount = archivedCount + 1
        end
    end
    local snapshotCount = 0
    local snapshots = BurdJournals.Server.getBaselineSnapshotStore and BurdJournals.Server.getBaselineSnapshotStore() or nil
    if snapshots and snapshots.bySnapshotId then
        for _ in pairs(snapshots.bySnapshotId) do
            snapshotCount = snapshotCount + 1
        end
    end
    local mirrorCount = 0
    local mirrorField = BurdJournals.Server.BASELINE_SNAPSHOT_ARCHIVE_MIRROR_FIELD or "baselineSnapshotsMirrorV1"
    local legacyMirrorField = BurdJournals.Server.BASELINE_SNAPSHOT_ARCHIVE_MIRROR_FIELD_LEGACY or "_baselineSnapshotsMirrorV1"
    local mirror = archive and (archive[mirrorField] or archive[legacyMirrorField]) or nil
    if type(mirror) == "table" and type(mirror.bySnapshotId) == "table" then
        for _ in pairs(mirror.bySnapshotId) do
            mirrorCount = mirrorCount + 1
        end
    end
    
    if isNewGame then
        BurdJournals.debugPrint("[BurdJournals] New game detected - baseline cache is fresh")
    else
        BurdJournals.debugPrint("[BurdJournals] Existing game loaded - baseline cache has " .. playerCount
            .. " player(s), " .. debugModifiedCount .. " debug-modified, archive has " .. archivedCount
            .. " entry(ies), snapshots have " .. snapshotCount .. " entry(ies), snapshot mirror has "
            .. mirrorCount .. " entry(ies)")
        
        -- Ensure data persists by triggering a transmit (belt and suspenders approach)
        if (playerCount > 0 or archivedCount > 0) and BurdJournals.Server.transmitBaselineStores then
            BurdJournals.Server.transmitBaselineStores(true)
            BurdJournals.debugPrint("[BurdJournals] Triggered baseline cache + archive transmit to ensure persistence")
        elseif playerCount > 0 and ModData.transmit and BurdJournals.Server.isTrueSinglePlayerContext and BurdJournals.Server.isTrueSinglePlayerContext() then
            ModData.transmit("BurdJournals_PlayerBaselines")
            BurdJournals.debugPrint("[BurdJournals] Triggered ModData.transmit to ensure persistence")
        end
        if snapshotCount > 0 and BurdJournals.Server.transmitBaselineSnapshotStore then
            BurdJournals.Server.transmitBaselineSnapshotStore()
            BurdJournals.debugPrint("[BurdJournals] Triggered baseline snapshot transmit to ensure persistence")
        end
    end
end

PLAYER_JOURNAL_RESTRICTED_COMMANDS = {
    logSkills = true,
    learnSkills = true,
    initializeJournal = true,
    recordProgress = true,
    syncJournalData = true,
    claimSkill = true,
    claimTrait = true,
    claimForgetSlot = true,
    claimRecipe = true,
    claimStat = true,
    absorbSkill = true,
    absorbTrait = true,
    absorbRecipe = true,
    batchClaimRewards = true,
    batchAbsorbRewards = true,
    eraseJournal = true,
    eraseEntry = true,
    renameJournal = true,
    saveJournalNotes = true,
    dissolveJournal = true,
}

local function isPlayerJournalInteractionBlocked(command, player, args)
    if not PLAYER_JOURNAL_RESTRICTED_COMMANDS[command] then
        return false
    end
    if BurdJournals.isPlayerJournalsEnabled and BurdJournals.isPlayerJournalsEnabled() then
        return false
    end

    local journal = resolveServerCommandJournal(player, args, command)
    if not journal then
        return false
    end
    local modData = journal:getModData()
    local journalData = modData and modData.BurdJournals or nil
    return journalData and journalData.isPlayerCreated == true
end

function BurdJournals.Server.onPlayerDeathPrepareRespawnJournal(player)
    -- Deprecated: filled player-journal respawn restoration is intentionally disabled.
    return
end

function BurdJournals.Server.handleRequestRespawnJournalProvision(player, args)
    local spawnBlank = BurdJournals.getSandboxOption("SpawnWithBlankPlayerJournal") == true
    if not spawnBlank then
        return
    end

    if BurdJournals.isPlayerJournalsEnabled and not BurdJournals.isPlayerJournalsEnabled() then
        return
    end

    local playerModData = player and player.getModData and player:getModData() or nil
    if type(playerModData) ~= "table" then
        return
    end
    if type(playerModData.BurdJournals) ~= "table" then
        playerModData.BurdJournals = {}
    end
    local playerJournalState = playerModData.BurdJournals
    if playerJournalState.spawnBlankPlayerJournalProvisioned == true then
        return
    end

    local currentJournal = BurdJournals.Server.findRespawnPlayerJournalCandidate(player)
    local provisionedJournal = currentJournal
    if not provisionedJournal then
        provisionedJournal = BurdJournals.Server.createBlankRespawnPlayerJournal(player)
    end
    if not provisionedJournal then
        -- Do not latch a failure. A later OnCreatePlayer/request may safely retry.
        return
    end

    -- This marker lives on the character's own persisted ModData: reconnecting
    -- the same survivor remains idempotent, while a post-death character gets a
    -- fresh marker even when they reuse the same Steam account and name.
    playerJournalState.spawnBlankPlayerJournalProvisioned = true
    if player.transmitModData then
        player:transmitModData()
    end
end

function BurdJournals.Server.onClientCommand(module, command, player, args)
    -- Ignore other mods before touching BSJ response scopes or cleanup caches.
    if module ~= "BurdJournals" then return end
    if type(command) ~= "string" or not BurdJournals.Server.RECOGNIZED_CLIENT_COMMANDS[command] then
        return
    end
    local responseScopeKey = BurdJournals.Server.getBatchRewardPlayerKey
        and BurdJournals.Server.getBatchRewardPlayerKey(player)
        or tostring(player)
    BurdJournals.Server._batchResponseScopes[responseScopeKey] = nil
    local commandNowMs = (getTimestampMs and getTimestampMs()) or ((os.time() or 0) * 1000)
    if (commandNowMs - (tonumber(BurdJournals.Server._lastTransientCommandCleanupAt) or 0)) >= 60000 then
        BurdJournals.Server._lastTransientCommandCleanupAt = commandNowMs
        BurdJournals.Server.cleanupTransientCommandCaches(commandNowMs)
    end
    if type(args) ~= "table" then
        args = {}
    end

    if BurdJournals.flushPendingRuntimeShardTransmits then
        BurdJournals.flushPendingRuntimeShardTransmits(false)
    end

    BurdJournals.debugPrint("[BurdJournals] Server received command: " .. tostring(command) .. " from player: " .. tostring(player and player.getUsername and player:getUsername() or "unknown"))

    if not player then
        bsjWriteLogLine("[BurdJournals] ERROR: No player in command")
        return
    end

    -- Throttle the per-command compaction preamble to at most once per player per
    -- ~10s. It previously ran on every command, including the rapid-fire per-skill
    -- claim/absorb queue (~120ms apart), doing repeated full table scans each time.
    local preambleKey
    if player.getOnlineID then
        preambleKey = tostring(player:getOnlineID())
    elseif player.getUsername then
        preambleKey = tostring(player:getUsername())
    else
        preambleKey = "unknown"
    end
    BurdJournals.Server._lastPreambleCompactAt = BurdJournals.Server._lastPreambleCompactAt or {}
    local preambleNow = BurdJournals._getRuntimeNowMs and BurdJournals._getRuntimeNowMs() or ((os.time() or 0) * 1000)
    local lastPreambleAt = tonumber(BurdJournals.Server._lastPreambleCompactAt[preambleKey]) or 0
    local shouldRunPreambleCompaction = (preambleNow - lastPreambleAt) >= 10000
    if shouldRunPreambleCompaction then
        BurdJournals.Server._lastPreambleCompactAt[preambleKey] = preambleNow
    end

    local skipBaselineCompaction = command == "requestBaseline" or command == "registerBaseline"
    if shouldRunPreambleCompaction and BurdJournals.compactPlayerBurdJournalsData and not skipBaselineCompaction then
        local changed, removedLegacy, removedTransient, removedSkills, removedTraits, removedRecipes =
            BurdJournals.compactPlayerBurdJournalsData(player, true)
        if changed then
            BurdJournals.debugPrint("[BurdJournals] Server compacted player BurdJournals data for "
                .. tostring(player:getUsername())
                .. ": legacy=" .. tostring(removedLegacy)
                .. ", transient=" .. tostring(removedTransient)
                .. ", skills=" .. tostring(removedSkills)
                .. ", traits=" .. tostring(removedTraits)
                .. ", recipes=" .. tostring(removedRecipes))
        end
    end

    if shouldRunPreambleCompaction and BurdJournals.compactPlayerJournalDRCache then
        local changed, removedJournals, removedAliases = BurdJournals.compactPlayerJournalDRCache(player, true)
        if changed then
            BurdJournals.debugPrint("[BurdJournals] Server compacted player DR cache for "
                .. tostring(player:getUsername()) .. ": removed "
                .. tostring(removedJournals) .. " journals, "
                .. tostring(removedAliases) .. " aliases")
        end
    end

    -- Get player ID safely - getOnlineID may not exist on older builds
    local playerId
    if player.getOnlineID then
        playerId = tostring(player:getOnlineID())
    elseif player.getUsername then
        playerId = tostring(player:getUsername())
    else
        playerId = "unknown"
    end

    -- Rate limiting is command-scoped so one operation cannot block another.
    -- Timed-action commands use short explicit intervals; bulk commands use longer ones.
    local isDebugCommand = type(command) == "string" and string.sub(command, 1, 5) == "debug"
    if getTimestampMs then
        local now = getTimestampMs()
        local commandInterval = tonumber(COMMAND_RATE_LIMIT_MS[command]) or (isDebugCommand and 250 or 100)
        local rateLimitKey = playerId .. "|" .. tostring(command)
        local lastCmd = BurdJournals.Server._rateLimitCache[rateLimitKey] or 0
        if lastCmd > 0 and now - lastCmd < commandInterval then
            BurdJournals.debugPrint("[BurdJournals] Server: RATE LIMITED command " .. tostring(command) .. " (only " .. tostring(now - lastCmd) .. "ms since last)")
            if command == "sanitizeJournal" then
                local requestId = type(args) == "table" and args.requestId or nil
                if type(requestId) ~= "string" or #requestId > 128 or requestId:find("%c") then requestId = nil end
                BurdJournals.Server.sendToClient(player, "syncSuccess", {
                    sanitizeRequestId = requestId,
                    sanitizeError = "rateLimited",
                    retryAfterMs = commandInterval - (now - lastCmd),
                    serverRuntimeMarker = BurdJournals.RUNTIME_LOAD_MARKER,
                })
            end
            return
        end
        BurdJournals.Server._rateLimitCache[rateLimitKey] = now

        -- Periodic cleanup (1% chance per command) - use ZombRand for PZ compatibility
        local rand = ZombRand and ZombRand(100) or 1
        if rand == 0 then
            BurdJournals.Server.cleanupRateLimitCache()
        end
    end

    local isEnabled = BurdJournals.isEnabled()
    BurdJournals.debugPrint("[BurdJournals] onClientCommand: isEnabled=" .. tostring(isEnabled))
    if not isEnabled then
        bsjWriteLogLine("[BurdJournals] onClientCommand ERROR: Journals disabled!")
        BurdJournals.Server.sendToClient(player, "error", {message = "Journals are disabled on this server."})
        return
    end
    if isPlayerJournalInteractionBlocked(command, player, args) then
        BurdJournals.debugPrint("[BurdJournals] Blocked player journal command while player journals are disabled: " .. tostring(command))
        BurdJournals.Server.sendToClient(player, "error", {
            message = (getText and getText("UI_BurdJournals_PlayerJournalsDisabled")) or "Player journals are disabled on this server."
        })
        return
    end

    BurdJournals.debugPrint("[BurdJournals] onClientCommand: Routing command '" .. tostring(command) .. "'")
    if command == "logSkills" then
        -- Retired legacy protocol: its remove-then-create transaction could
        -- destroy the source journal if materialization failed. Current clients
        -- use recordProgress, which is bounded and server-authoritative.
        BurdJournals.Server.sendToClient(player, "error", {message = "This journal recording request is no longer supported.", errorCode = "legacyLogSkillsRetired"})
    elseif command == "learnSkills" then
        BurdJournals.Server.handleLearnSkills(player, args)
    elseif command == "openCursedJournal" then
        BurdJournals.Server.handleOpenCursedJournal(player, args)
    elseif command == "requestCursedInsightPreview" then
        BurdJournals.Server.handleRequestCursedInsightPreview(player, args)
    elseif command == "openYuletideJournal" then
        BurdJournals.Server.handleOpenYuletideJournal(player, args)
    elseif command == "breakJournalSeal" then
        BurdJournals.Server.handleBreakJournalSeal(player, args)
    elseif command == "yuletideGiftMaterialized" then
        BurdJournals.Server.handleYuletideGiftMaterialized(player, args)
    elseif command == "absorbSkill" then
        BurdJournals.Server.handleAbsorbSkill(player, args)
    elseif command == "absorbTrait" then
        BurdJournals.Server.handleAbsorbTrait(player, args)
    elseif command == "claimSkill" then
